-- Poems batch 475
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-8','江上逢故人','崔道融','唐','御定全唐诗','yuding','','[]','故里琴樽侶，相逢近臘梅。江村買一醉，破淚卻成咍。',24,'御定全唐詩/json/714.json','["故里琴樽侶，相逢近臘梅。江村買一醉，破淚卻成咍。"]'),
('yuding-9','牧豎','崔道融','唐','御定全唐诗','yuding','','[]','牧豎持蓑笠，逢人氣傲然。臥牛吹短笛，耕卻傍溪田。',24,'御定全唐詩/json/714.json','["牧豎持蓑笠，逢人氣傲然。臥牛吹短笛，耕卻傍溪田。"]'),
('yuding-10','過農家','崔道融','唐','御定全唐诗','yuding','','[]','欲羨農家子，秋新看刈禾。蘇秦無負郭，六印又如何。',24,'御定全唐詩/json/714.json','["欲羨農家子，秋新看刈禾。蘇秦無負郭，六印又如何。"]'),
('yuding-11','江夕','崔道融','唐','御定全唐诗','yuding','','[]','江心秋月白，起柁信潮行。蛟龍化為人，半夜吹笛聲。',24,'御定全唐詩/json/714.json','["江心秋月白，起柁信潮行。蛟龍化為人，半夜吹笛聲。"]'),
('yuding-12','春墅','崔道融','唐','御定全唐诗','yuding','','[]','蛙聲近過社，農事忽已忙。鄰婦餉田歸，不見百花芳。',24,'御定全唐詩/json/714.json','["蛙聲近過社，農事忽已忙。鄰婦餉田歸，不見百花芳。"]'),
('yuding-13','江村','崔道融','唐','御定全唐诗','yuding','','[]','日暮片帆落，江村如有情。獨對沙上月，滿船人睡聲。',24,'御定全唐詩/json/714.json','["日暮片帆落，江村如有情。獨對沙上月，滿船人睡聲。"]'),
('yuding-14','擬樂府子夜四時歌四首','崔道融','唐','御定全唐诗','yuding','','[]','吳子愛桃李，月色不到地。明朝欲看花，六宮人不睡。',96,'御定全唐詩/json/714.json','["吳子愛桃李，月色不到地。明朝欲看花，六宮人不睡。", "涼軒待月生，暗裏螢飛出。低回不稱意，蛙鳴亂清瑟。", "月色明如晝，蟲聲入戶多。狂夫自不歸，滿地無天河。", "銀缸照殘夢，零淚沾粉臆。洞房猶自寒，何況關山北。"]'),
('yuding-15','寄人二首','崔道融','唐','御定全唐诗','yuding','','[]','花上斷續雨，江頭來去風。相思春欲盡，未遣酒尊空。',48,'御定全唐詩/json/714.json','["花上斷續雨，江頭來去風。相思春欲盡，未遣酒尊空。", "澹澹長江水，悠悠遠客情。落花相與恨，到地一無聲。"]'),
('yuding-16','江鷗','崔道融','唐','御定全唐诗','yuding','','[]','白鳥波上棲，見人懶飛起。為有求魚心，不是戀江水。',24,'御定全唐詩/json/714.json','["白鳥波上棲，見人懶飛起。為有求魚心，不是戀江水。"]'),
('yuding-17','春晚','崔道融','唐','御定全唐诗','yuding','','[]','三月寒食時，日色濃於酒。落盡牆頭花，鶯聲隔原柳。',24,'御定全唐詩/json/714.json','["三月寒食時，日色濃於酒。落盡牆頭花，鶯聲隔原柳。"]'),
('yuding-18','漢宮詞','崔道融','唐','御定全唐诗','yuding','','[]','獨詔胡衣出，天花落殿堂。他人不敢妒，垂淚向君王。',24,'御定全唐詩/json/714.json','["獨詔胡衣出，天花落殿堂。他人不敢妒，垂淚向君王。"]'),
('yuding-19','旅行','崔道融','唐','御定全唐诗','yuding','','[]','少壯經勤苦，衰年始浪遊。誰憐不龜手，他處卻封侯。',24,'御定全唐詩/json/714.json','["少壯經勤苦，衰年始浪遊。誰憐不龜手，他處卻封侯。"]'),
('yuding-20','班婕妤','崔道融','唐','御定全唐诗','yuding','','[]','寵極辭同輦，恩深棄後宮。自題秋扇後，不敢怨春風。',24,'御定全唐詩/json/714.json','["寵極辭同輦，恩深棄後宮。自題秋扇後，不敢怨春風。"]'),
('yuding-21','元日有題','崔道融','唐','御定全唐诗','yuding','','[]','十載元正酒，相歡意轉深。自量麋鹿分，只合在山林。',24,'御定全唐詩/json/714.json','["十載元正酒，相歡意轉深。自量麋鹿分，只合在山林。"]'),
('yuding-22','古樹','崔道融','唐','御定全唐诗','yuding','','[]','古樹春風入，陽和力太遲。莫言生意盡，更引萬年枝。',24,'御定全唐詩/json/714.json','["古樹春風入，陽和力太遲。莫言生意盡，更引萬年枝。"]'),
('yuding-23','春題二首','崔道融','唐','御定全唐诗','yuding','','[]','青春未得意，見花卻如讎。路逢白麵郎，醉插花滿頭。',48,'御定全唐詩/json/714.json','["青春未得意，見花卻如讎。路逢白麵郎，醉插花滿頭。", "滿眼桃李花，愁人如不見。別有惜花人，東風莫吹散。"]'),
('yuding-24','長安春','崔道融','唐','御定全唐诗','yuding','','[]','長安牡丹開，繡轂輾晴雷。若使花長在，人應看不回。',24,'御定全唐詩/json/714.json','["長安牡丹開，繡轂輾晴雷。若使花長在，人應看不回。"]'),
('yuding-25','病起二首','崔道融','唐','御定全唐诗','yuding','','[]','病起春已晚，曳筇傷綠苔。強攀庭樹枝，喚作花未開。',48,'御定全唐詩/json/714.json','["病起春已晚，曳筇傷綠苔。強攀庭樹枝，喚作花未開。", "病起繞庭除，春泥粘屐齒。如從萬里來，骨肉滿面喜。"]'),
('yuding-26','峽路','崔道融','唐','御定全唐诗','yuding','','[]','清猿啼不住，白水下來新。八月莫為客，夜長愁殺人。',24,'御定全唐詩/json/714.json','["清猿啼不住，白水下來新。八月莫為客，夜長愁殺人。"]'),
('yuding-27','長門怨','崔道融','唐','御定全唐诗','yuding','','[]','長門春欲盡，明月照花枝。買得相如賦，君恩不可移。',24,'御定全唐詩/json/714.json','["長門春欲盡，明月照花枝。買得相如賦，君恩不可移。"]'),
('yuding-28','月夕有懷','崔道融','唐','御定全唐诗','yuding','','[]','圓光照一海，遠客在孤舟。相憶無期見，中宵獨上樓。',24,'御定全唐詩/json/714.json','["圓光照一海，遠客在孤舟。相憶無期見，中宵獨上樓。"]'),
('yuding-29','夜泊九江','崔道融','唐','御定全唐诗','yuding','','[]','夜泊江門外，歡聲月裏樓。明朝歸去路，猶隔洞庭秋。',24,'御定全唐詩/json/714.json','["夜泊江門外，歡聲月裏樓。明朝歸去路，猶隔洞庭秋。"]'),
('yuding-30','寒食夜','崔道融','唐','御定全唐诗','yuding','','[]','滿地梨花白，風吹碎月明。大家寒食夜，獨貯望鄉情。',24,'御定全唐詩/json/714.json','["滿地梨花白，風吹碎月明。大家寒食夜，獨貯望鄉情。"]'),
('yuding-31','歸燕','崔道融','唐','御定全唐诗','yuding','','[]','海燕頻來去，西人獨滯留。天邊又相送，腸斷故園秋。',24,'御定全唐詩/json/714.json','["海燕頻來去，西人獨滯留。天邊又相送，腸斷故園秋。"]'),
('yuding-32','長安春','崔道融','唐','御定全唐诗','yuding','','[]','珠箔映高柳，美人紅袖垂。忽聞半天語，不見上樓時。',24,'御定全唐詩/json/714.json','["珠箔映高柳，美人紅袖垂。忽聞半天語，不見上樓時。"]'),
('yuding-33','鑾駕東回','崔道融','唐','御定全唐诗','yuding','','[]','兩川花捧禦衣香，萬歲山呼輦路長。',32,'御定全唐詩/json/714.json','["兩川花捧禦衣香，萬歲山呼輦路長。", "天子還從馬嵬過，別無惆悵似明皇。"]'),
('yuding-34','釣魚','崔道融','唐','御定全唐诗','yuding','','[]','閑釣江魚不釣名，瓦甌斟酒暮山青。',32,'御定全唐詩/json/714.json','["閑釣江魚不釣名，瓦甌斟酒暮山青。", "醉頭倒向蘆花裏，卻笑無端犯客星。"]'),
('yuding-35','西施','崔道融','唐','御定全唐诗','yuding','','[]','苧蘿山下如花女，占得姑蘇臺上春。',32,'御定全唐詩/json/714.json','["苧蘿山下如花女，占得姑蘇臺上春。", "一笑不能忘敵國，五湖何處有功臣。"]'),
('yuding-36','馬嵬','崔道融','唐','御定全唐诗','yuding','','[]','萬乘淒涼蜀路歸，眼前朱翠與心違。',32,'御定全唐詩/json/714.json','["萬乘淒涼蜀路歸，眼前朱翠與心違。", "重華不是風流主，湘水猶傳泣二妃。"]'),
('yuding-37','羯鼓','崔道融','唐','御定全唐诗','yuding','','[]','華清宮裏打撩聲，供奉絲簧束手聽。',32,'御定全唐詩/json/714.json','["華清宮裏打撩聲，供奉絲簧束手聽。", "寂寞鑾輿斜穀裏，是誰翻得雨淋鈴。"]'),
('yuding-38','寄李左司','崔道融','唐','御定全唐诗','yuding','','[]','柏台蘭省共清風，鳴玉朝聯夜被同。',32,'御定全唐詩/json/714.json','["柏台蘭省共清風，鳴玉朝聯夜被同。", "肯信人間有兄弟，一生長在別離中。"]'),
('yuding-39','梅','崔道融','唐','御定全唐诗','yuding','','[]','溪上寒梅初滿枝，夜來霜月透芳菲。',32,'御定全唐詩/json/714.json','["溪上寒梅初滿枝，夜來霜月透芳菲。", "清光寂寞思無盡，應待琴尊與解圍。"]'),
('yuding-40','天臺陳逸人','崔道融','唐','御定全唐诗','yuding','','[]','絕粒空山秋複春，欲看滄海化成塵。',32,'御定全唐詩/json/714.json','["絕粒空山秋複春，欲看滄海化成塵。", "近拋三井更深去，不怕虎狼唯怕人。"]'),
('yuding-41','雪竇禪師','崔道融','唐','御定全唐诗','yuding','','[]','雪竇峰前一派懸，雪竇五月無炎天。',32,'御定全唐詩/json/714.json','["雪竇峰前一派懸，雪竇五月無炎天。", "客塵半日洗欲盡，師到白頭林下禪。"]'),
('yuding-42','溪上遇雨二首','崔道融','唐','御定全唐诗','yuding','','[]','回塘雨腳如繅絲，野禽不起沈魚飛。',64,'御定全唐詩/json/714.json','["回塘雨腳如繅絲，野禽不起沈魚飛。", "耕蓑釣笠取未暇，秋田有望從淋漓。", "坐看黑雲銜猛雨，噴灑前山此獨晴。", "忽驚雲雨在頭上，卻是山前晚照明。"]'),
('yuding-43','長門怨','崔道融','唐','御定全唐诗','yuding','','[]','長門花泣一枝春，爭奈君恩別處新。',32,'御定全唐詩/json/714.json','["長門花泣一枝春，爭奈君恩別處新。", "錯把黃金買詞賦，相如自是薄情人。"]'),
('yuding-44','秋夕','崔道融','唐','御定全唐诗','yuding','','[]','自憐三十未西游，傍水尋山過卻秋。',32,'御定全唐詩/json/714.json','["自憐三十未西游，傍水尋山過卻秋。", "一夜雨聲多少事，不思量盡到心頭。"]'),
('yuding-45','過隆中','崔道融','唐','御定全唐诗','yuding','','[]','玄德蒼黃起臥龍，鼎分天下一言中。',32,'御定全唐詩/json/714.json','["玄德蒼黃起臥龍，鼎分天下一言中。", "可憐蜀國關張後，不見商量徐庶功。"]'),
('yuding-46','關下','崔道融','唐','御定全唐诗','yuding','','[]','百二山河壯帝畿，關門何事更開遲。',32,'御定全唐詩/json/714.json','["百二山河壯帝畿，關門何事更開遲。", "應從漏卻田文後，每度聞雞不免疑。"]'),
('yuding-47','寒食客中有懷','崔道融','唐','御定全唐诗','yuding','','[]','江上聞鶯禁火時，百花開盡柳依依。',32,'御定全唐詩/json/714.json','["江上聞鶯禁火時，百花開盡柳依依。", "故園兄弟別來久，應到清明猶望歸。"]'),
('yuding-48','溪夜','崔道融','唐','御定全唐诗','yuding','','[]','積雪消來溪水寬，滿樓明月碎琅玕。漁人拋得釣筒盡，卻放輕舟下急灘。',32,'御定全唐詩/json/714.json','["積雪消來溪水寬，滿樓明月碎琅玕。漁人拋得釣筒盡，卻放輕舟下急灘。"]'),
('yuding-49','山居臥疾，廣利大師見訪','崔道融','唐','御定全唐诗','yuding','','[]','桐谷孫枝已上弦，野人猶臥白雲邊。',32,'御定全唐詩/json/714.json','["桐谷孫枝已上弦，野人猶臥白雲邊。", "九天飛錫應相誚，三到行朝二十年。"]'),
('yuding-50','村墅','崔道融','唐','御定全唐诗','yuding','','[]','正月二月村墅閑，餘糧未乏人心寬。',32,'御定全唐詩/json/714.json','["正月二月村墅閑，餘糧未乏人心寬。", "南鄰雨中揭屋笑，酒熟數家來相看。"]'),
('yuding-51','悲李拾遺二首','崔道融','唐','御定全唐诗','yuding','','[]','故友從來匪石心，諫多難得主恩深。',64,'御定全唐詩/json/714.json','["故友從來匪石心，諫多難得主恩深。", "行朝半夜煙塵起，曉殿籲嗟一鏡沈。", "天涯時有北來塵，因話它人及故人。", "也是先皇能罪己，殿前頻得觸龍鱗。"]'),
('yuding-52','《題李將軍傳》','崔道融','唐','御定全唐诗','yuding','','[]','猿臂將軍去似飛，彎弓百步虜無遺。',32,'御定全唐詩/json/714.json','["猿臂將軍去似飛，彎弓百步虜無遺。", "漢文自與封侯得，何必傷嗟不遇時。"]'),
('yuding-53','酒醒','崔道融','唐','御定全唐诗','yuding','','[]','酒醒撥剔殘灰火，多少淒涼在此中。',32,'御定全唐詩/json/714.json','["酒醒撥剔殘灰火，多少淒涼在此中。", "爐畔自斟還自醉，打窗深夜雪兼風。"]'),
('yuding-54','郊居友人相訪','崔道融','唐','御定全唐诗','yuding','','[]','柴門深掩古城秋，背郭緣溪一徑幽。',32,'御定全唐詩/json/714.json','["柴門深掩古城秋，背郭緣溪一徑幽。", "不有小園新竹色，君來那肯暫淹留。"]'),
('yuding-55','鏡湖雪霽貽方幹','崔道融','唐','御定全唐诗','yuding','','[]','天外曉嵐和雪望，月中歸棹帶冰行。',32,'御定全唐詩/json/714.json','["天外曉嵐和雪望，月中歸棹帶冰行。", "相逢半醉吟詩苦，應抵寒猿嫋樹聲。"]'),
('yuding-56','秋霽','崔道融','唐','御定全唐诗','yuding','','[]','雨霽長空蕩滌清，遠山初出未知名。',32,'御定全唐詩/json/714.json','["雨霽長空蕩滌清，遠山初出未知名。", "夜來江上如鉤月，時有驚魚擲浪聲。"]'),
('yuding-57','謝朱常侍寄貺蜀茶、剡紙二首','崔道融','唐','御定全唐诗','yuding','','[]','瑟瑟香塵瑟瑟泉，驚風驟雨起爐煙。',64,'御定全唐詩/json/714.json','["瑟瑟香塵瑟瑟泉，驚風驟雨起爐煙。", "一甌解卻山中醉，便覺身輕欲上天。", "百幅輕明雪未融，薛家凡紙漫深紅。", "不應點染閑言語，留記將軍蓋世功。"]'),
('yuding-58','讀杜紫微集','崔道融','唐','御定全唐诗','yuding','','[]','紫微才調複知兵，長覺風雷筆下生。',32,'御定全唐詩/json/714.json','["紫微才調複知兵，長覺風雷筆下生。", "還有枉拋心力處，多於五柳賦閒情。"]'),
('yuding-59','寓題','崔道融','唐','御定全唐诗','yuding','','[]','海上乘查便合仙，若無仙骨未如船。',32,'御定全唐詩/json/714.json','["海上乘查便合仙，若無仙骨未如船。", "人間亦有支機石，虛被聲名到洞天。"]'),
('yuding-60','寓吟集','崔道融','唐','御定全唐诗','yuding','','[]','陶集篇篇皆有酒，崔詩句句不無杯。',32,'御定全唐詩/json/714.json','["陶集篇篇皆有酒，崔詩句句不無杯。", "醉來已共身安約，讓卻詩人作酒魁。"]'),
('yuding-61','溪居即事','崔道融','唐','御定全唐诗','yuding','','[]','籬外誰家不系船，春風吹入釣魚灣。',32,'御定全唐詩/json/714.json','["籬外誰家不系船，春風吹入釣魚灣。", "小童疑是有村客，急向柴門去卻關。"]'),
('yuding-62','雞','崔道融','唐','御定全唐诗','yuding','','[]','買得晨雞共雞語，常時不用等閒鳴。',32,'御定全唐詩/json/714.json','["買得晨雞共雞語，常時不用等閒鳴。", "深山月黑風雨夜，欲近曉天啼一聲。"]'),
('yuding-63','獻浙東柳大夫','崔道融','唐','御定全唐诗','yuding','','[]','屬城甘雨幾經春，聖主全分付越人。',32,'御定全唐詩/json/714.json','["屬城甘雨幾經春，聖主全分付越人。", "俗眼不知青瑣貴，江頭爭看碧油新。"]'),
('yuding-64','楊柳枝詞','崔道融','唐','御定全唐诗','yuding','','[]','霧撚煙搓一索春，年年長似染來新。',32,'御定全唐詩/json/714.json','["霧撚煙搓一索春，年年長似染來新。", "應須喚作風流線，系得東西南北人。"]'),
('yuding-65','楚懷王','崔道融','唐','御定全唐诗','yuding','','[]','宮花一朵掌中開，緩急翻為敵國媒。',32,'御定全唐詩/json/714.json','["宮花一朵掌中開，緩急翻為敵國媒。", "六裏江山天下笑，張儀容易去還來。"]'),
('yuding-66','對早梅寄友人二首','崔道融','唐','御定全唐诗','yuding','','[]','憶得前年君寄詩，海邊三見早梅詞。',64,'御定全唐詩/json/714.json','["憶得前年君寄詩，海邊三見早梅詞。", "與君猶是海邊客，又見早梅花發時。", "憶得去年有遺恨，花前未醉到無花。", "清芳一夜月通白，先脫寒衣送酒家。"]'),
('yuding-67','句','崔道融','唐','御定全唐诗','yuding','','[]','萬里一點白，長空鳥不飛。',28,'御定全唐詩/json/714.json','["萬里一點白，長空鳥不飛。", "如今卻羨相如富，猶有人間四壁居。"]'),
('yuding-0','苦吟','盧延讓','唐','御定全唐诗','yuding','','[]','莫話詩中事，詩中難更無。吟安一個字，撚斷數莖須。',48,'御定全唐詩/json/715.json','["莫話詩中事，詩中難更無。吟安一個字，撚斷數莖須。", "險覓天應悶，狂搜海亦枯。不同文賦易，為著者之乎。"]'),
('yuding-1','雪','盧延讓','唐','御定全唐诗','yuding','','[]','瑞雪落紛華，隨風一向斜。地平鋪作月，天迥撒成花。',48,'御定全唐詩/json/715.json','["瑞雪落紛華，隨風一向斜。地平鋪作月，天迥撒成花。", "客滿燒煙舍，牛牽賣炭車。吾皇憂挾纊，猶自問君家。"]'),
('yuding-2','松寺','盧延讓','唐','御定全唐诗','yuding','','[]','山寺取涼當夏夜，共僧蹲坐石階前。兩三條電欲為雨，',40,'御定全唐詩/json/715.json','["山寺取涼當夏夜，共僧蹲坐石階前。兩三條電欲為雨，", "通宵聽論蓮華義，不藉松窗一覺眠。"]'),
('yuding-3','贈僧','盧延讓','唐','御定全唐诗','yuding','','[]','浮世浮華一斷空，偶拋煩惱到蓮宮。高僧解語牙無水，',40,'御定全唐詩/json/715.json','["浮世浮華一斷空，偶拋煩惱到蓮宮。高僧解語牙無水，", "禪師莫問求名苦，滋味過於食蓼蟲。"]'),
('yuding-4','逢友人赴闕','盧延讓','唐','御定全唐诗','yuding','','[]','正當天下待雍熙，丹詔征來早為遲。倚馬才高猶愛藝，',40,'御定全唐詩/json/715.json','["正當天下待雍熙，丹詔征來早為遲。倚馬才高猶愛藝，", "卻笑郡人留不得，感恩唯擬立生祠。"]'),
('yuding-5','哭李郢端公','盧延讓','唐','御定全唐诗','yuding','','[]','軍門半掩槐花宅，每過猶聞哭臨聲。北固暴亡兼在路，',40,'御定全唐詩/json/715.json','["軍門半掩槐花宅，每過猶聞哭臨聲。北固暴亡兼在路，", "詩侶酒徒消散盡，一場春夢越王城。"]'),
('yuding-6','謝楊尚書惠櫻桃','盧延讓','唐','御定全唐诗','yuding','','[]','滿合虛紅怕動搖，尚書知重賜櫻桃。揉藍尚帶新鮮葉，',40,'御定全唐詩/json/715.json','["滿合虛紅怕動搖，尚書知重賜櫻桃。揉藍尚帶新鮮葉，", "春來老病尤珍荷，並食中腸似火燒。"]'),
('yuding-7','寒食日戲贈李侍禦','盧延讓','唐','御定全唐诗','yuding','','[]','十二街如市，紅塵咽不開。灑蹄驄馬汗，沒處看花來。',24,'御定全唐詩/json/715.json','["十二街如市，紅塵咽不開。灑蹄驄馬汗，沒處看花來。"]'),
('yuding-8','樊川寒食二首','盧延讓','唐','御定全唐诗','yuding','','[]','寒食權豪盡出行，一川如畫雨初晴。',64,'御定全唐詩/json/715.json','["寒食權豪盡出行，一川如畫雨初晴。", "誰家絡絡游春盛，擔入花間軋軋聲。", "鞍馬和花總是塵，歌聲處處有佳人。", "五陵年少粗於事，栲栳量金買斷春。"]'),
('yuding-9','句','盧延讓','唐','御定全唐诗','yuding','','[]','只訛些子緣，應耗沒多光。',164,'御定全唐詩/json/715.json','["只訛些子緣，應耗沒多光。", "臂鷹健卒懸氊帽，騎馬佳人卷畫衫。", "每過私第邀看鶴，長著公裳送上驢。", "名紙毛生五門下，家僮骨立六街中。", "雲間鬧鐸騾駝至，雪裏殘骸虎拽來。", "樹上咨諏批頰鳥，窗間壁駁叩頭蟲。", "莫欺零落殘牙齒，曾吃紅綾餅餤來。", "渡水蹇驢雙耳直，避風羸僕一肩高。", "高據襄陽播盛名，問人人道是詩星。（《吊孟浩然》，", "涼雨打低殘菡萏，急風吹散小蜻蜓。"]'),
('yuding-10','示門生馬侍郎胤孫','裴皞','唐','御定全唐诗','yuding','','[]','宦途最重是文衡，天與愚夫著盛名。',32,'御定全唐詩/json/715.json','["宦途最重是文衡，天與愚夫著盛名。", "三主禮闈年八十，門生門下見門生。"]'),
('yuding-11','贈杜荀鶴','王希羽','唐','御定全唐诗','yuding','','[]','金榜曉懸生世日，玉書潛記上升時。',32,'御定全唐詩/json/715.json','["金榜曉懸生世日，玉書潛記上升時。", "九華山色高千尺，未必高於第八枝。"]'),
('yuding-12','宮怨二首','柯崇','唐','御定全唐诗','yuding','','[]','塵滿金爐不炷香，黃昏獨自立重廊。',64,'御定全唐詩/json/715.json','["塵滿金爐不炷香，黃昏獨自立重廊。", "笙歌何處承恩寵，一一隨風入上陽。", "長門槐柳半蕭疏，玉輦沈思恨有餘。", "紅淚漸消傾國態，黃金誰為達相如。"]'),
('yuding-13','早春池亭獨遊三首','劉象','唐','御定全唐诗','yuding','','[]','春意送殘臘，春晴融小洲。蒲茸才簇岸，柳頰已遮樓。',144,'御定全唐詩/json/715.json','["春意送殘臘，春晴融小洲。蒲茸才簇岸，柳頰已遮樓。", "便有杯觴興，可據羈旅愁。鳧鷖亦相狎，盡日戲清流。", "清流環綠筱，清景媚虹橋。鶯刷初遷羽，莎拳擬拆苗。", "細沙擢暖岸，淑景動和飆。倍憶同袍侶，相歡倒一瓢。", "一瓢歡自足，一日興偏多。幽意人先賞，疏叢蝶未過。", "知音新句苦，窺沼醉顏酡。萬慮從相擬，今朝欲奈何。"]'),
('yuding-14','鷺鷥','劉象','唐','御定全唐诗','yuding','','[]','潔白孤高生不同，頂絲清軟冷搖風。窺魚翹立荷香裏，',40,'御定全唐詩/json/715.json','["潔白孤高生不同，頂絲清軟冷搖風。窺魚翹立荷香裏，", "摩霄志在潛修羽，會接鸞凰別葦叢。"]'),
('yuding-15','春夜二首','劉象','唐','御定全唐诗','yuding','','[]','幾處兵戈阻路岐，憶山心切與山違。',64,'御定全唐詩/json/715.json','["幾處兵戈阻路岐，憶山心切與山違。", "時難何處披懷抱，日日日斜空醉歸。", "一別杜陵歸未期，只憑魂夢接親知。", "近來欲睡兼難睡，夜夜夜深聞子規。"]'),
('yuding-16','曉登迎春閣','劉象','唐','御定全唐诗','yuding','','[]','未櫛憑欄眺錦城，煙籠萬井二江明。',32,'御定全唐詩/json/715.json','["未櫛憑欄眺錦城，煙籠萬井二江明。", "香風滿閣花盈戶，樹樹樹梢啼曉鶯。"]'),
('yuding-17','詠仙掌','劉象','唐','御定全唐诗','yuding','','[]','萬古亭亭倚碧霄，不成擎亦不成招。',32,'御定全唐詩/json/715.json','["萬古亭亭倚碧霄，不成擎亦不成招。", "何如掬取天池水，灑向人間救旱苗。"]'),
('yuding-18','郪中感舊','劉象','唐','御定全唐诗','yuding','','[]','頃年曾住此中來，今日重遊事可哀。',32,'御定全唐詩/json/715.json','["頃年曾住此中來，今日重遊事可哀。", "憶得幾家歡宴處，家家家業盡成灰。"]'),
('yuding-19','白髭','劉象','唐','御定全唐诗','yuding','','[]','到處逢人求至藥，幾回染了又成絲。',32,'御定全唐詩/json/715.json','["到處逢人求至藥，幾回染了又成絲。", "素絲易染髭難染，墨翟當時合泣髭。"]'),
('yuding-20','題縣令范傳真化洽亭','沈顏','唐','御定全唐诗','yuding','','[]','前有淺山，屹然如屏。後有卑嶺，繚然如城。',40,'御定全唐詩/json/715.json','["前有淺山，屹然如屏。後有卑嶺，繚然如城。", "跨池左右，足以建亭。斯亭何名，化洽而成。"]'),
('yuding-21','書懷寄友人','沈顏','唐','御定全唐诗','yuding','','[]','江湖勞遍尋，只自長愁襟。到處慵開口，何人可話心。',48,'御定全唐詩/json/715.json','["江湖勞遍尋，只自長愁襟。到處慵開口，何人可話心。", "登樓得句遠，望月抒情深。卻憶山齋後，猿聲相伴吟。"]'),
('yuding-22','題壁','楊凝式','唐','御定全唐诗','yuding','','[]','院似禪心靜，花如覺性圓。自然知了義，爭肯學神仙。',24,'御定全唐詩/json/715.json','["院似禪心靜，花如覺性圓。自然知了義，爭肯學神仙。"]'),
('yuding-23','贈張全義','楊凝式','唐','御定全唐诗','yuding','','[]','洛陽風景實堪哀，昔日曾為瓦子堆。',32,'御定全唐詩/json/715.json','["洛陽風景實堪哀，昔日曾為瓦子堆。", "不是我公重葺理，至今猶是一堆灰。"]'),
('yuding-24','題懷素酒狂帖後','楊凝式','唐','御定全唐诗','yuding','','[]','十年揮素學臨池，始識王公學衛非。',32,'御定全唐詩/json/715.json','["十年揮素學臨池，始識王公學衛非。", "草聖未須因酒發，筆端應解化龍飛。"]'),
('yuding-25','句','楊凝式','唐','御定全唐诗','yuding','','[]','押引蝗蟲到洛京，合消郡守遠相迎。（歸洛寄尹張從恩，',33,'御定全唐詩/json/715.json','["押引蝗蟲到洛京，合消郡守遠相迎。（歸洛寄尹張從恩，", "到此今經三紀春。"]'),
('yuding-26','奉試詔用拓拔思恭為京北收復都統','李琪','唐','御定全唐诗','yuding','','[]','飛騎經巴棧，鴻恩及夏台。將從天上去，人自日邊來。',48,'御定全唐詩/json/715.json','["飛騎經巴棧，鴻恩及夏台。將從天上去，人自日邊來。", "此處金門遠，何時玉輦回。早平關右賊，莫待詔書催。"]'),
('yuding-27','題廣愛寺楞伽山','李琪','唐','御定全唐诗','yuding','','[]','善高天外遠，方丈海中遙。自有山神護，應無劫火燒。',48,'御定全唐詩/json/715.json','["善高天外遠，方丈海中遙。自有山神護，應無劫火燒。", "壞文侵古壁，飛劍出寒霄。何似蒼蒼色，嚴妝十七朝。"]'),
('yuding-28','句','李琪','唐','御定全唐诗','yuding','','[]','哀痛不下詔，登封誰上書。',12,'御定全唐詩/json/715.json','["哀痛不下詔，登封誰上書。"]'),
('yuding-29','寄桂帥','劉崇龜','唐','御定全唐诗','yuding','','[]','碧幢仁施合洪鈞，桂樹林前倍得春。',32,'御定全唐詩/json/715.json','["碧幢仁施合洪鈞，桂樹林前倍得春。", "莫戀此時好風景，磻溪不是釣漁人。"]'),
('yuding-30','席上吟','劉崇魯','唐','御定全唐诗','yuding','','[]','南行忽見李深之，手舞如蜚令不疑。',32,'御定全唐詩/json/715.json','["南行忽見李深之，手舞如蜚令不疑。", "任有風流兼蘊藉，天生不似鄭都知。"]'),
('yuding-31','寄孫儲','孫定','唐','御定全唐诗','yuding','','[]','行行血淚灑塵襟，事逐東流渭水深。秋跨蹇驢風尚緊，',40,'御定全唐詩/json/715.json','["行行血淚灑塵襟，事逐東流渭水深。秋跨蹇驢風尚緊，", "明月悲歌又前去，滿城煙樹噪春禽。"]'),
('yuding-32','江南行','許晝','唐','御定全唐诗','yuding','','[]','江南蕭灑地，本自與君宜。固節還同我，虛心欲待誰。',120,'御定全唐詩/json/715.json','["江南蕭灑地，本自與君宜。固節還同我，虛心欲待誰。", "澗泉傍借響，山木共含滋。粉膩蟲難篆，叢疏鳥易窺。", "盡應逢野渡，中忽見村祠。葉掃秋空靜，根橫古塹危。", "影迷寒靄裏，聲出夜風時。客棹深深過，人家遠遠移。", "游邊曾結念，到此數題詩。莫恨成龍晚，成龍會有期。"]'),
('yuding-33','中秋月','許晝','唐','御定全唐诗','yuding','','[]','應是蟾宮別有情，每逢秋半倍澄清。清光不向此中見，',40,'御定全唐詩/json/715.json','["應是蟾宮別有情，每逢秋半倍澄清。清光不向此中見，", "殷勤好長來年桂，莫遣平人道不平。"]'),
('yuding-34','臨終詩','薛准','唐','御定全唐诗','yuding','','[]','舊國深恩不易酬，又離繼母出他州。',32,'御定全唐詩/json/715.json','["舊國深恩不易酬，又離繼母出他州。", "誰知天怒無因息，積愧終身乞速休。"]'),
('yuding-35','觀修處士畫桃花圖歌','裴諧','唐','御定全唐诗','yuding','','[]','一從天寶王維死，於今始遇修夫子。能向鮫綃四幅中，',72,'御定全唐詩/json/715.json','["一從天寶王維死，於今始遇修夫子。能向鮫綃四幅中，", "堪憐彩筆似東風，一朵一枝隨手發。燕支乍濕如含露，", "工夫妙麗實奇絕，似對韶光好時節。偏宜留著待深冬，"]'),
('yuding-36','句','裴諧','唐','御定全唐诗','yuding','','[]','風回山火斷，朝落岸冰高。',24,'御定全唐詩/json/715.json','["風回山火斷，朝落岸冰高。", "名終埋不得，骨任朽何妨。"]'),
('yuding-0','長安春日','曹松','唐','御定全唐诗','yuding','','[]','浩浩看花晨，六街揚遠塵。塵中一丈日，誰是晏眠人。',48,'御定全唐詩/json/716.json','["浩浩看花晨，六街揚遠塵。塵中一丈日，誰是晏眠人。", "禦柳舞著水，野鶯啼破春。徒雲多失意，猶自惜離秦。"]'),
('yuding-1','慈恩寺貽楚霄上人','曹松','唐','御定全唐诗','yuding','','[]','在秦生楚思，波浪接禪關。塔礙高林鳥，窗開白日山。',48,'御定全唐詩/json/716.json','["在秦生楚思，波浪接禪關。塔礙高林鳥，窗開白日山。", "樹陰移草上，岸色透庭間。入內談經徹，空攜講疏還。"]'),
('yuding-2','崇義裏言懷','曹松','唐','御定全唐诗','yuding','','[]','馬蹄京洛岐，複此少閒時。老積滄洲夢，秋乖白閣期。',48,'御定全唐詩/json/716.json','["馬蹄京洛岐，複此少閒時。老積滄洲夢，秋乖白閣期。", "平生五字句，一夕滿頭絲。把向侯門去，侯門未可知。"]'),
('yuding-3','僧院松','曹松','唐','御定全唐诗','yuding','','[]','此木韻彌全，秋霄學瑟弦。空知百餘尺，未定幾多年。',48,'御定全唐詩/json/716.json','["此木韻彌全，秋霄學瑟弦。空知百餘尺，未定幾多年。", "古甲磨雲拆，孤根捉地堅。何當拋一干，作蓋道場前。"]'),
('yuding-4','貽世','曹松','唐','御定全唐诗','yuding','','[]','富者非義取，樸風爭肯還。紅塵不待曉，白首有誰閑。',48,'御定全唐詩/json/716.json','["富者非義取，樸風爭肯還。紅塵不待曉，白首有誰閑。", "淺度四溟水，平看諸國山。只消年作劫，俱到總無間。"]'),
('yuding-5','南游','曹松','唐','御定全唐诗','yuding','','[]','直到南箕下，方諳漲海頭。君恩過銅柱，戎節限交州。',48,'御定全唐詩/json/716.json','["直到南箕下，方諳漲海頭。君恩過銅柱，戎節限交州。", "犀占花陰臥，波沖瘴色流。遠夷非不樂，自是北人愁。"]'),
('yuding-6','送胡中丞使日東','曹松','唐','御定全唐诗','yuding','','[]','辭天理玉簪，指日使雞林。猶有中華戀，方同積浪深。',48,'御定全唐詩/json/716.json','["辭天理玉簪，指日使雞林。猶有中華戀，方同積浪深。", "張帆度鯨口，銜命見臣心。渥澤遐宣後，歸期抵萬金。"]'),
('yuding-7','哭陳陶處士','曹松','唐','御定全唐诗','yuding','','[]','園裏先生塚，鳥啼春更傷。空餘八封樹，尚對一茅堂。',48,'御定全唐詩/json/716.json','["園裏先生塚，鳥啼春更傷。空餘八封樹，尚對一茅堂。", "白日埋杜甫，皇天無耒陽。如何稽古力，報答甚茫茫。"]'),
('yuding-8','言懷','曹松','唐','御定全唐诗','yuding','','[]','冥心坐似癡，寢食亦如遺。為覓出人句，只求當路知。',48,'御定全唐詩/json/716.json','["冥心坐似癡，寢食亦如遺。為覓出人句，只求當路知。", "豈能窮到老，未信達無時。此道須天付，三光幸不私。"]'),
('yuding-9','月','曹松','唐','御定全唐诗','yuding','','[]','寥寥天地內，夜魄爽何輕。頻見此輪滿，即應華發生。',48,'御定全唐詩/json/716.json','["寥寥天地內，夜魄爽何輕。頻見此輪滿，即應華發生。", "不圓爭得破，才正又須傾。人事還如此，因知倚伏情。"]'),
('yuding-10','答匡山僧贈榔栗杖','曹松','唐','御定全唐诗','yuding','','[]','栗杖出匡頂，百中無一枝。雖因野僧得，猶畏嶽神知。',48,'御定全唐詩/json/716.json','["栗杖出匡頂，百中無一枝。雖因野僧得，猶畏嶽神知。", "畫月冷光在，指雲秋片移。宜留引蹇步，他日訪峨嵋。"]'),
('yuding-11','商山夜聞泉','曹松','唐','御定全唐诗','yuding','','[]','瀉月聲不斷，坐來心益閑。無人知落處，萬木冷空山。',48,'御定全唐詩/json/716.json','["瀉月聲不斷，坐來心益閑。無人知落處，萬木冷空山。", "遠憶雲容外，幽疑石縫間。那辭通曙聽，明日度藍關。"]'),
('yuding-12','書懷','曹松','唐','御定全唐诗','yuding','','[]','默默守吾道，望榮來替愁。吟詩應有罪，當路卻如讎。',48,'御定全唐詩/json/716.json','["默默守吾道，望榮來替愁。吟詩應有罪，當路卻如讎。", "陸海儻難溺，九霄爭便休。敢言名譽出，天未白吾頭。"]'),
('yuding-13','道中','曹松','唐','御定全唐诗','yuding','','[]','出門嗟世路，何日樸風歸。是處太行險，□□應解飛。',48,'御定全唐詩/json/716.json','["出門嗟世路，何日樸風歸。是處太行險，□□應解飛。", "主人厚薄禮，客子新故衣。所以澆浮態，多令行者違。"]'),
('yuding-14','夏雲','曹松','唐','御定全唐诗','yuding','','[]','勢能成嶽仞，頃刻長崔嵬。暝鳥飛不到，野風吹得開。',48,'御定全唐詩/json/716.json','["勢能成嶽仞，頃刻長崔嵬。暝鳥飛不到，野風吹得開。", "一天分萬態，立地看忘回。欲結暑宵雨，先聞江上雷。"]'),
('yuding-15','塞上行','曹松','唐','御定全唐诗','yuding','','[]','上將擁黃須，安西逐指呼。離鄉俱少壯，到磧減肌膚。',48,'御定全唐詩/json/716.json','["上將擁黃須，安西逐指呼。離鄉俱少壯，到磧減肌膚。", "風雪夜防塞，腥膻朝系胡。為君樂戰死，誰喜作征夫。"]'),
('yuding-16','晨起','曹松','唐','御定全唐诗','yuding','','[]','曉色教不睡，捲簾清氣中。林殘數枝月，發冷一梳風。',48,'御定全唐詩/json/716.json','["曉色教不睡，捲簾清氣中。林殘數枝月，發冷一梳風。", "並鳥含鐘語，欹荷隔霧空。莫疑營白日，道路本無窮。"]'),
('yuding-17','感世','曹松','唐','御定全唐诗','yuding','','[]','觸目盡如幻，幻中能幾時。愁來舍行樂，事去莫吞悲。',48,'御定全唐詩/json/716.json','["觸目盡如幻，幻中能幾時。愁來舍行樂，事去莫吞悲。", "白髮不由己，黃金留待誰。耕煙得銘志，翻為古人思。"]'),
('yuding-18','觀華夷圖','曹松','唐','御定全唐诗','yuding','','[]','落筆勝縮地，展圖當晏寧。中華屬貴分，遠裔占何星。',48,'御定全唐詩/json/716.json','["落筆勝縮地，展圖當晏寧。中華屬貴分，遠裔占何星。", "分寸辨諸嶽，鬥升觀四溟。長疑未到處，一一似曾經。"]'),
('yuding-19','山中寒夜呈進士許棠','曹松','唐','御定全唐诗','yuding','','[]','山寒草堂暖，寂夜有良朋。讀易分高燭，煎茶取折冰。',48,'御定全唐詩/json/716.json','["山寒草堂暖，寂夜有良朋。讀易分高燭，煎茶取折冰。", "庭垂河半形，窗露月微棱。俱入論心地，爭無俗者憎。"]'),
('yuding-20','滕王閣春日晚眺','曹松','唐','御定全唐诗','yuding','','[]','淩春帝子閣，偶眺日移西。浪勢平花塢，帆陰上柳堤。',48,'御定全唐詩/json/716.json','["淩春帝子閣，偶眺日移西。浪勢平花塢，帆陰上柳堤。", "凝嵐藏宿翼，疊鼓碎歸蹄。只此長吟詠，因高思不迷。"]'),
('yuding-21','鐘陵野步','曹松','唐','御定全唐诗','yuding','','[]','岡扉聊自啟，信步出波邊。野火風吹闊，春冰鶴啄穿。',48,'御定全唐詩/json/716.json','["岡扉聊自啟，信步出波邊。野火風吹闊，春冰鶴啄穿。", "渚檣齊驛樹，山鳥入公田。未創孤雲勢，空思白閣年。"]'),
('yuding-22','哭胡處士','曹松','唐','御定全唐诗','yuding','','[]','故人江閣在，重到事悠悠。無爾向潭上，為吾傾甕頭。',48,'御定全唐詩/json/716.json','["故人江閣在，重到事悠悠。無爾向潭上，為吾傾甕頭。", "空餘赤楓葉，墮落釣魚舟。疑是沖虛去，不為天地囚。"]'),
('yuding-23','青龍寺贈雲顥法師','曹松','唐','御定全唐诗','yuding','','[]','紫檀衣且香，春殿日尤長。此地開新講，何山鎖舊房。',48,'御定全唐詩/json/716.json','["紫檀衣且香，春殿日尤長。此地開新講，何山鎖舊房。", "僧名喧北闕，師印續南方。莫惜青蓮喻，秦人聽未忘。"]'),
('yuding-24','薦福寺贈應制白公','曹松','唐','御定全唐诗','yuding','','[]','才子紫檀衣，明君寵顧時。講升高座懶，書答重臣遲。',48,'御定全唐詩/json/716.json','["才子紫檀衣，明君寵顧時。講升高座懶，書答重臣遲。", "瓶勢傾圓頂，刀聲落碎髭。還聞穿內去，隨駕進新詩。"]'),
('yuding-25','觀山寺僧穿井','曹松','唐','御定全唐诗','yuding','','[]','雲僧鑿山井，寒碧在中庭。況是分岩眼，同來下石瓶。',48,'御定全唐詩/json/716.json','["雲僧鑿山井，寒碧在中庭。況是分岩眼，同來下石瓶。", "旁痕終變蘚，圓影即澄星。異夜天龍蟄，應聞說葉經。"]'),
('yuding-26','送德光禪師','曹松','唐','御定全唐诗','yuding','','[]','天涯緣事了，又造石霜微。不以千峰險，唯將獨影歸。',48,'御定全唐詩/json/716.json','["天涯緣事了，又造石霜微。不以千峰險，唯將獨影歸。", "有為嫌假佛，無境是真機。到後流沙錫，何時更有飛。"]'),
('yuding-27','贈南陵李主簿','曹松','唐','御定全唐诗','yuding','','[]','外邑官同隱，甯勞短吏趨。看雲情自足，愛酒逸應無。',48,'御定全唐詩/json/716.json','["外邑官同隱，甯勞短吏趨。看雲情自足，愛酒逸應無。", "簟席彈棋子，衣裳惹印朱。仍聞陂水近，亦擬掉菰蒲。"]'),
('yuding-28','慈恩寺東樓','曹松','唐','御定全唐诗','yuding','','[]','寺樓涼出竹，非與曲江賒。野火流穿苑，秦山疊入巴。',48,'御定全唐詩/json/716.json','["寺樓涼出竹，非與曲江賒。野火流穿苑，秦山疊入巴。", "風梢離眾葉，岸角積虛沙。此地鐘聲近，令人思未涯。"]'),
('yuding-29','古塚','曹松','唐','御定全唐诗','yuding','','[]','代遠已難問，累累次古城。民田侵不盡，客路踏還平。',48,'御定全唐詩/json/716.json','["代遠已難問，累累次古城。民田侵不盡，客路踏還平。", "作穴蛇分蟄，依岡鹿繞行。唯應風雨夕，鬼火出林明。"]'),
('yuding-30','訪山友','曹松','唐','御定全唐诗','yuding','','[]','一徑通高屋，重雲翳兩原。山寒初宿頂，泉落未知根。',48,'御定全唐詩/json/716.json','["一徑通高屋，重雲翳兩原。山寒初宿頂，泉落未知根。", "急雨洗荒壁，驚風開靜門。聽君吟廢夜，苦卻建溪猿。"]'),
('yuding-31','林下書懷寄建州李頻員外','曹松','唐','御定全唐诗','yuding','','[]','一從諸事懶，海上跡宜沉。吾道不當路，鄙人甘入林。',48,'御定全唐詩/json/716.json','["一從諸事懶，海上跡宜沉。吾道不當路，鄙人甘入林。", "雲垂方覓鶴，月濕始收琴。水石南州好，誰陪刻骨吟。"]'),
('yuding-32','猿','曹松','唐','御定全唐诗','yuding','','[]','曾宿三巴路，今來不願聽。雲根啼片白，峰頂擲尖青。',48,'御定全唐詩/json/716.json','["曾宿三巴路，今來不願聽。雲根啼片白，峰頂擲尖青。", "護果憎禽啄，棲霜覷葉零。唯應臥嵐客，憐爾傍岩扃。"]'),
('yuding-33','秋日送方幹遊上元','曹松','唐','御定全唐诗','yuding','','[]','天高淮泗白，料子趨修程。汲水疑山動，揚帆覺岸行。',48,'御定全唐詩/json/716.json','["天高淮泗白，料子趨修程。汲水疑山動，揚帆覺岸行。", "雲離京口樹，雁入石頭城。後夜分遙念，諸峰霜露生。"]'),
('yuding-34','哭李頻員外','曹松','唐','御定全唐诗','yuding','','[]','出麾臨建水，下世在公堂。苦集休開篋，清資罷轉郎。',48,'御定全唐詩/json/716.json','["出麾臨建水，下世在公堂。苦集休開篋，清資罷轉郎。", "瘴中無子奠，嶺外一妻孀。定是浮香骨，東歸就故鄉。"]'),
('yuding-35','山中言事','曹松','唐','御定全唐诗','yuding','','[]','嵐靄潤窗櫺，吟詩得冷症。教餐有效藥，多愧獨行僧。',48,'御定全唐詩/json/716.json','["嵐靄潤窗櫺，吟詩得冷症。教餐有效藥，多愧獨行僧。", "雲濕煎茶火，冰封汲井繩。片扉深著掩，經國自無能。"]'),
('yuding-36','送左協律京西從事','曹松','唐','御定全唐诗','yuding','','[]','辟書來幾日，遂喜就嘉招。猶向風沙淺，非於甸服遙。',48,'御定全唐詩/json/716.json','["辟書來幾日，遂喜就嘉招。猶向風沙淺，非於甸服遙。", "時平無探騎，秋靜見盤雕。若遣關中使，煩君問寂寥。"]'),
('yuding-37','望九華寄池陽太守','曹松','唐','御定全唐诗','yuding','','[]','造華峰峰異，宜教嶽德謙。靈蹤載籍古，怪刃刺雲尖。',48,'御定全唐詩/json/716.json','["造華峰峰異，宜教嶽德謙。靈蹤載籍古，怪刃刺雲尖。", "盤蹙陵陽壯，孤標建鄴瞻。霽餘堪洗目，青出謝家簷。"]'),
('yuding-38','上廣州支使王拾遺','曹松','唐','御定全唐诗','yuding','','[]','明時應不諫，天幕稱仙才。聘入關中去，人從帝側來。',48,'御定全唐詩/json/716.json','["明時應不諫，天幕稱仙才。聘入關中去，人從帝側來。", "詩窗盛島嶼，檄盾照風雷。幾度陪旄節，營巡海色回。"]'),
('yuding-39','題僧松禪','曹松','唐','御定全唐诗','yuding','','[]','空山澗畔枯松樹，禪老堂頭甲乙身。',32,'御定全唐詩/json/716.json','["空山澗畔枯松樹，禪老堂頭甲乙身。", "傳是昔朝僧種著，下頭應有茯苓神。"]'),
('yuding-40','贈華陰李明府','曹松','唐','御定全唐诗','yuding','','[]','佩墨縣兼清，約關西近城。三峰豈不重，厚地戴猶輕。',48,'御定全唐詩/json/716.json','["佩墨縣兼清，約關西近城。三峰豈不重，厚地戴猶輕。", "雪筱欹難直，風泉噴易橫。須知高枕外，長是勸民耕。"]'),
('yuding-41','送人庭鶴','曹松','唐','御定全唐诗','yuding','','[]','度歲休籠閉，身輕好羽儀。白雲□是伴，滄海得因誰。',48,'御定全唐詩/json/716.json','["度歲休籠閉，身輕好羽儀。白雲□是伴，滄海得因誰。", "唳起遺殘食，盤餘在迥枝。條風頻雨去，只恐更相隨。"]'),
('yuding-42','信州聞通寺題僧砌下泉','曹松','唐','御定全唐诗','yuding','','[]','細聲從嶠足，幽淡浸香墀。此境未開日，何人初見時。',48,'御定全唐詩/json/716.json','["細聲從嶠足，幽淡浸香墀。此境未開日，何人初見時。", "耗痕延黑蘚，淨罅吐微澌。應有喬梢鶴，下來當飲之。"]'),
('yuding-43','山中','曹松','唐','御定全唐诗','yuding','','[]','此地似商嶺，雲霞空往還。衰條難定鳥，缺月易依山。',48,'御定全唐詩/json/716.json','["此地似商嶺，雲霞空往還。衰條難定鳥，缺月易依山。", "野色耕不盡，溪容釣自閑。分因多臥退，百計少相關。"]'),
('yuding-44','寄崇聖寺僧','曹松','唐','御定全唐诗','yuding','','[]','不醉長安酒，冥心只似師。望山吟過日，伴鶴立多時。',48,'御定全唐詩/json/716.json','["不醉長安酒，冥心只似師。望山吟過日，伴鶴立多時。", "溝遠流聲細，林寒綠色遲。庵西蘿月夕，重約語空期。"]'),
('yuding-45','金陵道中寄','曹松','唐','御定全唐诗','yuding','','[]','忍苦待知音，無時省廢吟。始為分路客，莫問向隅心。',48,'御定全唐詩/json/716.json','["忍苦待知音，無時省廢吟。始為分路客，莫問向隅心。", "嶠翠藏幽瀑，枝風下曉禽。憶君秋欲盡，馬上秣陵砧。"]'),
('yuding-46','都門送許棠東歸','曹松','唐','御定全唐诗','yuding','','[]','舊客東歸遠，長安詩少朋。去愁分磧雁，行計逐鄉僧。',48,'御定全唐詩/json/716.json','["舊客東歸遠，長安詩少朋。去愁分磧雁，行計逐鄉僧。", "華岳無時雪，黃河漫處冰。知辭國門路，片席認西陵。"]'),
('yuding-47','送進士喻坦之游太原','曹松','唐','御定全唐诗','yuding','','[]','北鄙征難盡，詩愁滿去程。廢巢侵燒色，荒塚入鋤聲。',48,'御定全唐詩/json/716.json','["北鄙征難盡，詩愁滿去程。廢巢侵燒色，荒塚入鋤聲。", "逗野河流濁，離雲磧日明。並州戎壘地，角動引風生。"]'),
('yuding-48','九江暮春書事','曹松','唐','御定全唐诗','yuding','','[]','楊柳城初鎖，輪蹄息去蹤。春流無舊岸，夜色失諸峰。',48,'御定全唐詩/json/716.json','["楊柳城初鎖，輪蹄息去蹤。春流無舊岸，夜色失諸峰。", "影動漁邊火，聲遲話後鐘。明朝回去雁，誰向北郊逢。"]'),
('yuding-49','再到洪州望西山','曹松','唐','御定全唐诗','yuding','','[]','洪州向西顧，不忍暫忘君。記得瀑泉落，省同幽鳥聞。',48,'御定全唐詩/json/716.json','["洪州向西顧，不忍暫忘君。記得瀑泉落，省同幽鳥聞。", "一回經雨雹，長有剩風雲。未定卻棲息，前頭江海分。"]'),
('yuding-50','與胡汾坐月期貫休上人不至','曹松','唐','御定全唐诗','yuding','','[]','掃庭秋漏滴，接話貴忘眠。靜夜人相語，低枝鳥暗遷。',48,'御定全唐詩/json/716.json','["掃庭秋漏滴，接話貴忘眠。靜夜人相語，低枝鳥暗遷。", "星圍南極定，月照斷河連。後會花宮子，應開石上禪。"]'),
('yuding-51','贈胡處士','曹松','唐','御定全唐诗','yuding','','[]','年光離嶽色，帶疾臥南原。白日與無事，俗人嗔閉門。',48,'御定全唐詩/json/716.json','["年光離嶽色，帶疾臥南原。白日與無事，俗人嗔閉門。", "樵魚臨片水，野鹿入荒園。莫問榮華事，清霜點發根。"]'),
('yuding-52','鉛山寫懷','曹松','唐','御定全唐诗','yuding','','[]','天涯兵火後，風景畏臨門。骨肉到時節，團圓因夢魂。',48,'御定全唐詩/json/716.json','["天涯兵火後，風景畏臨門。骨肉到時節，團圓因夢魂。", "池塘營水眼，嶺嶠結花根。耳縱聽歌吹，中心不可論。"]'),
('yuding-53','書翠岩寺壁','曹松','唐','御定全唐诗','yuding','','[]','何年話尊宿，瞻禮此堂中。入郭非無路，歸林自學空。',48,'御定全唐詩/json/716.json','["何年話尊宿，瞻禮此堂中。入郭非無路，歸林自學空。", "濺瓶雲嶠水，逆磬雪川風。時說南廬事，知師用意同。"]'),
('yuding-54','江西題東湖','曹松','唐','御定全唐诗','yuding','','[]','鑿出江湖思，涼多□□間。無風觸微浪，半日□秋山。',48,'御定全唐詩/json/716.json','["鑿出江湖思，涼多□□間。無風觸微浪，半日□秋山。", "客袖沙光滿，船窗荻影閑。時人見黃綬，應笑狎鷗還。"]'),
('yuding-55','題湖南嶽麓寺','曹松','唐','御定全唐诗','yuding','','[]','海雲山上寺，每到每開襟。萬木長不住，細泉聽更深。',48,'御定全唐詩/json/716.json','["海雲山上寺，每到每開襟。萬木長不住，細泉聽更深。", "蜩沾高雨斷，鳥遇夕嵐沈。此地良宵月，秋懷隔楚砧。"]'),
('yuding-56','贈衡山麋明府','曹松','唐','御定全唐诗','yuding','','[]','為縣瀟湘水，門前樹配苔。晚吟公籍少，春醉積林開。',48,'御定全唐詩/json/716.json','["為縣瀟湘水，門前樹配苔。晚吟公籍少，春醉積林開。", "滌硯松香起，擎茶嶽影來。任官當此境，更莫夢天臺。"]'),
('yuding-57','塞上','曹松','唐','御定全唐诗','yuding','','[]','邊寒來所闊，今日複明朝。河淩堅通馬，胡雲缺見雕。',48,'御定全唐詩/json/716.json','["邊寒來所闊，今日複明朝。河淩堅通馬，胡雲缺見雕。", "砂中程獨泣，鄉外隱誰招。回首若經歲，靈州生柳條。"]'),
('yuding-58','送邵安石及第歸連州覲省','曹松','唐','御定全唐诗','yuding','','[]','及第兼歸覲，宜忘涉驛勞。青雲重慶少，白日一飛高。',48,'御定全唐詩/json/716.json','["及第兼歸覲，宜忘涉驛勞。青雲重慶少，白日一飛高。", "轉楚聞啼狖，臨湘見疊濤。海陽沈飲罷，何地佐旌旄。"]'),
('yuding-59','邊上送友人歸甯','曹松','唐','御定全唐诗','yuding','','[]','鄉路穿京過，寧心去少同。日斜尋闊磧，春盡逐歸鴻。',48,'御定全唐詩/json/716.json','["鄉路穿京過，寧心去少同。日斜尋闊磧，春盡逐歸鴻。", "獨樹河聲外，凝笳塞色中。憐君到此處，卻背老萊風。"]'),
('yuding-60','除夜','曹松','唐','御定全唐诗','yuding','','[]','殘臘即又盡，東風應漸聞。一宵猶幾許，兩歲欲平分。',48,'御定全唐詩/json/716.json','["殘臘即又盡，東風應漸聞。一宵猶幾許，兩歲欲平分。", "燎暗傾時鬥，春通綻處芬。明朝遙捧酒，先合祝堯君。"]'),
('yuding-61','題甘露寺','曹松','唐','御定全唐诗','yuding','','[]','香門接巨壘，畫角間清鐘。北固一何峭，西僧多此逢。',48,'御定全唐詩/json/716.json','["香門接巨壘，畫角間清鐘。北固一何峭，西僧多此逢。", "天垂無際海，雲白久晴峰。旦暮然燈外，濤頭振蟄龍。"]'),
('yuding-62','貽住山僧','曹松','唐','御定全唐诗','yuding','','[]','罷講巡岩塢，無窮得野情。臘高猶伴鹿，夏滿不歸城。',48,'御定全唐詩/json/716.json','["罷講巡岩塢，無窮得野情。臘高猶伴鹿，夏滿不歸城。", "雲朵緣崖發，峰陰截水清。自然雙洗耳，唯任白毫生。"]'),
('yuding-63','題鶴鳴泉','曹松','唐','御定全唐诗','yuding','','[]','仙鶴曾鳴處，泉兼半井苔。直峰拋影入，片月瀉光來。',48,'御定全唐詩/json/716.json','["仙鶴曾鳴處，泉兼半井苔。直峰拋影入，片月瀉光來。", "瀲灩侵顏冷，深沉慰眼開。何因值舟頂，滿汲石瓶回。"]'),
('yuding-64','吊賈島二首','曹松','唐','御定全唐诗','yuding','','[]','先生不折桂，謫去抱何冤。已葬離燕骨，難招入劍魂。',96,'御定全唐詩/json/716.json','["先生不折桂，謫去抱何冤。已葬離燕骨，難招入劍魂。", "旅墳低卻草，稚子哭勝猿。冥寞如搜句，宜邀賀監論。", "青旆低寒水，清笳出曉風。鳥為傷賈傅，馬立葬滕公。", "松柏青山上，城池白日中。一朝今古隔，惟有月明同。"]'),
('yuding-65','憶江西並悼亡友','曹松','唐','御定全唐诗','yuding','','[]','前心奈兵阻，悔作豫章分。芳草未歸日，故人多是墳。',48,'御定全唐詩/json/716.json','["前心奈兵阻，悔作豫章分。芳草未歸日，故人多是墳。", "帆行出岫雨，馬踐過江雲。此地一樽酒，當時皆以文。"]'),
('yuding-0','九江送方幹歸鏡湖','曹松','唐','御定全唐诗','yuding','','[]','一檣懸五兩，此日動歸風。客路拋湓口，家林入鏡中。',48,'御定全唐詩/json/717.json','["一檣懸五兩，此日動歸風。客路拋湓口，家林入鏡中。", "譚餘雲出嶠，詠苦月欹空。更若看鳷鵲，何人夜坐同。"]'),
('yuding-1','廬山訪賈匡','曹松','唐','御定全唐诗','yuding','','[]','西城疾病日，此地少尋君。古跡春猶在，遙泉夜盡聞。',48,'御定全唐詩/json/717.json','["西城疾病日，此地少尋君。古跡春猶在，遙泉夜盡聞。", "片時三處雨，九疊幾重雲。到者皆忘寐，神精與俗分。"]'),
('yuding-2','顧少府池上','曹松','唐','御定全唐诗','yuding','','[]','池上分行種，公庭覺少塵。根離潮水岸，韻爽判曹人。',48,'御定全唐詩/json/717.json','["池上分行種，公庭覺少塵。根離潮水岸，韻爽判曹人。", "正午回魚影，方昏息鷺身。無時不動詠，滄島思方頻。"]'),
('yuding-3','喜友人歸上元別業','曹松','唐','御定全唐诗','yuding','','[]','一檣千裏外，隱者興宜孤。落日長邊海，秋風滿故都。',48,'御定全唐詩/json/717.json','["一檣千裏外，隱者興宜孤。落日長邊海，秋風滿故都。", "掩關苔色老，盤徑葉聲枯。匡岳來時過，遲回絕頂無。"]'),
('yuding-4','曲江暮春雪霽','曹松','唐','御定全唐诗','yuding','','[]','霽動江池色，春殘一去遊。菰風生馬足，槐雪滴人頭。',48,'御定全唐詩/json/717.json','["霽動江池色，春殘一去遊。菰風生馬足，槐雪滴人頭。", "北闕塵未起，南山青欲流。如何多別地，卻得醉汀洲。"]'),
('yuding-5','立春日','曹松','唐','御定全唐诗','yuding','','[]','春飲一杯酒，便吟春日詩。木梢寒未覺，地脈暖先知。',48,'御定全唐詩/json/717.json','["春飲一杯酒，便吟春日詩。木梢寒未覺，地脈暖先知。", "鳥囀星沈後，山分雪薄時。賞心無處說，悵望曲江池。"]'),
('yuding-6','宿溪僧院','曹松','唐','御定全唐诗','yuding','','[]','少年雲溪裏，禪心夜更閑。煎茶留靜者，靠月坐蒼山。',48,'御定全唐詩/json/717.json','["少年雲溪裏，禪心夜更閑。煎茶留靜者，靠月坐蒼山。", "露白鐘尋定，螢多戶未關。嵩陽大石室，何日譯經還。"]'),
('yuding-7','石頭懷古','曹松','唐','御定全唐诗','yuding','','[]','日月出又沒，台城空白雲。雖寬百姓土，漸缺六朝墳。',48,'御定全唐詩/json/717.json','["日月出又沒，台城空白雲。雖寬百姓土，漸缺六朝墳。", "禾黍是亡國，山河歸聖君。松聲驟雨足，幾寺晚鐘聞。"]'),
('yuding-8','浙右贈陸處士','曹松','唐','御定全唐诗','yuding','','[]','靜節灌園餘，得非成隱居。長當庚子日，獨拜五經書。',48,'御定全唐詩/json/717.json','["靜節灌園餘，得非成隱居。長當庚子日，獨拜五經書。", "白浪吹亡國，秋霜洗大虛。門前是京口，身外不營儲。"]'),
('yuding-9','哭胡處士','曹松','唐','御定全唐诗','yuding','','[]','丘中久不起，將謂詔書來。及見淩雲說，方知掩夜台。',48,'御定全唐詩/json/717.json','["丘中久不起，將謂詔書來。及見淩雲說，方知掩夜台。", "白衣歸北路，玄造亦遺才。世上亡君後，詩聲更大哉。"]'),
('yuding-10','贈餘幹袁明府','曹松','唐','御定全唐诗','yuding','','[]','一雨西城色，陶家心自清。山銜中郭分，雲卷下湖程。',48,'御定全唐詩/json/717.json','["一雨西城色，陶家心自清。山銜中郭分，雲卷下湖程。", "公署聞流木，人煙入廢城。難忘楚盡處，新有越吟生。"]'),
('yuding-11','贈雷鄉張明府','曹松','唐','御定全唐诗','yuding','','[]','任官征戰後，度日寄閑身。封卷還高客，飛書問野人。',48,'御定全唐詩/json/717.json','["任官征戰後，度日寄閑身。封卷還高客，飛書問野人。", "廢田教種穀，生路遣尋薪。若起柴桑興，無先漉酒巾。"]'),
('yuding-12','岳陽晚泊','曹松','唐','御定全唐诗','yuding','','[]','輕帆下闊流，便泊此沙洲。湖影撼山朵，日陽燒野愁。',48,'御定全唐詩/json/717.json','["輕帆下闊流，便泊此沙洲。湖影撼山朵，日陽燒野愁。", "白波爭起倒，青嶼或沈浮。是際船中望，東南仞仞秋。"]'),
('yuding-13','覽春榜喜孫鄠成名','曹松','唐','御定全唐诗','yuding','','[]','門外報春榜，喜君天子知。舊愁渾似雪，見日總消時。',48,'御定全唐詩/json/717.json','["門外報春榜，喜君天子知。舊愁渾似雪，見日總消時。", "塔下牡丹氣，江頭楊柳絲。風光若有分，無處不相宜。"]'),
('yuding-14','己亥歲二首','曹松','唐','御定全唐诗','yuding','','[]','澤國江山入戰圖，生民何計樂樵蘇。',64,'御定全唐詩/json/717.json','["澤國江山入戰圖，生民何計樂樵蘇。", "憑君莫話封侯事，一將功成萬骨枯。", "傳聞一戰百神愁，兩岸強兵過未休。", "誰道滄江總無事，近來長共血爭流。"]'),
('yuding-15','亂後入洪州西山','曹松','唐','御定全唐诗','yuding','','[]','寂寂陰溪水漱苔，塵中將得苦吟來。',32,'御定全唐詩/json/717.json','["寂寂陰溪水漱苔，塵中將得苦吟來。", "東峰道士如相問，縣令而今不姓梅。"]'),
('yuding-16','送僧入廬山','曹松','唐','御定全唐诗','yuding','','[]','若到江州二林寺，遍游應未出雲霞。',32,'御定全唐詩/json/717.json','["若到江州二林寺，遍游應未出雲霞。", "廬山瀑布三千仞，畫破青霄始落斜。"]'),
('yuding-17','送僧入蜀過夏','曹松','唐','御定全唐诗','yuding','','[]','師言結夏入巴峰，雲水回頭幾萬重。',32,'御定全唐詩/json/717.json','["師言結夏入巴峰，雲水回頭幾萬重。", "五月峨眉須近火，木皮領重只如冬。"]'),
('yuding-18','江西逢僧省文','曹松','唐','御定全唐诗','yuding','','[]','閩地高僧楚地逢，僧遊蠻錫掛垂松。',72,'御定全唐詩/json/717.json','["閩地高僧楚地逢，僧遊蠻錫掛垂松。", "白雲逸性都無定，才出雙峰愛五峰。", "高僧不負雪峰期，卻伴青霞入翠微。百葉岩前霜欲降，", "想得白蓮花上月，滿山猶帶舊光輝。"]'),
('yuding-19','水精念珠','曹松','唐','御定全唐诗','yuding','','[]','等量紅縷貫晶熒，盡道勻圓別未勝。鑿斷玉潭盈尺水，',40,'御定全唐詩/json/717.json','["等量紅縷貫晶熒，盡道勻圓別未勝。鑿斷玉潭盈尺水，", "幾度夜深尋不著，琉璃為殿月為燈。"]'),
('yuding-20','南海旅次','曹松','唐','御定全唐诗','yuding','','[]','憶歸休上越王台，歸思臨高不易裁。為客正當無雁處，',40,'御定全唐詩/json/717.json','["憶歸休上越王台，歸思臨高不易裁。為客正當無雁處，", "心似百花開未得，年年爭發被春催。"]'),
('yuding-21','春草','曹松','唐','御定全唐诗','yuding','','[]','不獨滿池塘，夢中佳句香。春風有餘力，引上古城牆。',24,'御定全唐詩/json/717.json','["不獨滿池塘，夢中佳句香。春風有餘力，引上古城牆。"]'),
('yuding-22','金谷園','曹松','唐','御定全唐诗','yuding','','[]','當年歌舞時，不說草離離。今日歌舞盡，滿園秋露垂。',24,'御定全唐詩/json/717.json','["當年歌舞時，不說草離離。今日歌舞盡，滿園秋露垂。"]'),
('yuding-23','夏日東齋','曹松','唐','御定全唐诗','yuding','','[]','三庚到秋伏，偶來松檻立。熱少清風多，開門放山入。',24,'御定全唐詩/json/717.json','["三庚到秋伏，偶來松檻立。熱少清風多，開門放山入。"]'),
('yuding-24','南朝','曹松','唐','御定全唐诗','yuding','','[]','三籬蓋馳道，風烈一無取。時見牧牛童，嗔牛吃禾黍。',24,'御定全唐詩/json/717.json','["三籬蓋馳道，風烈一無取。時見牧牛童，嗔牛吃禾黍。"]'),
('yuding-25','言懷','曹松','唐','御定全唐诗','yuding','','[]','出山不得意，謁帝值戈鋋。豈料為文日，翻成用武年。',24,'御定全唐詩/json/717.json','["出山不得意，謁帝值戈鋋。豈料為文日，翻成用武年。"]'),
('yuding-26','寒食日題杜鵑花','曹松','唐','御定全唐诗','yuding','','[]','一朵又一朵，並開寒食時。誰家不禁火，總在此花枝。',24,'御定全唐詩/json/717.json','["一朵又一朵，並開寒食時。誰家不禁火，總在此花枝。"]'),
('yuding-27','鐘陵寒食日郊外閒遊','曹松','唐','御定全唐诗','yuding','','[]','可憐時節足風情，杏子粥香如冷餳。',32,'御定全唐詩/json/717.json','["可憐時節足風情，杏子粥香如冷餳。", "無奈春風輸舊火，遍教人喚作山櫻。"]'),
('yuding-28','中秋對月','曹松','唐','御定全唐诗','yuding','','[]','無雲世界秋三五，共看蟾盤上海涯。',32,'御定全唐詩/json/717.json','["無雲世界秋三五，共看蟾盤上海涯。", "直到天頭天盡處，不曾私照一人家。"]'),
('yuding-29','陪湖南李中丞宴隱溪','曹松','唐','御定全唐诗','yuding','','[]','竹林啼鳥不知休，羅列飛橋水亂流。觸散柳絲回玉勒，',40,'御定全唐詩/json/717.json','["竹林啼鳥不知休，羅列飛橋水亂流。觸散柳絲回玉勒，", "若值主人嫌晝短，應陪秉燭夜深遊。"]'),
('yuding-30','別湖上主人','曹松','唐','御定全唐诗','yuding','','[]','門系釣舟雲滿岸，借君幽致坐移旬。湖村夜叫白蕪雁，',40,'御定全唐詩/json/717.json','["門系釣舟雲滿岸，借君幽致坐移旬。湖村夜叫白蕪雁，", "不辭更住醒還醉，太一東峰歸夢頻。"]'),
('yuding-31','贈廣宣大師','曹松','唐','御定全唐诗','yuding','','[]','憶昔同遊紫閣雲，別來三十二回春。',32,'御定全唐詩/json/717.json','["憶昔同遊紫閣雲，別來三十二回春。", "白頭相見雙林下，猶是清朝未退人。"]'),
('yuding-32','鐘陵寒食日與同年裴顏李先輩、鄭校書郊外閒遊','曹松','唐','御定全唐诗','yuding','','[]','寒節鐘陵香騎隨，同年相命楚江湄。雲間影過秋千女，',40,'御定全唐詩/json/717.json','["寒節鐘陵香騎隨，同年相命楚江湄。雲間影過秋千女，", "銀瓶冷酒皆傾盡，半臥垂楊自不知。"]'),
('yuding-33','江外除夜','曹松','唐','御定全唐诗','yuding','','[]','千門庭燎照樓臺，總為年光急急催。半夜臘因風卷去，',40,'御定全唐詩/json/717.json','["千門庭燎照樓臺，總為年光急急催。半夜臘因風卷去，", "不是多岐漸平穩，誰能呼酒祝昭回。"]'),
('yuding-34','七夕','曹松','唐','御定全唐诗','yuding','','[]','牛女相期七夕秋，相逢俱喜鵲橫流。彤雲縹緲回金輅，',40,'御定全唐詩/json/717.json','["牛女相期七夕秋，相逢俱喜鵲橫流。彤雲縹緲回金輅，", "更殘便是分襟處，曉箭東來射翠樓。"]'),
('yuding-35','羅浮山下書逸人壁','曹松','唐','御定全唐诗','yuding','','[]','海上亭臺山下煙，買時幽邃不爭錢。莫言白日催華髮，',40,'御定全唐詩/json/717.json','["海上亭臺山下煙，買時幽邃不爭錢。莫言白日催華髮，", "可中更踐無人境，知是羅浮第幾天。"]'),
('yuding-36','天臺瀑布','曹松','唐','御定全唐诗','yuding','','[]','萬仞得名雲瀑布，遠看如織掛天臺。休疑寶尺難量度，',40,'御定全唐詩/json/717.json','["萬仞得名雲瀑布，遠看如織掛天臺。休疑寶尺難量度，", "欲知便是銀河水，墮落人間合卻回。"]'),
('yuding-37','桂江','曹松','唐','御定全唐诗','yuding','','[]','未識佳人尋桂水，水雲先解傍壺觴。筍林次第添斑竹，',40,'御定全唐詩/json/717.json','["未識佳人尋桂水，水雲先解傍壺觴。筍林次第添斑竹，", "如飛似墮皆青壁，畫手不強元化強。"]'),
('yuding-38','南海','曹松','唐','御定全唐诗','yuding','','[]','傾騰界漢沃諸蠻，立望何如畫此看。無地不同方覺遠，',40,'御定全唐詩/json/717.json','["傾騰界漢沃諸蠻，立望何如畫此看。無地不同方覺遠，", "萬狀千形皆得意，長鯨獨自轉身難。"]'),
('yuding-39','洞庭湖','曹松','唐','御定全唐诗','yuding','','[]','東西南北各連空，波上唯留小朵峰。長與岳陽翻鼓角，',40,'御定全唐詩/json/717.json','["東西南北各連空，波上唯留小朵峰。長與岳陽翻鼓角，", "直到劫餘還作陸，是時應有羽人逢。"]'),
('yuding-40','霍山','曹松','唐','御定全唐诗','yuding','','[]','七千七百七十丈，丈丈藤蘿勢入天。未必展來空似翅，',40,'御定全唐詩/json/717.json','["七千七百七十丈，丈丈藤蘿勢入天。未必展來空似翅，", "直是畫工須閣筆，況無名畫可流傳。"]'),
('yuding-41','巫峽','曹松','唐','御定全唐诗','yuding','','[]','巫山蒼翠峽通津，下有仙宮楚女真。不逐彩雲歸碧落，',40,'御定全唐詩/json/717.json','["巫山蒼翠峽通津，下有仙宮楚女真。不逐彩雲歸碧落，", "應是荊山留不住，至今猶得睹芳塵。"]'),
('yuding-42','送陳樵校書歸泉州','曹松','唐','御定全唐诗','yuding','','[]','巨塔列名題，詩心亦罕齊。除官京下闕，乞假海門西。',72,'御定全唐詩/json/717.json','["巨塔列名題，詩心亦罕齊。除官京下闕，乞假海門西。", "別席侵殘漏，歸程避戰鼙。關遙秦雁斷，家近瘴雲低。", "候馬春風館，迎船曉月溪。帝京須早入，莫被刺桐迷。"]'),
('yuding-43','贈鏡湖處士方幹二首','曹松','唐','御定全唐诗','yuding','','[]','包含教化剩搜羅，句出東甌奈峭何。世路不妨平處少，',80,'御定全唐詩/json/717.json','["包含教化剩搜羅，句出東甌奈峭何。世路不妨平處少，", "後輩難為措機杼，先生織字得龍梭。", "只擬應星眠越絕，唯將麗什當高勳。磨礱清濁人難會，", "他時莫為三征起，門外沙鷗解笑君。"]'),
('yuding-44','拜訪陸處士','曹松','唐','御定全唐诗','yuding','','[]','萬卷書邊人半白，再來惟恐降玄纁。性靈比鶴爭多少，',40,'御定全唐詩/json/717.json','["萬卷書邊人半白，再來惟恐降玄纁。性靈比鶴爭多少，", "將知穀口耕煙者，低視齊梁楚趙君。"]'),
('yuding-45','嶺南道中','曹松','唐','御定全唐诗','yuding','','[]','百花成實未成歸，未必歸心與志違。但有壺觴資逸詠，',40,'御定全唐詩/json/717.json','["百花成實未成歸，未必歸心與志違。但有壺觴資逸詠，", "遊子馬前芳草合，鷓鴣啼歇又南飛。"]'),
('yuding-46','春日自吳門之陽羨道中書事','曹松','唐','御定全唐诗','yuding','','[]','勝異恣游應未遍，路岐猶去幾時還。浪花湖闊虹蜺斷，',40,'御定全唐詩/json/717.json','["勝異恣游應未遍，路岐猶去幾時還。浪花湖闊虹蜺斷，", "眼前便是神仙事，何必須言洞府間。"]'),
('yuding-47','將入關行次湘陰','曹松','唐','御定全唐诗','yuding','','[]','背顧秦城在何處，圖書作伴過湘東。神鴉亂噪黃陵近，',40,'御定全唐詩/json/717.json','["背顧秦城在何處，圖書作伴過湘東。神鴉亂噪黃陵近，", "也知漸老岩棲穩，爭奈文闈有至公。"]'),
('yuding-48','題昭州山寺常寂上人水閣','曹松','唐','御定全唐诗','yuding','','[]','常寂常居常寂裏，年年月月是空空。階前未放岩根斷，',40,'御定全唐詩/json/717.json','["常寂常居常寂裏，年年月月是空空。階前未放岩根斷，", "他時憶著堪圖畫，一朵雲山二水中。"]'),
('yuding-49','廣州貽匡緒法師','曹松','唐','御定全唐诗','yuding','','[]','口宣微密不思議，不是除貪即誡癡。只待外方緣了日，',40,'御定全唐詩/json/717.json','["口宣微密不思議，不是除貪即誡癡。只待外方緣了日，", "必竟懶過高坐寺，未能全讓法雲師。"]'),
('yuding-50','贈道人','曹松','唐','御定全唐诗','yuding','','[]','住山因以福為庭，便向山中隱姓名。閬苑駕將雕羽去，',40,'御定全唐詩/json/717.json','["住山因以福為庭，便向山中隱姓名。閬苑駕將雕羽去，", "顧我從來斷浮濁，擬驅雞犬上三清。"]'),
('yuding-51','送乞雨禪師臨遇南游','曹松','唐','御定全唐诗','yuding','','[]','活得枯樵耕者知，巡方又欲向天涯。珠穿閩國菩提子，',40,'御定全唐詩/json/717.json','["活得枯樵耕者知，巡方又欲向天涯。珠穿閩國菩提子，", "生緣在地南浮去，自此孤雲不可期。"]'),
('yuding-52','南海陪鄭司空遊荔園','曹松','唐','御定全唐诗','yuding','','[]','荔枝時節出旌斿，南國名園盡興遊。亂結羅紋照襟袖，',40,'御定全唐詩/json/717.json','["荔枝時節出旌斿，南國名園盡興遊。亂結羅紋照襟袖，", "他日為霖不將去，也須圖畫取風流。"]'),
('yuding-53','李郎中林亭','曹松','唐','御定全唐诗','yuding','','[]','只向砌邊流野水，樽前上下看魚兒。筍蹊已長過人竹，',40,'御定全唐詩/json/717.json','["只向砌邊流野水，樽前上下看魚兒。筍蹊已長過人竹，", "大才必擬逍遙去，更遣何人佐盛時。"]'),
('yuding-54','夜飲','曹松','唐','御定全唐诗','yuding','','[]','良宵公子宴蘭堂，濃麝熏人獸吐香。雲帶金龍銜畫燭，',40,'御定全唐詩/json/717.json','["良宵公子宴蘭堂，濃麝熏人獸吐香。雲帶金龍銜畫燭，", "席上未知簾幕曉，青娥低語指東方。"]'),
('yuding-55','駙馬宅宴罷','曹松','唐','御定全唐诗','yuding','','[]','粉牆殘月照宮祠，宴闋銀瓶一半欹。',32,'御定全唐詩/json/717.json','["粉牆殘月照宮祠，宴闋銀瓶一半欹。", "學語鶯兒飛未穩，放身斜墜綠楊枝。"]'),
('yuding-56','吊建州李員外','曹松','唐','御定全唐诗','yuding','','[]','銘旌歸故里，猿鳥亦淒然。已葬桐江月，空回建水船。',48,'御定全唐詩/json/717.json','["銘旌歸故里，猿鳥亦淒然。已葬桐江月，空回建水船。", "客傳為郡日，僧說讀書年。恐有吟魂在，深山古木邊。"]'),
('yuding-57','吊李翰林','曹松','唐','御定全唐诗','yuding','','[]','李白雖然成異物，逸名猶與萬方傳。昔朝曾侍玄宗側，',40,'御定全唐詩/json/717.json','["李白雖然成異物，逸名猶與萬方傳。昔朝曾侍玄宗側，", "投金渚畔春楊柳，自此何人系酒船。"]'),
('yuding-58','山中','曹松','唐','御定全唐诗','yuding','','[]','要路豪家非往還，岩門先有不曾關。眾心惟恐地無剩，',40,'御定全唐詩/json/717.json','["要路豪家非往還，岩門先有不曾關。眾心惟恐地無剩，", "樵夫豈解營生業，貴欲自安麋鹿間。"]'),
('yuding-59','山寺引泉','曹松','唐','御定全唐诗','yuding','','[]','劈碎琅玕意有餘，細泉高引入香廚。',32,'御定全唐詩/json/717.json','["劈碎琅玕意有餘，細泉高引入香廚。", "山僧未肯言根本，莫是銀河漏泄無。"]'),
('yuding-60','友人池上詠蘆','曹松','唐','御定全唐诗','yuding','','[]','秋聲誰種得，蕭瑟在池欄。葉澀棲蟬穩，叢疏宿鷺難。',48,'御定全唐詩/json/717.json','["秋聲誰種得，蕭瑟在池欄。葉澀棲蟬穩，叢疏宿鷺難。", "斂煙宜下□，颯吹省先寒。此物生蒼島，令人憶釣竿。"]'),
('yuding-61','商山','曹松','唐','御定全唐诗','yuding','','[]','垂白商于原下住，兒孫共死一身忙。',32,'御定全唐詩/json/717.json','["垂白商于原下住，兒孫共死一身忙。", "木弓未得長離手，猶與官家射麝香。"]'),
('yuding-62','荊南道中','曹松','唐','御定全唐诗','yuding','','[]','十月荒郊雪氣催，依稀愁色認陽臺。游秦分系三條燭，',40,'御定全唐詩/json/717.json','["十月荒郊雪氣催，依稀愁色認陽臺。游秦分系三條燭，", "如何住在猿聲裏，卻被蟬吟引下來。"]'),
('yuding-63','武德殿朝退望九衢春色','曹松','唐','御定全唐诗','yuding','','[]','玉殿朝初退，天街一看春。南山初過雨，北闕淨無塵。',72,'御定全唐詩/json/717.json','["玉殿朝初退，天街一看春。南山初過雨，北闕淨無塵。", "夾道夭桃滿，連溝禦柳新。蘇舒同舜澤，煦嫗並堯仁。", "佳氣浮軒蓋，和風襲縉紳。自茲憐萬物，同入發生辰。"]'),
('yuding-64','吊北邙','曹松','唐','御定全唐诗','yuding','','[]','山下望山上，夕陽看又曛。無人醫白髮，少地著新墳。',48,'御定全唐詩/json/717.json','["山下望山上，夕陽看又曛。無人醫白髮，少地著新墳。", "歲代殊相遠，賢愚旋不分。東歸聊一吊，亂木倚寒雲。"]'),
('yuding-65','及第敕下，宴中獻座主杜侍郎','曹松','唐','御定全唐诗','yuding','','[]','得召丘牆淚卻頻，若無公道也無因。門前送敕朱衣吏，',40,'御定全唐詩/json/717.json','["得召丘牆淚卻頻，若無公道也無因。門前送敕朱衣吏，", "南山雖有歸溪路，爭那酬恩未殺身。"]'),
('yuding-66','梢雲','曹松','唐','御定全唐诗','yuding','','[]','殊質資靈貺，陵空發瑞雲。梢梢含樹影，鬱鬱動霞文。',72,'御定全唐詩/json/717.json','["殊質資靈貺，陵空發瑞雲。梢梢含樹影，鬱鬱動霞文。", "不比因風起，全非觸石分。葉光閑泛灩，枝彩靜氛氳。", "隱見心無宰，裴回慶自君。翻飛如可托，長願在橫汾。"]'),
('yuding-67','白角簟','曹松','唐','御定全唐诗','yuding','','[]','角簟工夫已到頭，夏來全占滿床秋。若言保惜歸華屋，',40,'御定全唐詩/json/717.json','["角簟工夫已到頭，夏來全占滿床秋。若言保惜歸華屋，", "蒲桃錦是瀟湘底，曾得王孫價倍酬。"]'),
('yuding-68','碧角簟','曹松','唐','御定全唐诗','yuding','','[]','細皮重疊織霜紋，滑膩鋪床勝錦茵。八尺碧天無點翳，',40,'御定全唐詩/json/717.json','["細皮重疊織霜紋，滑膩鋪床勝錦茵。八尺碧天無點翳，", "五月不教炎氣入，滿堂秋色冷龍鱗。"]'),
('yuding-69','滕王閣春日晚望','曹松','唐','御定全唐诗','yuding','','[]','淩春帝子閣，偶眺日移西。浪勢平花塢，帆陰上柳堤。',24,'御定全唐詩/json/717.json','["淩春帝子閣，偶眺日移西。浪勢平花塢，帆陰上柳堤。"]'),
('yuding-70','句','曹松','唐','御定全唐诗','yuding','','[]','追遊若遇三清樂，行從應妨一日春。（李肇《國史補》',113,'御定全唐詩/json/717.json','["追遊若遇三清樂，行從應妨一日春。（李肇《國史補》", "雲：曲江大會，先牒教坊，請奏上禦紫雲樓觀焉。", "時或擬作樂，則為之移日，故曹松詩云云）", "石脈水流泉滴沙，鬼燈然點松柏花。", "鹿眠荒圃寒蕪白，鴉噪殘陽敗葉飛。", "華嶽影寒清露掌，海門風急白潮頭。"]'),
('yuding-0','頌魯','蘇拯','唐','御定全唐诗','yuding','','[]','天推魯仲尼，周遊布典墳。游遍七十國，不令遇一君。',84,'御定全唐詩/json/718.json','["天推魯仲尼，周遊布典墳。游遍七十國，不令遇一君。", "一國如一遇，單車不轉輪。良由至化力，為國不為身。", "禮樂行未足，邅回厄于陳。禮樂今有餘，袞旒當聖人。", "傷哉絕糧議，千載誤云云。"]'),
('yuding-1','醫人','蘇拯','唐','御定全唐诗','yuding','','[]','古人醫在心，心正藥自真。今人醫在手，手濫藥不神。',60,'御定全唐詩/json/718.json','["古人醫在心，心正藥自真。今人醫在手，手濫藥不神。", "我願天地爐，多銜扁鵲身。遍行君臣藥，先從凍餒均。", "自然六合內，少聞貧病人。"]'),
('yuding-2','西施','蘇拯','唐','御定全唐诗','yuding','','[]','吳王從驕佚，天產西施出。豈徒伐一人，所希救群物。',84,'御定全唐詩/json/718.json','["吳王從驕佚，天產西施出。豈徒伐一人，所希救群物。", "良由上天意，惡盈戒奢侈。不獨破吳國，不獨生越水。", "在周名褒姒，在紂名妲己。變化本多塗，生殺亦如此。", "君王政不修，立地生西子。"]'),
('yuding-3','金谷園','蘇拯','唐','御定全唐诗','yuding','','[]','積金累作山，山高小於址。栽花比綠珠，花落還相似。',60,'御定全唐詩/json/718.json','["積金累作山，山高小於址。栽花比綠珠，花落還相似。", "徒有敵國富，不能買東市。徒有絕世容，不能樓上死。", "只此上高樓，何如在平地。"]'),
('yuding-4','巫山','蘇拯','唐','御定全唐诗','yuding','','[]','昔時亦雲雨，今時亦雲雨。自是荒淫多，夢得巫山女。',48,'御定全唐詩/json/718.json','["昔時亦雲雨，今時亦雲雨。自是荒淫多，夢得巫山女。", "從來聖明君，可聽妖魅語。只今峰上雲，徒自生容與。"]'),
('yuding-5','賈客','蘇拯','唐','御定全唐诗','yuding','','[]','長帆掛短舟，所願疾如箭。得喪一驚飄，生死無良賤。',48,'御定全唐詩/json/718.json','["長帆掛短舟，所願疾如箭。得喪一驚飄，生死無良賤。", "不謂天不佑，自是人苟患。嘗言海利深，利深不如淺。"]'),
('yuding-6','狡兔行','蘇拯','唐','御定全唐诗','yuding','','[]','秋來無骨肥，鷹犬遍原野。草中三穴無處藏，',20,'御定全唐詩/json/718.json','["秋來無骨肥，鷹犬遍原野。草中三穴無處藏，"]'),
('yuding-7','長城','蘇拯','唐','御定全唐诗','yuding','','[]','嬴氏設防胡，烝沙築冤壘。蒙公取勳名，豈算生民死。',96,'御定全唐詩/json/718.json','["嬴氏設防胡，烝沙築冤壘。蒙公取勳名，豈算生民死。", "運畚力不禁，碎身砂磧裏。黔黎欲半空，長城舂未已。", "皇天潛鼓怒，力化一女子。遂使萬雉崩，不盡數行淚。", "自古進身者，本非陷物致。當時文德修，不到三世地。"]'),
('yuding-8','織婦女','蘇拯','唐','御定全唐诗','yuding','','[]','伊余盡少女，一種飾螓首。徒能事機杼，與之作歌舞。',64,'御定全唐詩/json/718.json','["伊余盡少女，一種飾螓首。徒能事機杼，與之作歌舞。", "歌舞片時間，黃金翻袖取。只看舞者樂，豈念織者苦。", "感此嘗憶古人言，一婦不織天下寒。"]'),
('yuding-9','古塞下','蘇拯','唐','御定全唐诗','yuding','','[]','百戰已休兵，寒雲愁未歇。血染長城沙，馬踏征人骨。',48,'御定全唐詩/json/718.json','["百戰已休兵，寒雲愁未歇。血染長城沙，馬踏征人骨。", "早得用蛾眉，免陷邊戍卒。始知髦頭星，不在彎弓沒。"]'),
('yuding-10','水旱禱','蘇拯','唐','御定全唐诗','yuding','','[]','禱祈勿告天，酒漿勿澆地。陰陽和也無妖氣，',20,'御定全唐詩/json/718.json','["禱祈勿告天，酒漿勿澆地。陰陽和也無妖氣，"]'),
('yuding-11','鄒律','蘇拯','唐','御定全唐诗','yuding','','[]','鄒律暖燕穀，青史徒編錄。人心不變遷，空吹閑草木。',68,'御定全唐詩/json/718.json','["鄒律暖燕穀，青史徒編錄。人心不變遷，空吹閑草木。", "世患有三惑，爾律莫能抑。邊苦有長征，爾律莫能息。", "斯術未濟時，斯律亦何益。爭如至公一開口，"]'),
('yuding-12','蜘蛛諭','蘇拯','唐','御定全唐诗','yuding','','[]','春蠶吐出絲，濟世功不絕。蜘蛛吐出絲，飛蟲成聚血。',84,'御定全唐詩/json/718.json','["春蠶吐出絲，濟世功不絕。蜘蛛吐出絲，飛蟲成聚血。", "蠶絲何專利，爾絲何專孽。映日張網羅，遮天亦何別。", "儻居要地門，害物可堪說。網成雖福己，網敗還禍爾。", "小人與君子，利害一如此。"]'),
('yuding-13','獵犬行','蘇拯','唐','御定全唐诗','yuding','','[]','獵犬未成行，狐兔無奈何。獵犬今盈群，狐兔依舊多。',92,'御定全唐詩/json/718.json','["獵犬未成行，狐兔無奈何。獵犬今盈群，狐兔依舊多。", "自爾初跳躍，人言多拏躩。常指天外狼，立可口中嚼。", "骨長毛衣重，燒殘煙草薄。狡兔何曾擒，時把家雞捉。", "食盡者飯翻，增養者惡壯。可嗟獵犬壯復壯，"]'),
('yuding-14','斷火謠','蘇拯','唐','御定全唐诗','yuding','','[]','誰謂之推賢，于世何功果。絕爾晉侯交，禁我唐虞火。',92,'御定全唐詩/json/718.json','["誰謂之推賢，于世何功果。絕爾晉侯交，禁我唐虞火。", "國閉檀榆煙，大禮成隳墮。暗室枯槁飯，冷面相看坐。", "陽升既非佑，陰伏若為佐。焉凍群生腹，將止天下禍。", "但究冤濫刑，天道無不可。鄙哉前朝翊贊臣，"]'),
('yuding-15','思婦吟','蘇拯','唐','御定全唐诗','yuding','','[]','秋風雁又歸，邊信一何早。攬衣出門望，落葉滿長道。',44,'御定全唐詩/json/718.json','["秋風雁又歸，邊信一何早。攬衣出門望，落葉滿長道。", "一從秉箕帚，十載孤懷抱。可堪日日醉寵榮，"]'),
('yuding-16','雉兔者','蘇拯','唐','御定全唐诗','yuding','','[]','所獵一何酷，終年耗林麓。飛走如未空，貪殘豈知足。',88,'御定全唐詩/json/718.json','["所獵一何酷，終年耗林麓。飛走如未空，貪殘豈知足。", "嘗聞獵書史，可以鑒榮辱。嘗聞獵賢良，可以霸邦國。", "如何縱網羅，空成肥骨肉。和濟俱不聞，曷所禳顛覆。", "誰能為扣天地爐，鑄此傷生其可乎！"]'),
('yuding-17','藥草','蘇拯','唐','御定全唐诗','yuding','','[]','天子恤疲瘵，坤靈奉其職。年年濟世功，貴賤相兼植。',96,'御定全唐詩/json/718.json','["天子恤疲瘵，坤靈奉其職。年年濟世功，貴賤相兼植。", "因產眾草中，所希采者識。一枝當若神，千金亦何直。", "生草不生藥，無以彰士德。生藥不生草，無以彰奇特。", "國忠在臣賢，民患憑藥力。靈草猶如此，賢人豈多得。"]'),
('yuding-18','凡草誡','蘇拯','唐','御定全唐诗','yuding','','[]','野草凡不凡，亦應生和出。鋤夫耘藥欄，根不留其一。',72,'御定全唐詩/json/718.json','["野草凡不凡，亦應生和出。鋤夫耘藥欄，根不留其一。", "良田本蕪穢，著地成棄物。人生行不修，何門可容膝。", "不唯不爾容，得無凡草嫉。賢愚偃仰間，鑒之宜日日。"]'),
('yuding-19','明禁忌','蘇拯','唐','御定全唐诗','yuding','','[]','陰陽家有書，蔔築多禁忌。土中若有神，穴處何無祟。',120,'御定全唐詩/json/718.json','["陰陽家有書，蔔築多禁忌。土中若有神，穴處何無祟。", "我識先賢意，本誡驕侈地。恣欲創樓臺，率情染朱翠。", "四面興土功，四時妨農事。可以沒凶災，四隅通一二。", "一年省修營，萬民停困躓。動若契於理，福匪神之遺。", "動若越于常，禍乃身之致。神在虛無間，土中非神位。"]'),
('yuding-20','傷彩飾','蘇拯','唐','御定全唐诗','yuding','','[]','朝見亦光彩，暮見亦光彩。一旦風雨飄，十分無一在。',72,'御定全唐詩/json/718.json','["朝見亦光彩，暮見亦光彩。一旦風雨飄，十分無一在。", "爾形才似削，爾貌不如昨。本為是凡姿，誰教染丹雘。", "虛飾片時間，天意以為惡。物假猶如此，人假爭堪作。"]'),
('yuding-21','世迷','蘇拯','唐','御定全唐诗','yuding','','[]','烏兔日夜行，與人運枯榮。為善不常缺，為惡不常盈。',96,'御定全唐詩/json/718.json','["烏兔日夜行，與人運枯榮。為善不常缺，為惡不常盈。", "天道無阿党，人心自覆傾。所以多遷變，寧合天地情。", "我願造化手，莫放狐兔走。恣海產珍奇，縱地生花柳。", "美者一齊美，醜者一齊醜。民心歸大樸，戰爭亦何有。"]'),
('yuding-22','鴟梟','蘇拯','唐','御定全唐诗','yuding','','[]','為害未為害，其如汙物類。斯言之一玷，流傳極天地。',96,'御定全唐詩/json/718.json','["為害未為害，其如汙物類。斯言之一玷，流傳極天地。", "良木不得棲，清波不得戲。曾戲水堪疑，曾棲樹終棄。", "天不殲爾族，與夫惡相濟。地若默爾聲，與夫妖為諱。", "一時懷害心，千古不能替。傷哉醜行人，茲禽亦為譬。"]'),
('yuding-23','山中道者','蘇拯','唐','御定全唐诗','yuding','','[]','筇杖六尺許，坐石流泉所。舉頭看古松，似對仙鶴語。',48,'御定全唐詩/json/718.json','["筇杖六尺許，坐石流泉所。舉頭看古松，似對仙鶴語。", "是時天氣清，四迥無塵侶。顧我笑相迎，知有丹砂異。"]'),
('yuding-24','漁人','蘇拯','唐','御定全唐诗','yuding','','[]','垂竿朝與暮，披蓑臥橫楫。不問清平時，自樂滄波業。',48,'御定全唐詩/json/718.json','["垂竿朝與暮，披蓑臥橫楫。不問清平時，自樂滄波業。", "長畏不得閒，幾度避遊畋。當笑釣臺上，逃名名卻傳。"]'),
('yuding-25','聞猿','蘇拯','唐','御定全唐诗','yuding','','[]','秋風颯颯猿聲起，客恨猿哀一相似。',32,'御定全唐詩/json/718.json','["秋風颯颯猿聲起，客恨猿哀一相似。", "漫向孤危驚客心，何曾解入笙歌耳。"]'),
('yuding-26','經馬嵬坡','蘇拯','唐','御定全唐诗','yuding','','[]','一從殺貴妃，春來花無意。此地縱千年，土香猶破鼻。',48,'御定全唐詩/json/718.json','["一從殺貴妃，春來花無意。此地縱千年，土香猶破鼻。", "寵既出常理，辱豈同常死。一等異於眾，傾覆皆如此。"]'),
('yuding-27','經鶴台','蘇拯','唐','御定全唐诗','yuding','','[]','築台非謂賢，獨聚乘軒鶴。六馬不能馭，九皋欲何托。',72,'御定全唐詩/json/718.json','["築台非謂賢，獨聚乘軒鶴。六馬不能馭，九皋欲何托。", "一旦敵兵來，萬民同隕濩。如何警露禽，不似銜環雀。", "一物欲誤時，眾類皆成惡。至今台基上，飛鳥不至泊。"]'),
('yuding-28','寄遠','蘇拯','唐','御定全唐诗','yuding','','[]','遊子雖惜別，一去何時見。飛鳥猶戀巢，萬里亦何遠。',48,'御定全唐詩/json/718.json','["遊子雖惜別，一去何時見。飛鳥猶戀巢，萬里亦何遠。", "妾願化為霜，日日下河梁。若能侵鬢色，先染薄情郎。"]'),
('yuding-0','芭蕉','路德延','唐','御定全唐诗','yuding','','[]','一種靈苗異，天然體性虛。葉如斜界紙，心似倒抽書。',24,'御定全唐詩/json/719.json','["一種靈苗異，天然體性虛。葉如斜界紙，心似倒抽書。"]'),
('yuding-1','感舊詩','路德延','唐','御定全唐诗','yuding','','[]','初騎竹馬詠芭蕉，嘗忝名卿誦滿朝。五字便容趨絳帳，',40,'御定全唐詩/json/719.json','["初騎竹馬詠芭蕉，嘗忝名卿誦滿朝。五字便容趨絳帳，", "國境未安身未立，至今顏巷守簞瓢。"]'),
('yuding-2','小兒詩','路德延','唐','御定全唐诗','yuding','','[]','情態任天然，桃紅兩頰鮮。乍行人共看，初語客多憐。',576,'御定全唐詩/json/719.json','["情態任天然，桃紅兩頰鮮。乍行人共看，初語客多憐。", "臂膊肥如瓠，肌膚軟勝綿。長頭才覆額，分角漸垂肩。", "散誕無塵慮，逍遙占地仙。排衙朱閣上，喝道畫堂前。", "合調歌楊柳，齊聲踏採蓮。走堤行細雨，奔巷趁輕煙。", "嫩竹乘為馬，新蒲折作鞭。鶯雛金镟系，貓子彩絲牽。", "擁鶴歸晴島，驅鵝入暖泉。楊花爭弄雪，榆葉共收錢。", "錫鏡當胸掛，銀珠對耳懸。頭依蒼鶻裹，袖學柘枝揎。", "酒殢丹砂暖，茶催小玉煎。頻邀籌箸掙，時乞繡針穿。", "寶篋拏紅豆，妝奩拾翠鈿。戲袍披按褥，劣帽戴靴氈。", "展畫趨三聖，開屏笑七賢。貯懷青杏小，垂額綠荷圓。", "驚滴沾羅淚，嬌流汙錦涎。倦書饒婭姹，憎藥巧遷延。", "弄帳鸞綃映，藏衾鳳綺纏。指敲迎使鼓，筋撥賽神弦。", "簾拂魚鉤動，箏推雁柱偏。棋圖添路畫，笛管欠聲鐫。", "惱客初酣睡，驚僧半入禪。尋蛛窮屋瓦，探雀遍樓椽。", "拋果忙開口，藏鉤亂出拳。夜分圍榾柮，聚朝打秋千。", "折竹裝泥燕，添絲放紙鳶。互誇輪水碓，相教放風旋。", "旗小裁紅絹，書幽截碧箋。遠鋪張鴿網，低控射蠅弦。", "詀語時時道，謠歌處處傳。匿窗眉乍曲，遮路臂相連。", "鬥草當春徑，爭球出晚田。柳傍慵獨坐，花底困橫眠。", "等鵲前籬畔，聽蛩伏砌邊。傍枝粘舞蝶，隈樹捉鳴蟬。", "平島誇趫上，層崖逞捷緣。嫩苔車跡小，深雪履痕全。", "競指雲生岫，齊呼月上天。蟻窠尋徑劚，蜂穴繞階填。", "樵唱回深嶺，牛歌下遠川。壘柴為屋木，和土作盤筵。", "險砌高臺石，危跳峻塔磚。忽升鄰舍樹，偷上後池船。"]'),
('yuding-3','句','路德延','唐','御定全唐诗','yuding','','[]','不是上臺知姓字，五花賓館敢從容。（《上成汭》，',23,'御定全唐詩/json/719.json','["不是上臺知姓字，五花賓館敢從容。（《上成汭》，"]'),
('yuding-4','及第後呈朝中知己','李旭','唐','御定全唐诗','yuding','','[]','淩晨曉鼓奏嘉音，雷擁龍迎出陸沈。金榜高懸當玉闕，',40,'御定全唐詩/json/719.json','["淩晨曉鼓奏嘉音，雷擁龍迎出陸沈。金榜高懸當玉闕，", "今日始知天有意，還教雪得一生心。"]'),
('yuding-5','題惠嚴寺','崔庸','唐','御定全唐诗','yuding','','[]','人莫嫌山小，僧還愛寺靈。殿高神氣力，龍活客丹青。',24,'御定全唐詩/json/719.json','["人莫嫌山小，僧還愛寺靈。殿高神氣力，龍活客丹青。"]'),
('yuding-6','經費拾遺舊隱','胡駢','唐','御定全唐诗','yuding','','[]','林下茅齋已半傾，九華幽徑少人行。不將冠劍為榮事，',40,'御定全唐詩/json/719.json','["林下茅齋已半傾，九華幽徑少人行。不將冠劍為榮事，", "白楊風起秋山暮，時複哀猿啼一聲。"]'),
('yuding-7','失題','周祚','唐','御定全唐诗','yuding','','[]','莫道春花獨照人，秋花未必怯青春。',32,'御定全唐詩/json/719.json','["莫道春花獨照人，秋花未必怯青春。", "四時風雨沒時節，共保松筠根底塵。"]'),
('yuding-8','蛺蝶行','盧頻','唐','御定全唐诗','yuding','','[]','東園宮草綠，上下飛相逐。君恩不禁春，昨夜花中宿。',24,'御定全唐詩/json/719.json','["東園宮草綠，上下飛相逐。君恩不禁春，昨夜花中宿。"]'),
('yuding-9','東西行','盧頻','唐','御定全唐诗','yuding','','[]','種荷玉盆裏，不及溝中水。養雉黃金籠，見草心先喜。',24,'御定全唐詩/json/719.json','["種荷玉盆裏，不及溝中水。養雉黃金籠，見草心先喜。"]'),
('yuding-10','失題','盧頻','唐','御定全唐诗','yuding','','[]','春淚爛羅綺，泣聲抽恨多。莫滴芙蓉池，愁傷連蒂荷。',48,'御定全唐詩/json/719.json','["春淚爛羅綺，泣聲抽恨多。莫滴芙蓉池，愁傷連蒂荷。", "一朵花葉飛，一枝花光彩。美人惜花心，但願春長在。"]'),
('yuding-11','晚泊漢江渡','劉畋','唐','御定全唐诗','yuding','','[]','末秋雲木輕，蓮折晚香清。雨下侵苔色，雲涼出浪聲。',48,'御定全唐詩/json/719.json','["末秋雲木輕，蓮折晚香清。雨下侵苔色，雲涼出浪聲。", "疊帆依岸盡，微照夾堤明。渡吏已頭白，遙知客姓名。"]'),
('yuding-12','句','劉畋','唐','御定全唐诗','yuding','','[]','殘陽來霽岫，獨興起滄洲。',12,'御定全唐詩/json/719.json','["殘陽來霽岫，獨興起滄洲。"]'),
('yuding-0','游洞庭湖','裴說','唐','御定全唐诗','yuding','','[]','楚雲團翠八百里，澧蘭吹香墮春水。白頭漁子搖蒼煙，',64,'御定全唐詩/json/720.json','["楚雲團翠八百里，澧蘭吹香墮春水。白頭漁子搖蒼煙，", "露寒紫藟結新愁，城角泣斷關河秋。謫仙欲識雷斧手，", "瀛洲一棹何時還，滿江宮錦看湖山。"]'),
('yuding-1','懷素台歌','裴說','唐','御定全唐诗','yuding','','[]','我呼古人名，鬼神側耳聽：杜甫李白與懷素，',54,'御定全唐詩/json/720.json','["我呼古人名，鬼神側耳聽：杜甫李白與懷素，", "筆塚低低高如山，墨池淺淺深如海。我來恨不已，", "枯樹槎。烏梢蛇，墨老鴉。"]'),
('yuding-2','聞砧','裴說','唐','御定全唐诗','yuding','','[]','深閨乍冷鑒開篋，玉箸微微濕紅頰。一陣霜風殺柳條，',88,'御定全唐詩/json/720.json','["深閨乍冷鑒開篋，玉箸微微濕紅頰。一陣霜風殺柳條，", "只知抱杵搗秋砧，不覺高樓已無月。時聞寒雁聲相喚，", "細想儀形執牙尺，回刀剪破澄江色。愁撚銀針信手縫，", "書中不盡心中事，一片殷勤寄邊使。"]'),
('yuding-3','春早寄華下同人','裴說','唐','御定全唐诗','yuding','','[]','正是花時節，思君寢復興。市沽終不醉，春夢亦無憑。',48,'御定全唐詩/json/720.json','["正是花時節，思君寢復興。市沽終不醉，春夢亦無憑。", "嶽面懸青雨，河心走濁冰。東門一條路，離恨鎮相仍。"]'),
('yuding-4','贈衡山令','裴說','唐','御定全唐诗','yuding','','[]','君吟十二載，辛苦必能官。造化猶難隱，生靈豈易謾。',48,'御定全唐詩/json/720.json','["君吟十二載，辛苦必能官。造化猶難隱，生靈豈易謾。", "猿跳高嶽靜，魚擺大江寬。與我為同道，相留夜話闌。"]'),
('yuding-5','南中縣令','裴說','唐','御定全唐诗','yuding','','[]','寂寥雖下邑，良宰有清威。苦節長如病，為官豈肯肥。',48,'御定全唐詩/json/720.json','["寂寥雖下邑，良宰有清威。苦節長如病，為官豈肯肥。", "山多村地狹，水淺客舟稀。上國搜賢急，陶公早晚歸。"]'),
('yuding-6','寄曹松','裴說','唐','御定全唐诗','yuding','','[]','莫怪苦吟遲，詩成鬢亦絲。鬢絲猶可染，詩病卻難醫。',48,'御定全唐詩/json/720.json','["莫怪苦吟遲，詩成鬢亦絲。鬢絲猶可染，詩病卻難醫。", "山暝雲橫處，星沈月側時。冥搜不可得，一句至公知。"]'),
('yuding-7','贈賓貢','裴說','唐','御定全唐诗','yuding','','[]','惟君懷至業，萬里信悠悠。路向東溟出，枝來北闕求。',48,'御定全唐詩/json/720.json','["惟君懷至業，萬里信悠悠。路向東溟出，枝來北闕求。", "家無一夜夢，帆掛來年秋。鬢髮爭禁得，孤舟往復愁。"]'),
('yuding-8','漢南郵亭','裴說','唐','御定全唐诗','yuding','','[]','高閣水風清，開門日送迎。帆張獨鳥起，樂奏大魚驚。',48,'御定全唐詩/json/720.json','["高閣水風清，開門日送迎。帆張獨鳥起，樂奏大魚驚。", "驟雨拖山過，微風拂面生。閑吟雖得句，留此謝多情。"]'),
('yuding-9','棋','裴說','唐','御定全唐诗','yuding','','[]','十九條平路，言平又嶮巇。人心無算處，國手有輸時。',48,'御定全唐詩/json/720.json','["十九條平路，言平又嶮巇。人心無算處，國手有輸時。", "勢迥流星遠，聲幹下雹遲。臨軒才一局，寒日又西垂。"]'),
('yuding-10','夏日即事','裴說','唐','御定全唐诗','yuding','','[]','僻居門巷靜，竟日坐階墀。鵲喜雖傳信，蛩吟不見詩。',48,'御定全唐詩/json/720.json','["僻居門巷靜，竟日坐階墀。鵲喜雖傳信，蛩吟不見詩。", "筍抽通舊竹，梅落立閑枝。此際無塵撓，僧來稱所宜。"]'),
('yuding-11','送人宰邑','裴說','唐','御定全唐诗','yuding','','[]','官小任還重，命官難偶然。皇恩輕一邑，赤子病三年。',48,'御定全唐詩/json/720.json','["官小任還重，命官難偶然。皇恩輕一邑，赤子病三年。", "瘦馬稀餐粟，羸童不識錢。如君清苦節，到處有人傳。"]'),
('yuding-12','春暖送人下第','裴說','唐','御定全唐诗','yuding','','[]','相送短亭前，知君愚複賢。事多憑夜夢，老為待明年。',48,'御定全唐詩/json/720.json','["相送短亭前，知君愚複賢。事多憑夜夢，老為待明年。", "春樹添山脊，晴雲學曉煙。雄文有公道，此別莫潸然。"]'),
('yuding-13','湖外送何崇入閣','裴說','唐','御定全唐诗','yuding','','[]','因詩相識久，忽此告臨途。便是有船發，也須容市沽。',48,'御定全唐詩/json/720.json','["因詩相識久，忽此告臨途。便是有船發，也須容市沽。", "精吟五個字，穩泛兩重湖。長短逢公道，清名振帝都。"]'),
('yuding-14','送進士蘇瞻亂後出家','裴說','唐','御定全唐诗','yuding','','[]','因亂事空王，孤心亦不傷。梵僧為骨肉，柏寺作家鄉。',48,'御定全唐詩/json/720.json','["因亂事空王，孤心亦不傷。梵僧為骨肉，柏寺作家鄉。", "眼閉千行淚，頭梳一把霜。詩書不得力，誰與問蒼蒼。"]'),
('yuding-15','秋日送河北從事','裴說','唐','御定全唐诗','yuding','','[]','北風沙漠地，吾子遠從軍。官路雖非遠，詩名要且聞。',48,'御定全唐詩/json/720.json','["北風沙漠地，吾子遠從軍。官路雖非遠，詩名要且聞。", "蟬悲欲落日，雕下擬陰雲。此去難相戀，前山摻袂分。"]'),
('yuding-16','喜友人再面','裴說','唐','御定全唐诗','yuding','','[]','一別幾寒暄，迢迢隔塞垣。相思長有事，及見卻無言。',48,'御定全唐詩/json/720.json','["一別幾寒暄，迢迢隔塞垣。相思長有事，及見卻無言。", "靜坐將茶試，閒書把葉翻。依依又留宿，圓月上東軒。"]'),
('yuding-17','對雪','裴說','唐','御定全唐诗','yuding','','[]','大片向空舞，出門肌骨寒。路岐平即易，溝壑滿應難。',48,'御定全唐詩/json/720.json','["大片向空舞，出門肌骨寒。路岐平即易，溝壑滿應難。", "兔穴歸時失，禽枝宿處幹。豪家寧肯厭，五月畫圖看。"]'),
('yuding-18','冬日後作','裴說','唐','御定全唐诗','yuding','','[]','寂寞掩荊扉，昏昏坐欲癡。事無前定處，愁有並來時。',48,'御定全唐詩/json/720.json','["寂寞掩荊扉，昏昏坐欲癡。事無前定處，愁有並來時。", "日影才添線，鬢根已半絲。明庭正公道，應許苦心詩。"]'),
('yuding-19','冬日作','裴說','唐','御定全唐诗','yuding','','[]','糲食擁敗絮，苦吟吟過冬。稍寒人卻健，太飽事多慵。',48,'御定全唐詩/json/720.json','["糲食擁敗絮，苦吟吟過冬。稍寒人卻健，太飽事多慵。", "樹老生煙薄，牆陰貯雪重。安能只如此，公道會相容。"]'),
('yuding-20','中秋月','裴說','唐','御定全唐诗','yuding','','[]','一歲幾盈虧，當軒重此期。幸無偏照處，剛有不明時。',48,'御定全唐詩/json/720.json','["一歲幾盈虧，當軒重此期。幸無偏照處，剛有不明時。", "色靜雲歸早，光寒鶴睡遲。相看吟未足，皎皎下疏籬。"]'),
('yuding-21','塞上曲','裴說','唐','御定全唐诗','yuding','','[]','極目望空闊，馬羸程又賒。月生方見樹，風定始無沙。',48,'御定全唐詩/json/720.json','["極目望空闊，馬羸程又賒。月生方見樹，風定始無沙。", "楚水辭魚窟，燕山到雁家。如斯名利役，爭不老天涯。"]'),
('yuding-22','終南山','裴說','唐','御定全唐诗','yuding','','[]','九衢南面色，蒼翠絕纖塵。寸步有閑處，百年無到人。',48,'御定全唐詩/json/720.json','["九衢南面色，蒼翠絕纖塵。寸步有閑處，百年無到人。", "禁林寒對望，太華淨相鄰。誰與群峰並，祥雲瑞露頻。"]'),
('yuding-23','訪道士','裴說','唐','御定全唐诗','yuding','','[]','高岡微雨後，木脫草堂新。惟有疏慵者，來看淡薄人。',48,'御定全唐詩/json/720.json','["高岡微雨後，木脫草堂新。惟有疏慵者，來看淡薄人。", "竹牙生礙路，松子落敲巾。粗得玄中趣，當期宿話頻。"]'),
('yuding-24','道林寺','裴說','唐','御定全唐诗','yuding','','[]','獨立憑危闌，高低落照間。寺分一派水，僧鎖半房山。',48,'御定全唐詩/json/720.json','["獨立憑危闌，高低落照間。寺分一派水，僧鎖半房山。", "對面浮世隔，垂簾到老閑。煙雲與塵土，寸步不相關。"]'),
('yuding-25','般若寺','裴說','唐','御定全唐诗','yuding','','[]','南嶽古般若，自來天下知。翠籠無價寺，光射有名詩。',48,'御定全唐詩/json/720.json','["南嶽古般若，自來天下知。翠籠無價寺，光射有名詩。", "一水湧獸跡，五峰排鳳儀。高僧引閒步，晝出夕陽歸。"]'),
('yuding-26','兜率寺','裴說','唐','御定全唐诗','yuding','','[]','一片無塵地，高連夢澤南。僧居跨鳥道，佛影照魚潭。',48,'御定全唐詩/json/720.json','["一片無塵地，高連夢澤南。僧居跨鳥道，佛影照魚潭。", "朽枿雲斜映，平蕪日半涵。行行不得住，回首望煙嵐。"]'),
('yuding-27','鹿門寺','裴說','唐','御定全唐诗','yuding','','[]','鹿門山上寺，突兀盡無塵。到此修行者，應非取次人。',48,'御定全唐詩/json/720.json','["鹿門山上寺，突兀盡無塵。到此修行者，應非取次人。", "鳥過驚石磬，日出礙金身。何計生煩惱，虛空是四鄰。"]'),
('yuding-28','題嶽州僧舍','裴說','唐','御定全唐诗','yuding','','[]','喜到重湖北，孤州橫晚煙。鷺銜魚入寺，鴉接飯隨船。',48,'御定全唐詩/json/720.json','["喜到重湖北，孤州橫晚煙。鷺銜魚入寺，鴉接飯隨船。", "松檜君山迥，菰蒲夢澤連。與師吟論處，秋水浸遙天。"]'),
('yuding-29','過洞庭湖','裴說','唐','御定全唐诗','yuding','','[]','浪高風力大，掛席亦言遲。及到堪憂處，爭如未濟時。',48,'御定全唐詩/json/720.json','["浪高風力大，掛席亦言遲。及到堪憂處，爭如未濟時。", "魚龍侵莫測，雷雨動須疑。此際情無賴，何門寄所思。"]'),
('yuding-30','旅行聞寇','裴說','唐','御定全唐诗','yuding','','[]','動步憂多事，將行問四鄰。深山不畏虎，當路卻防人。',48,'御定全唐詩/json/720.json','["動步憂多事，將行問四鄰。深山不畏虎，當路卻防人。", "豪富田園廢，疲羸屋舍新。自慚為旅客，無計避煙塵。"]'),
('yuding-31','旅中作','裴說','唐','御定全唐诗','yuding','','[]','妄動遠拋山，其如餒與寒。投人言去易，開口說貧難。',48,'御定全唐詩/json/720.json','["妄動遠拋山，其如餒與寒。投人言去易，開口說貧難。", "澤國雲千片，湘江竹一竿。時明未忍別，猶待計窮看。"]'),
('yuding-32','旅次衡陽','裴說','唐','御定全唐诗','yuding','','[]','欲往幾經年，今來意豁然。江風長借客，嶽雨不因天。',48,'御定全唐詩/json/720.json','["欲往幾經年，今來意豁然。江風長借客，嶽雨不因天。", "戲鷺飛輕雪，驚鴻叫亂煙。晚秋紅藕裏，十宿寄漁船。"]'),
('yuding-33','不出院僧','裴說','唐','御定全唐诗','yuding','','[]','四遠參尋遍，修行卻不行。耳邊無俗語，門外是前生。',48,'御定全唐詩/json/720.json','["四遠參尋遍，修行卻不行。耳邊無俗語，門外是前生。", "塔見移來影，鐘聞過去聲。一齋唯默坐，應笑我營營。"]'),
('yuding-34','湖外寄處賓上人','裴說','唐','御定全唐诗','yuding','','[]','怪得意相親，高攜一軸新。能搜大雅句，不似小乘人。',48,'御定全唐詩/json/720.json','["怪得意相親，高攜一軸新。能搜大雅句，不似小乘人。", "嶽麓擎枯檜，瀟湘吐白蘋。他年遇同道，為我話風塵。"]'),
('yuding-35','寄貫休','裴說','唐','御定全唐诗','yuding','','[]','憶昔與吾師，山中靜論時。總無方是法，難得始為詩。',48,'御定全唐詩/json/720.json','["憶昔與吾師，山中靜論時。總無方是法，難得始為詩。", "凍犬眠幹葉，饑禽啄病梨。他年白蓮社，猶許重相期。"]'),
('yuding-36','寄僧尚顏','裴說','唐','御定全唐诗','yuding','','[]','曾居五老峰，所得共誰同。才大天全與，吟精楚欲空。',48,'御定全唐詩/json/720.json','["曾居五老峰，所得共誰同。才大天全與，吟精楚欲空。", "客來庭減日，鳥過竹生風。早晚搖輕拂，重歸瀑布中。"]'),
('yuding-37','哭處默上人','裴說','唐','御定全唐诗','yuding','','[]','淒涼繐幕下，香吐一燈分。鬥老輸寒檜，留閑與白雲。',48,'御定全唐詩/json/720.json','["淒涼繐幕下，香吐一燈分。鬥老輸寒檜，留閑與白雲。", "挈盂曾幾度，傳衲不教焚。泣罷重回首，暮山鐘半聞。"]'),
('yuding-38','廬山瀑布','裴說','唐','御定全唐诗','yuding','','[]','靜景憑高望，光分翠嶂開。嶮飛千尺雪，寒撲一聲雷。',48,'御定全唐詩/json/720.json','["靜景憑高望，光分翠嶂開。嶮飛千尺雪，寒撲一聲雷。", "過去雲沖斷，旁來燒隔回。何當住峰下，終歲絕塵埃。"]'),
('yuding-39','華山上方','裴說','唐','御定全唐诗','yuding','','[]','獨上上方上，立高聊稱心。氣沖雲易黑，影落縣多陰。',48,'御定全唐詩/json/720.json','["獨上上方上，立高聊稱心。氣沖雲易黑，影落縣多陰。", "有雲草不死，無風松自吟。會當求大藥，他日複追尋。"]'),
('yuding-40','詠鸚鵡','裴說','唐','御定全唐诗','yuding','','[]','常貴西山鳥，銜恩在玉堂。語傳明主意，衣拂美人香。',48,'御定全唐詩/json/720.json','["常貴西山鳥，銜恩在玉堂。語傳明主意，衣拂美人香。", "緩步尋珠網，高飛上畫梁。長安頻道樂，何日從君王。"]'),
('yuding-41','鷺鷥','裴說','唐','御定全唐诗','yuding','','[]','秋江清淺時，魚過亦頻窺。卻為分明極，翻成所得遲。',48,'御定全唐詩/json/720.json','["秋江清淺時，魚過亦頻窺。卻為分明極，翻成所得遲。", "浴偎紅日色，棲壓碧蘆枝。會共鵷同侶，翱翔應可期。"]'),
('yuding-42','牡丹','裴說','唐','御定全唐诗','yuding','','[]','數朵欲傾城，安同桃李榮。未嘗貧處見，不似地中生。',48,'御定全唐詩/json/720.json','["數朵欲傾城，安同桃李榮。未嘗貧處見，不似地中生。", "此物疑無價，當春獨有名。遊蜂與蝴蝶，來往自多情。"]'),
('yuding-43','見王貞白','裴說','唐','御定全唐诗','yuding','','[]','共賀登科後，明宣入紫宸。又看重試榜，還見苦吟人。',48,'御定全唐詩/json/720.json','["共賀登科後，明宣入紫宸。又看重試榜，還見苦吟人。", "此得名渾別，歸來話亦新。分明一枝桂，堪動楚江濱。"]'),
('yuding-44','經杜工部墳','裴說','唐','御定全唐诗','yuding','','[]','騷人久不出，安得國風清。擬掘孤墳破，重教大雅生。',48,'御定全唐詩/json/720.json','["騷人久不出，安得國風清。擬掘孤墳破，重教大雅生。", "皇天高莫問，白酒恨難平。悒怏寒江上，誰人知此情。"]'),
('yuding-45','寄僧知幹','裴說','唐','御定全唐诗','yuding','','[]','貌高清入骨，帝裏舊臨壇。出語經相似，行心佛證安。',24,'御定全唐詩/json/720.json','["貌高清入骨，帝裏舊臨壇。出語經相似，行心佛證安。"]'),
('yuding-46','亂中偷路入故鄉','裴說','唐','御定全唐诗','yuding','','[]','愁看賊火起諸烽，偷得餘程悵望中。',32,'御定全唐詩/json/720.json','["愁看賊火起諸烽，偷得餘程悵望中。", "一國半為亡國燼，數城俱作古城空。"]'),
('yuding-47','薔薇','裴說','唐','御定全唐诗','yuding','','[]','一架長條萬朵春，嫩紅深綠小窠勻。',32,'御定全唐詩/json/720.json','["一架長條萬朵春，嫩紅深綠小窠勻。", "只應根下千年土，曾葬西川織錦人。"]'),
('yuding-48','春日山中竹','裴說','唐','御定全唐诗','yuding','','[]','數竿蒼翠擬龍形，峭拔須教此地生。',32,'御定全唐詩/json/720.json','["數竿蒼翠擬龍形，峭拔須教此地生。", "無限野花開不得，半山寒色與春爭。"]'),
('yuding-49','柳','裴說','唐','御定全唐诗','yuding','','[]','高拂危樓低拂塵，灞橋攀折一何頻。',32,'御定全唐詩/json/720.json','["高拂危樓低拂塵，灞橋攀折一何頻。", "思量卻是無情樹，不解迎人只送人。"]'),
('yuding-50','岳陽兵火後題僧舍','裴說','唐','御定全唐诗','yuding','','[]','十年兵火真多事，再到禪扉卻破顏。',32,'御定全唐詩/json/720.json','["十年兵火真多事，再到禪扉卻破顏。", "唯有兩般燒不得，洞庭湖水老僧閑。"]'),
('yuding-51','句','裴說','唐','御定全唐诗','yuding','','[]','讀書貧裏樂，搜句靜中忙。',134,'御定全唐詩/json/720.json','["讀書貧裏樂，搜句靜中忙。", "苦吟僧入定，得句將成功。", "是事精皆易，唯詩會卻難。", "因攜一家住，贏得半年吟。", "吟餘潮入浦，坐久燒移山。", "三年清似水，六月冷如冰。", "一通紅錦重，三事紫羅輕。", "瘦肌寒帶粟，病眼餒生花。", "避亂一生多。", "雪留寒竹寺舍冷，風撼早梅城郭香。", "畫球輕蹴壺中地，彩索高飛掌上身。"]'),
('yuding-0','贈唐山人','李洞','唐','御定全唐诗','yuding','','[]','垂須長似發，七十色如黳。醉眼青天小，吟情太華低。',48,'御定全唐詩/json/721.json','["垂須長似發，七十色如黳。醉眼青天小，吟情太華低。", "千年松繞屋，半夜雨連溪。邛蜀路無限，往來琴獨攜。"]'),
('yuding-1','送雲卿上人游安南','李洞','唐','御定全唐诗','yuding','','[]','春往海南邊，秋聞半夜蟬。鯨吞洗缽水，犀觸點燈船。',48,'御定全唐詩/json/721.json','["春往海南邊，秋聞半夜蟬。鯨吞洗缽水，犀觸點燈船。", "島嶼分諸國，星河共一天。長安卻回日，松偃舊房前。"]'),
('yuding-2','鄭補闕山居','李洞','唐','御定全唐诗','yuding','','[]','高節諫垣客，白雲居靜坊。馬饑餐落葉，鶴病曬殘陽。',48,'御定全唐詩/json/721.json','["高節諫垣客，白雲居靜坊。馬饑餐落葉，鶴病曬殘陽。", "野霧昏朝燭，溪箋惹禦香。相招倚蒲壁，論句夜何長。"]'),
('yuding-3','送曹郎中南歸，時南中用軍','李洞','唐','御定全唐诗','yuding','','[]','桂水淨和天，南歸似謫仙。系絛輕象笏，買布接蠻船。',48,'御定全唐詩/json/721.json','["桂水淨和天，南歸似謫仙。系絛輕象笏，買布接蠻船。", "海氣蒸鼙軟，江風激箭偏。罷郎吟亂裏，帝遠豈知賢。"]'),
('yuding-4','錦江陪兵部鄭侍郎話詩著棋','李洞','唐','御定全唐诗','yuding','','[]','落葉濺吟身，會棋雲外人。海枯搜不盡，天定著長新。',48,'御定全唐詩/json/721.json','["落葉濺吟身，會棋雲外人。海枯搜不盡，天定著長新。", "月上分題遍，鐘殘布子勻。忘餐二絕境，取意鑄陶鈞。"]'),
('yuding-5','中秋月','李洞','唐','御定全唐诗','yuding','','[]','四十五秋宵，月分千里毫。冷沉中嶽短，光溢太行高。',48,'御定全唐詩/json/721.json','["四十五秋宵，月分千里毫。冷沉中嶽短，光溢太行高。", "不寐清人眼，移棲濕鶴毛。露華臺上別，吟望十年勞。"]'),
('yuding-6','送沈光赴福幕','李洞','唐','御定全唐诗','yuding','','[]','泉齊嶺鳥飛，雨熟荔枝肥。南斗看應近，北人來恐稀。',48,'御定全唐詩/json/721.json','["泉齊嶺鳥飛，雨熟荔枝肥。南斗看應近，北人來恐稀。", "潮浮廉使宴，珠照島僧歸。幕下逢遷拜，何官著茜衣。"]'),
('yuding-7','鄠郊山舍題趙處士林亭','李洞','唐','御定全唐诗','yuding','','[]','圭峰秋後疊，亂葉落寒墟。四五百竿竹，二三千卷書。',48,'御定全唐詩/json/721.json','["圭峰秋後疊，亂葉落寒墟。四五百竿竹，二三千卷書。", "雲深猿拾栗，雨霽蟻緣蔬。只隔門前水，如同萬里餘。"]'),
('yuding-8','賦得送賈島謫長江','李洞','唐','御定全唐诗','yuding','','[]','敲驢吟雪月，謫出國西門。行傍長江影，愁深汨水魂。',48,'御定全唐詩/json/721.json','["敲驢吟雪月，謫出國西門。行傍長江影，愁深汨水魂。", "筇攜過竹寺，琴典在花村。饑拾山松子，誰知賈傅孫。"]'),
('yuding-9','河陽道中','李洞','唐','御定全唐诗','yuding','','[]','沖風仍躡凍，提轡手頻呵。得事應須早，愁人不在多。',48,'御定全唐詩/json/721.json','["沖風仍躡凍，提轡手頻呵。得事應須早，愁人不在多。", "雪田平入塞，煙郭曲隨河。翻憶江濤裏，船中睡蓋蓑。"]'),
('yuding-10','送知己赴濮州','李洞','唐','御定全唐诗','yuding','','[]','中路行僧謁，郵亭話海濤。劍搖林狖落，旗閃岳禽高。',48,'御定全唐詩/json/721.json','["中路行僧謁，郵亭話海濤。劍搖林狖落，旗閃岳禽高。", "苔長空州獄，花開夢省曹。濮陽流政化，一半布風騷。"]'),
('yuding-11','送行腳僧','李洞','唐','御定全唐诗','yuding','','[]','瓶枕繞腰垂，出門何所之。毳衣沾雨重，棕笠看山欹。',48,'御定全唐詩/json/721.json','["瓶枕繞腰垂，出門何所之。毳衣沾雨重，棕笠看山欹。", "夜觀入枯樹，野眠逢斷碑。鄰房母淚下，相課別離詞。"]'),
('yuding-12','龍州送人赴舉','李洞','唐','御定全唐诗','yuding','','[]','獻策赴招攜，行宮積翠西。挈囊秋卷重，轉棧晚峰齊。',48,'御定全唐詩/json/721.json','["獻策赴招攜，行宮積翠西。挈囊秋卷重，轉棧晚峰齊。", "踏月趨金闕，拂雲看禦題。飛鳴豈回顧，獨鶴困江泥。"]'),
('yuding-13','送安撫從兄夷偶中丞','李洞','唐','御定全唐诗','yuding','','[]','奉詔向軍前，朱袍映雪鮮。河橋吹角凍，嶽月卷旗圓。',48,'御定全唐詩/json/721.json','["奉詔向軍前，朱袍映雪鮮。河橋吹角凍，嶽月卷旗圓。", "僧救焚經火，人修著釣船。六州安撫後，萬戶解衣眠。"]'),
('yuding-14','送遠上人','李洞','唐','御定全唐诗','yuding','','[]','海嶽兩無邊，去來都偶然。齒因吟後冷，心向靜中圓。',48,'御定全唐詩/json/721.json','["海嶽兩無邊，去來都偶然。齒因吟後冷，心向靜中圓。", "蟲網花間井，鴻鳴雨後天。葉書歸舊寺，應附載鐘船。"]'),
('yuding-15','宿鳳翔天柱寺窮易玄上人房','李洞','唐','御定全唐诗','yuding','','[]','天柱暮相逢，吟思天柱峰。墨研青露月，茶吸白雲鐘。',48,'御定全唐詩/json/721.json','["天柱暮相逢，吟思天柱峰。墨研青露月，茶吸白雲鐘。", "臥語身粘蘚，行禪頂拂松。探玄為一決，明日去臨邛。"]'),
('yuding-16','下第送張霞歸覲江南','李洞','唐','御定全唐诗','yuding','','[]','此道背于時，攜歸一軸詩。樹沈孤鳥遠，風逆蹇驢遲。',48,'御定全唐詩/json/721.json','["此道背于時，攜歸一軸詩。樹沈孤鳥遠，風逆蹇驢遲。", "草入吟房壞，潮沖釣石移。恐傷歡覲意，半路摘愁髭。"]'),
('yuding-17','送人之天臺','李洞','唐','御定全唐诗','yuding','','[]','行李一枝藤，雲邊曉扣冰。丹經如不謬，白髮亦何能。',48,'御定全唐詩/json/721.json','["行李一枝藤，雲邊曉扣冰。丹經如不謬，白髮亦何能。", "淺井仙人境，明珠海客燈。乃知真隱者，笑就漢廷征。"]'),
('yuding-18','維摩暢林居','李洞','唐','御定全唐诗','yuding','','[]','諸方遊幾臘，五夏五峰銷。越講迎騎象，蕃齋懺射雕。',48,'御定全唐詩/json/721.json','["諸方遊幾臘，五夏五峰銷。越講迎騎象，蕃齋懺射雕。", "冷筇和雪倚，朽櫟帶雲燒。從此西林老，瞥然三萬朝。"]'),
('yuding-19','送張喬下第歸宣州','李洞','唐','御定全唐诗','yuding','','[]','詩道世難通，歸甯楚浪中。早程殘嶽月，夜泊隔淮鐘。',48,'御定全唐詩/json/721.json','["詩道世難通，歸甯楚浪中。早程殘嶽月，夜泊隔淮鐘。", "一鏡隨雙鬢，全家老半峰。無成來往過，折盡謝亭松。"]'),
('yuding-20','送盧郎中赴金州','李洞','唐','御定全唐诗','yuding','','[]','雲明天嶺高，刺郡輟仙曹。危棧窺猿頂，公庭掃鶴毛。',48,'御定全唐詩/json/721.json','["雲明天嶺高，刺郡輟仙曹。危棧窺猿頂，公庭掃鶴毛。", "出軍青壁罅，話道白眉毫。遠集歌謠客，州前泊幾艘。"]'),
('yuding-21','江幹即事','李洞','唐','御定全唐诗','yuding','','[]','病臥四更後，愁聞報早衙。隔關沈水鳥，侵郭噪園鴉。',48,'御定全唐詩/json/721.json','["病臥四更後，愁聞報早衙。隔關沈水鳥，侵郭噪園鴉。", "吏瘦餐溪柏，身羸憑海槎。滿朝吟五字，應不老煙霞。"]'),
('yuding-22','寄賀鄭常侍','李洞','唐','御定全唐诗','yuding','','[]','山亦懷恩地，高禽盡下飛。吏穿霞片望，僧掃月棱歸。',48,'御定全唐詩/json/721.json','["山亦懷恩地，高禽盡下飛。吏穿霞片望，僧掃月棱歸。", "省拜墀煙近，林居玉漏微。曾令駐錫話，聊用慰攀依。"]'),
('yuding-23','登樓','李洞','唐','御定全唐诗','yuding','','[]','川上值樓開，寒山四面來。竹吹人語遠，峰礙鳥飛回。',48,'御定全唐詩/json/721.json','["川上值樓開，寒山四面來。竹吹人語遠，峰礙鳥飛回。", "生死別離陌，朝昏雲雨堆。誰知獨立意，濺淚落莓苔。"]'),
('yuding-24','贈禪友','李洞','唐','御定全唐诗','yuding','','[]','散花留內殿，宮女夢談禪。樹杪開樓鎖，雲中認嶽蓮。',48,'御定全唐詩/json/721.json','["散花留內殿，宮女夢談禪。樹杪開樓鎖，雲中認嶽蓮。", "溪聲過長耳，筇節出羸肩。飛句相招宿，多逢有月天。"]'),
('yuding-25','早春友人訪別南歸','李洞','唐','御定全唐诗','yuding','','[]','南歸來取別，窮巷坐青苔。一盞薄醨酒，數枝零落梅。',48,'御定全唐詩/json/721.json','["南歸來取別，窮巷坐青苔。一盞薄醨酒，數枝零落梅。", "潮生楚驛閉，星在越樓開。明日望君處，前臨風月台。"]'),
('yuding-26','題雲際寺','李洞','唐','御定全唐诗','yuding','','[]','開門風雪頂，上徹困飛禽。猿戲青冥裏，人行紫閣陰。',48,'御定全唐詩/json/721.json','["開門風雪頂，上徹困飛禽。猿戲青冥裏，人行紫閣陰。", "臘泉冰下出，夜磬月中尋。盡欲居岩室，如何不住心。"]'),
('yuding-27','山寺老僧','李洞','唐','御定全唐诗','yuding','','[]','雲際眾僧裏，獨攢眉似愁。護茶高夏臘，愛火老春秋。',48,'御定全唐詩/json/721.json','["雲際眾僧裏，獨攢眉似愁。護茶高夏臘，愛火老春秋。", "海浪南曾病，河冰北苦遊。歸來諸弟子，白遍後生頭。"]'),
('yuding-28','同僧宿道者院','李洞','唐','御定全唐诗','yuding','','[]','攜文過水宿，拂席四廊塵。墜果敲樓瓦，高螢映鶴身。',48,'御定全唐詩/json/721.json','["攜文過水宿，拂席四廊塵。墜果敲樓瓦，高螢映鶴身。", "點燈吹葉火，談佛悟山人。盡有棲霞志，好謀三教鄰。"]'),
('yuding-29','古柏','李洞','唐','御定全唐诗','yuding','','[]','手植知何代，年齊偃蓋松。結根生別樹，吹子落鄰峰。',48,'御定全唐詩/json/721.json','["手植知何代，年齊偃蓋松。結根生別樹，吹子落鄰峰。", "古幹經龍嗅，高煙過雁沖。可佳繁葉盡，聲不礙秋鐘。"]'),
('yuding-30','贈王鳳二山人','李洞','唐','御定全唐诗','yuding','','[]','山兄望鶴信，山弟聽烏占。養藥同開鼎，休棋各枕奩。',48,'御定全唐詩/json/721.json','["山兄望鶴信，山弟聽烏占。養藥同開鼎，休棋各枕奩。", "相逢九江底，共到五峰尖。願許為三友，羞將白髮撏。"]'),
('yuding-31','避地冬夜與二三禪侶吟集茅齋','李洞','唐','御定全唐诗','yuding','','[]','四海通禪客，搜吟會草亭。撚髭孤燭白，閉目眾山青。',48,'御定全唐詩/json/721.json','["四海通禪客，搜吟會草亭。撚髭孤燭白，閉目眾山青。", "松掛敲冰杖，壚溫注月瓶。獨愁懸舊旆，笏冷立殘星。"]'),
('yuding-32','贈道微禪師','李洞','唐','御定全唐诗','yuding','','[]','銅瓶澀瀉水，出磧躡蓮層。猛虎降低鼠，盤雕望小蠅。',48,'御定全唐詩/json/721.json','["銅瓶澀瀉水，出磧躡蓮層。猛虎降低鼠，盤雕望小蠅。", "通禪五天日，照祖幾朝燈。短髮歸林白，何妨剃未能。"]'),
('yuding-33','吊草堂禪師','李洞','唐','御定全唐诗','yuding','','[]','杖屨疑師在，房關四壁蛩。貯瓶經臘水，響塔隔山鐘。',48,'御定全唐詩/json/721.json','["杖屨疑師在，房關四壁蛩。貯瓶經臘水，響塔隔山鐘。", "乳鴿沿苔井，齋猿散雪峰。如何不見性，倚遍寺前松。"]'),
('yuding-34','宿長安蘇雍主簿廳','李洞','唐','御定全唐诗','yuding','','[]','縣對數峰雲，官清主簿貧。聽更池上鶴，伴值岳陽人。',48,'御定全唐詩/json/721.json','["縣對數峰雲，官清主簿貧。聽更池上鶴，伴值岳陽人。", "井鎖煎茶水，廳關搗藥塵。往來多屣步，同舍即諸鄰。"]'),
('yuding-35','秋宿潤州劉處士江亭','李洞','唐','御定全唐诗','yuding','','[]','北夢風吹斷，江邊處士亭。吟生萬井月，見盡一天星。',48,'御定全唐詩/json/721.json','["北夢風吹斷，江邊處士亭。吟生萬井月，見盡一天星。", "浪靜魚沖鎖，窗高鶴聽經。東西渺無際，世界半滄溟。"]'),
('yuding-36','秋日曲江書事','李洞','唐','御定全唐诗','yuding','','[]','門搖枯葦影，落日共鷗歸。園近鹿來熟，江寒人到稀。',48,'御定全唐詩/json/721.json','["門搖枯葦影，落日共鷗歸。園近鹿來熟，江寒人到稀。", "片雲穿塔過，枯葉入城飛。翻怕賓鴻至，無才動禮闈。"]'),
('yuding-37','秋宿經上人房','李洞','唐','御定全唐诗','yuding','','[]','江房無葉落，松影帶山高。滿寺中秋月，孤窗入夜濤。',48,'御定全唐詩/json/721.json','["江房無葉落，松影帶山高。滿寺中秋月，孤窗入夜濤。", "舊真懸石壁，衰發落銅刀。臥聽曉耕者，與師知苦勞。"]'),
('yuding-38','冬日題覺公牛頭蘭若','李洞','唐','御定全唐诗','yuding','','[]','天寒高木靜，一磬隔川聞。鼎水看山汲，台香掃雪焚。',48,'御定全唐詩/json/721.json','["天寒高木靜，一磬隔川聞。鼎水看山汲，台香掃雪焚。", "鶴歸惟認刹，僧步不離雲。石室開禪後，輪珠謝聖君。"]'),
('yuding-39','送皇甫校書自蜀下峽，歸覲襄陽','李洞','唐','御定全唐诗','yuding','','[]','蜀道波不竭，巢烏出浪痕。松陰蓋巫峽，雨色徹荊門。',48,'御定全唐詩/json/721.json','["蜀道波不竭，巢烏出浪痕。松陰蓋巫峽，雨色徹荊門。", "宿寺青山盡，歸林彩服翻。苦吟懷凍餒，為吊浩然魂。"]'),
('yuding-40','題西明寺攻文僧林複上人房','李洞','唐','御定全唐诗','yuding','','[]','誰寄湘南信，陰窗硯起津。燒痕碑入集，海角寺留真。',48,'御定全唐詩/json/721.json','["誰寄湘南信，陰窗硯起津。燒痕碑入集，海角寺留真。", "樓憩長空鳥，鐘驚半闕人。禦溝圓月會，似在草堂身。"]'),
('yuding-41','寄翠微無可上人','李洞','唐','御定全唐诗','yuding','','[]','遠近眾心歸，居然占翠微。展經猿識字，聽法虎知非。',48,'御定全唐詩/json/721.json','["遠近眾心歸，居然占翠微。展經猿識字，聽法虎知非。", "泉注城池夢，霞生侍衛衣。玄機不可學，何似總無機。"]'),
('yuding-42','喜鸞公自蜀歸','李洞','唐','御定全唐诗','yuding','','[]','禁院對生台，尋師到綠槐。寺高猿看講，鐘動鳥知齋。',48,'御定全唐詩/json/721.json','["禁院對生台，尋師到綠槐。寺高猿看講，鐘動鳥知齋。", "掃石月盈帚，濾泉花滿篩。歸來逢聖節，吟步上堯階。"]'),
('yuding-43','題新安國寺','李洞','唐','御定全唐诗','yuding','','[]','佛亦遇艱難，重興疊廢壇。偃松枝舊折，畫竹粉新幹。',48,'御定全唐詩/json/721.json','["佛亦遇艱難，重興疊廢壇。偃松枝舊折，畫竹粉新幹。", "開講宮娃聽，拋生禁鳥餐。鐘聲入帝夢，天竺化長安。"]'),
('yuding-44','蕃寇侵逼，南歸道中','李洞','唐','御定全唐诗','yuding','','[]','雲州三萬騎，南走疾飛鷹。回磧星低雁，孤城月伴僧。',48,'御定全唐詩/json/721.json','["雲州三萬騎，南走疾飛鷹。回磧星低雁，孤城月伴僧。", "敲關通漢節，傾府守河冰。無處論邊事，歸溪夜結罾。"]'),
('yuding-45','送東宮賈正字之蜀','李洞','唐','御定全唐诗','yuding','','[]','南朝獻晉史，東蜀瞰巴樓。長棧懷宮樹，疏峰露劍州。',48,'御定全唐詩/json/721.json','["南朝獻晉史，東蜀瞰巴樓。長棧懷宮樹，疏峰露劍州。", "半空飛雪化，一道白雲流。若次江邊邑，宗詩為遍搜。"]'),
('yuding-46','吊侯圭常侍','李洞','唐','御定全唐诗','yuding','','[]','我重君能賦，君褒我解詩。三堂一拜遇，四海兩心知。',48,'御定全唐詩/json/721.json','["我重君能賦，君褒我解詩。三堂一拜遇，四海兩心知。", "影掛僧挑燭，名傳鶴拂碑。涪江吊孤塚，片月下峨嵋。"]'),
('yuding-47','顏上人房','李洞','唐','御定全唐诗','yuding','','[]','禦溝臨岸行，遠岫見雲生。松下度三伏，磬中銷五更。',48,'御定全唐詩/json/721.json','["禦溝臨岸行，遠岫見雲生。松下度三伏，磬中銷五更。", "雨淋經閣白，日閃剃刀明。海畔終須去，燒燈老國清。"]'),
('yuding-0','題薛少府莊','李洞','唐','御定全唐诗','yuding','','[]','何須鑿井飲，門占古溪居。寂寞苔床臥，寒虛玉柄書。',48,'御定全唐詩/json/722.json','["何須鑿井飲，門占古溪居。寂寞苔床臥，寒虛玉柄書。", "有期登白閣，又得賞紅蕖。清淺蒲根水，時看鷺啄魚。"]'),
('yuding-1','寄太白隱者','李洞','唐','御定全唐诗','yuding','','[]','開闢已來雪，為山長欠春。高遮辭磧雁，寒噤入川人。',48,'御定全唐詩/json/722.json','["開闢已來雪，為山長欠春。高遮辭磧雁，寒噤入川人。", "棧閣交冰柱，耕樵隔日輪。此中棲息者，不識兩京塵。"]'),
('yuding-2','秋宿青龍禪閣','李洞','唐','御定全唐诗','yuding','','[]','前山不可望，暮色漸沉規。日轉須彌北，蟾來渤海西。',48,'御定全唐詩/json/722.json','["前山不可望，暮色漸沉規。日轉須彌北，蟾來渤海西。", "風鈴亂僧語，霜枿欠猿啼。閣外千家月，分明見裏迷。"]'),
('yuding-3','登圭峰舊隱寄薦福棲白上人','李洞','唐','御定全唐诗','yuding','','[]','返照塔輪邊，殘霖滴幾懸。夜寒吟病甚，秋健講聲圓。',48,'御定全唐詩/json/722.json','["返照塔輪邊，殘霖滴幾懸。夜寒吟病甚，秋健講聲圓。", "粟穗幹燈焰，苔根濁水泉。西峰埋蘚石，秋月即師禪。"]'),
('yuding-4','將之蜀別友人','李洞','唐','御定全唐诗','yuding','','[]','嘉陵雨色青，澹別酌參苓。到蜀高諸嶽，窺天合四溟。',48,'御定全唐詩/json/722.json','["嘉陵雨色青，澹別酌參苓。到蜀高諸嶽，窺天合四溟。", "書來應隔雪，夢覺已無星。若遇多吟友，何妨勘竺經。"]'),
('yuding-5','吊膳曹從叔郎中','李洞','唐','御定全唐诗','yuding','','[]','華省支殘俸，寒蔬辦祭稀。安墳對白閣，買石折朱衣。',48,'御定全唐詩/json/722.json','["華省支殘俸，寒蔬辦祭稀。安墳對白閣，買石折朱衣。", "蜀客彈琴哭，江鷗入宅飛。帆吹佳句遠，不獨遍王畿。"]'),
('yuding-6','亂後龍州送鄭郎中兼寄鄭侍禦','李洞','唐','御定全唐诗','yuding','','[]','待車登疊嶂，經亂集鴒原。省壞蘭終潔，台寒柏有根。',48,'御定全唐詩/json/722.json','["待車登疊嶂，經亂集鴒原。省壞蘭終潔，台寒柏有根。", "縣清江入峽，樓靜雪連村。莫隱匡山社，機雲受晉恩。"]'),
('yuding-7','段秀才溪居送從弟游涇隴','李洞','唐','御定全唐诗','yuding','','[]','抱疾寒溪臥，因循草木青。相留開夏蜜，辭去見秋螢。',48,'御定全唐詩/json/722.json','["抱疾寒溪臥，因循草木青。相留開夏蜜，辭去見秋螢。", "朔雪痕侵雍，邊烽焰照涇。煙沈隴山色，西望涕交零。"]'),
('yuding-8','題劉相公光德里新構茅亭','李洞','唐','御定全唐诗','yuding','','[]','野色迷亭曉，龍墀待押班。帶涎移海木，兼雪寫湖山。',48,'御定全唐詩/json/722.json','["野色迷亭曉，龍墀待押班。帶涎移海木，兼雪寫湖山。", "月白吟床冷，河清直印閑。唐封三萬里，人偃翠微間。"]'),
('yuding-9','江峽寇亂寄懷吟僧','李洞','唐','御定全唐诗','yuding','','[]','半錫探寒流，別師猿鶴洲。二三更後雨，四十字邊秋。',48,'御定全唐詩/json/722.json','["半錫探寒流，別師猿鶴洲。二三更後雨，四十字邊秋。", "立塞吟霞石，敲鼙看雪樓。扶親何處隱，驚夢入嵩丘。"]'),
('yuding-10','賀昭國從叔員外轉本曹郎中','李洞','唐','御定全唐诗','yuding','','[]','苔砌塔陰濃，朝回尚叫蛩。粟征山縣欠，官轉水曹重。',48,'御定全唐詩/json/722.json','["苔砌塔陰濃，朝回尚叫蛩。粟征山縣欠，官轉水曹重。", "燈照樓中雨，書求海上峰。詩家無驟顯，一一古人蹤。"]'),
('yuding-11','贈宋校書','李洞','唐','御定全唐诗','yuding','','[]','曾伴元戎獵，寒來夢北軍。閑身不計日，病鶴放歸雲。',48,'御定全唐詩/json/722.json','["曾伴元戎獵，寒來夢北軍。閑身不計日，病鶴放歸雲。", "石上鋪棋勢，船中賭酒分。長言買天姥，高臥謝人群。"]'),
('yuding-12','越公上人洛中歸寄南孟家兄弟','李洞','唐','御定全唐诗','yuding','','[]','洛下因歸去，關西憶二龍。笠漫河岸雪，衣著虢城鐘。',48,'御定全唐詩/json/722.json','["洛下因歸去，關西憶二龍。笠漫河岸雪，衣著虢城鐘。", "睡鴨浮寒水，樵人出遠峰。何當化閭俗，護取草堂松。"]'),
('yuding-13','龍州送裴秀才','李洞','唐','御定全唐诗','yuding','','[]','違拜旆旗前，松陰路半千。樓沖高雪會，驛閉亂雲眠。',48,'御定全唐詩/json/722.json','["違拜旆旗前，松陰路半千。樓沖高雪會，驛閉亂雲眠。", "榜掛臨江省，名題赴宅筵。人求新蜀賦，應貴浣花箋。"]'),
('yuding-14','題慈恩友人房','李洞','唐','御定全唐诗','yuding','','[]','賈生耽此寺，勝事入詩多。鶴宿星千樹，僧歸燒一坡。',48,'御定全唐詩/json/722.json','["賈生耽此寺，勝事入詩多。鶴宿星千樹，僧歸燒一坡。", "塔棱垂雪水，江色映茶鍋。長久堪棲息，休言憶鏡波。"]'),
('yuding-15','寄竇禪山薛秀才','李洞','唐','御定全唐诗','yuding','','[]','竇嶺吟招隱，新詩滿集賢。白衫春絮暖，紅紙夏雲鮮。',48,'御定全唐詩/json/722.json','["竇嶺吟招隱，新詩滿集賢。白衫春絮暖，紅紙夏雲鮮。", "琴纏江絲細，棋分海石圓。因知醉公子，虛寫世人傳。"]'),
('yuding-16','西蜀與崔先生話東洛舊游','李洞','唐','御定全唐诗','yuding','','[]','王屋峭難名，三刀夢四更。日升當地缺，星盡未天明。',48,'御定全唐詩/json/722.json','["王屋峭難名，三刀夢四更。日升當地缺，星盡未天明。", "度雪雲林濕，穿松角韻清。崔家開錦浪，憶著水窗聲。"]'),
('yuding-17','上昭國水部從叔郎中','李洞','唐','御定全唐诗','yuding','','[]','極南極北遊，東泛複西流。行匝中華地，魂銷四海秋。',48,'御定全唐詩/json/722.json','["極南極北遊，東泛複西流。行匝中華地，魂銷四海秋。", "題詩在瓊府，附舶出青州。不遇一公子，彈琴吊古丘。"]'),
('yuding-18','題玉芝趙尊師院','李洞','唐','御定全唐诗','yuding','','[]','曉起磬房前，真經誦百篇。漱流星入齒，照鏡石差肩。',48,'御定全唐詩/json/722.json','["曉起磬房前，真經誦百篇。漱流星入齒，照鏡石差肩。", "靜閉街西觀，存思海上仙。閑聽說五嶽，窮遍一根蓮。"]'),
('yuding-19','送盧少府之任鞏洛','李洞','唐','御定全唐诗','yuding','','[]','從知東甸尉，銓注似恩除。帶土移嵩術，和泉送尹魚。',48,'御定全唐詩/json/722.json','["從知東甸尉，銓注似恩除。帶土移嵩術，和泉送尹魚。", "印床寒鷺宿，壁記醉僧書。堂下諸昆在，無妨候起居。"]'),
('yuding-20','送人歸覲河中','李洞','唐','御定全唐诗','yuding','','[]','青門塚前別，道路武關西。有寺雲連石，無僧葉滿溪。',48,'御定全唐詩/json/722.json','["青門塚前別，道路武關西。有寺雲連石，無僧葉滿溪。", "河長隨鳥盡，山遠與人齊。覲省波濤縣，寒窗響曙雞。"]'),
('yuding-21','錦城秋寄懷弘播上人','李洞','唐','御定全唐诗','yuding','','[]','極頂雲兼凍，孤城露洗初。共辭嵩少雪，久絕貝多書。',48,'御定全唐詩/json/722.json','["極頂雲兼凍，孤城露洗初。共辭嵩少雪，久絕貝多書。", "遠照雁行細，寒條狖掛虛。分泉煎月色，憶就茗林居。"]'),
('yuding-22','圭峰溪居寄懷韋曲曹秀才','李洞','唐','御定全唐诗','yuding','','[]','南北飛山雪，萬片寄相思。東西曲流水，千聲瀉別離。',48,'御定全唐詩/json/722.json','["南北飛山雪，萬片寄相思。東西曲流水，千聲瀉別離。", "巴猿學導引，隴鳥解吟詩。翻羨家林賞，世人那得知。"]'),
('yuding-23','送舍弟之山南','李洞','唐','御定全唐诗','yuding','','[]','南山入谷遊，去徹山南州。下馬雲未盡，聽猿星正稠。',48,'御定全唐詩/json/722.json','["南山入谷遊，去徹山南州。下馬雲未盡，聽猿星正稠。", "印茶泉繞石，封國角吹樓。遠宦有何興，貧兄無計留。"]'),
('yuding-24','題南鑒公山房','李洞','唐','御定全唐诗','yuding','','[]','竹房開處峭，迥掛半山燈。石磬敲來穴，不知何代僧。',48,'御定全唐詩/json/722.json','["竹房開處峭，迥掛半山燈。石磬敲來穴，不知何代僧。", "講歸雙袖雪，禪起一盂冰。唯說黃桑屐，當時著秣陵。"]'),
('yuding-25','送知己','李洞','唐','御定全唐诗','yuding','','[]','郡清官舍冷，枕席濺山泉。藥氣來人外，燈光到鶴邊。',48,'御定全唐詩/json/722.json','["郡清官舍冷，枕席濺山泉。藥氣來人外，燈光到鶴邊。", "夢秦書印鬥，思越畫漁船。擲笏南歸去，波濤路幾千。"]'),
('yuding-26','送人赴職湘潭','李洞','唐','御定全唐诗','yuding','','[]','南征雖赴辟，其奈負高科。水合湘潭住，山分越國多。',48,'御定全唐詩/json/722.json','["南征雖赴辟，其奈負高科。水合湘潭住，山分越國多。", "梅花雪共下，文□□相和。白髮陪官宴，紅旗影裏歌。"]'),
('yuding-27','過野叟居','李洞','唐','御定全唐诗','yuding','','[]','野人居止處，竹色與山光。留客羞蔬飯，灑泉開草堂。',48,'御定全唐詩/json/722.json','["野人居止處，竹色與山光。留客羞蔬飯，灑泉開草堂。", "雨餘松子落，風過朮苗香。盡日無炎暑，眠君青石床。"]'),
('yuding-28','吊鄭賓客','李洞','唐','御定全唐诗','yuding','','[]','朝行喪名節，嶽色慘天風。待漏秋吟斷，焚香夜直空。',48,'御定全唐詩/json/722.json','["朝行喪名節，嶽色慘天風。待漏秋吟斷，焚香夜直空。", "骨寒依壟草，家盡逐邊鴻。一吊知音後，歸來碎嶧桐。"]'),
('yuding-29','送從叔書記山陰隱居','李洞','唐','御定全唐诗','yuding','','[]','山頂絕茅居，雲泉繞枕虛。燒移僧影瘦，風展鷺行疏。',48,'御定全唐詩/json/722.json','["山頂絕茅居，雲泉繞枕虛。燒移僧影瘦，風展鷺行疏。", "卷箔清江月，敲松紫閣書。由來簪組貴，不信教猿鋤。"]'),
('yuding-30','避暑莊嚴禪院','李洞','唐','御定全唐诗','yuding','','[]','定裏無煩熱，吟中達性情。入林逢客話，上塔接僧行。',48,'御定全唐詩/json/722.json','["定裏無煩熱，吟中達性情。入林逢客話，上塔接僧行。", "八水皆知味，諸翁盡得名。常論冰井近，莫便厭浮生。"]'),
('yuding-31','寄清演','李洞','唐','御定全唐诗','yuding','','[]','忽聞清演病，可料苦吟身。不見近詩久，徒言華髮新。',48,'御定全唐詩/json/722.json','["忽聞清演病，可料苦吟身。不見近詩久，徒言華髮新。", "別來山已破，住處月為鄰。幾繞庭前樹，於今四十春。"]'),
('yuding-32','遷村居二首','李洞','唐','御定全唐诗','yuding','','[]','移居入村宇，樹闕見城隍。雲水雖堪畫，恩私不可忘。',96,'御定全唐詩/json/722.json','["移居入村宇，樹闕見城隍。雲水雖堪畫，恩私不可忘。", "猿涎滴鶴氅，麈尾拂僧床。棄逐隨樵牧，何由報稻粱。", "歌樂聽常稀，茅亭靜掩扉。槎來垂釣次，月落問安歸。", "遠客傳燒研，幽禽看衲衣。眼前無俗事，松雨蜀山輝。"]'),
('yuding-33','出山睹春榜','李洞','唐','御定全唐诗','yuding','','[]','未老鬢毛焦，心歸向石橋。指霞辭二紀，吟雪遇三朝。',48,'御定全唐詩/json/722.json','["未老鬢毛焦，心歸向石橋。指霞辭二紀，吟雪遇三朝。", "連席頻登相，分廊尚祝堯。回眸舊行侶，免使負嵩樵。"]'),
('yuding-34','賈島墓','李洞','唐','御定全唐诗','yuding','','[]','一第人皆得，先生豈不銷。位卑終蜀士，詩絕占唐朝。',48,'御定全唐詩/json/722.json','["一第人皆得，先生豈不銷。位卑終蜀士，詩絕占唐朝。", "旅葬新墳小，魂歸故國遙。我來因奠灑，立石用為標。"]'),
('yuding-35','觀水墨障子','李洞','唐','御定全唐诗','yuding','','[]','若非神助筆，硯水恐藏龍。研盡一寸墨，掃成千仞峰。',72,'御定全唐詩/json/722.json','["若非神助筆，硯水恐藏龍。研盡一寸墨，掃成千仞峰。", "壁根堆亂石，床罅插枯松。嶽麓穿因鼠，湘江綻為蛩。", "掛衣嵐氣濕，夢枕浪頭舂。只為少顏色，時人著意慵。"]'),
('yuding-36','對棋','李洞','唐','御定全唐诗','yuding','','[]','小檻明高雪，幽人鬥智棋。日斜拋作劫，月午蹙成遲。',72,'御定全唐詩/json/722.json','["小檻明高雪，幽人鬥智棋。日斜拋作劫，月午蹙成遲。", "倚杖湘僧算，翹松野鶴窺。側楸敲醒睡，片石夾吟詩。", "雨點奩中漬，燈花局上吹。秋濤寒竹寺，此興謝公知。"]'),
('yuding-37','題竹溪禪院','李洞','唐','御定全唐诗','yuding','','[]','溪邊山一色，水擁竹千竿。鳥觸翠微濕，人居酷暑寒。',72,'御定全唐詩/json/722.json','["溪邊山一色，水擁竹千竿。鳥觸翠微濕，人居酷暑寒。", "風搖瓶影碎，沙陷履痕端。爽極青崖樹，平流綠峽灘。", "閑來披衲數，漲後卷經看。三境通禪寂，囂塵染著難。"]'),
('yuding-38','投獻吏部張侍郎十韻','李洞','唐','御定全唐诗','yuding','','[]','苔染馬蹄青，何曾似在城。不於僧院宿，多傍禦溝行。',120,'御定全唐詩/json/722.json','["苔染馬蹄青，何曾似在城。不於僧院宿，多傍禦溝行。", "隱岫侵巴疊，租田帶渭平。肩囊尋省寺，袖軸遍公卿。", "夢入連濤郡，書來積雪營。淚隨邊雁墮，魂逐夜蟬驚。", "發憤巡江塔，無眠數縣更。玄都一病客，興善幾回鶯。", "貢藝披沙細，酬恩戴嶽輕。心期公子念，滴酒在雕楹。"]'),
('yuding-39','終南山二十韻','李洞','唐','御定全唐诗','yuding','','[]','關內平田窄，東西截杳冥。雨侵諸縣黑，雲破九門青。',240,'御定全唐詩/json/722.json','["關內平田窄，東西截杳冥。雨侵諸縣黑，雲破九門青。", "暫看猶無暇，長棲信有靈。古苔秋漬鬥，積霧夜昏螢。", "怒恐撞天漏，深疑隱地形。盤根連北嶽，轉影落南溟。", "窮穴何山出，遮蠻上國寧。殘陽高照蜀，敗葉遠浮涇。", "劚竹煙嵐凍，偷湫雨雹腥。閒房僧灌頂，浴澗鶴遺翎。", "梯滑危緣索，雲深靜唱經。放泉驚鹿睡，聞磬得人醒。", "踏著神仙宅，敲開洞府扃。棋殘秦士局，字缺晉公銘。", "一穀勢當午，孤峰聳起丁。遠平丹鳳闕，冷射五侯廳。", "萬丈冰聲折，千尋樹影停。望中仙島動，行處月輪馨。", "疊石移臨砌，研膠潑上屏。明時獻君壽，不假老人星。"]'),
('yuding-40','秋日同覺公上人眺慈恩塔六韻','李洞','唐','御定全唐诗','yuding','','[]','九級聳蓮宮，晴登袖拂虹。房廊窺井底，世界出籠中。',72,'御定全唐詩/json/722.json','["九級聳蓮宮，晴登袖拂虹。房廊窺井底，世界出籠中。", "照牖三山火，吹鈴八極風。細聞槎客語，遙辨海魚沖。", "禁靜聲連北，江寒影在東。謁師開秘鎖，塵日閉虛空。"]'),
('yuding-41','感知上刑部鄭侍郎','李洞','唐','御定全唐诗','yuding','','[]','寄掩白雲司，蜀都高臥時。鄰僧照寒竹，宿鳥動秋池。',144,'御定全唐詩/json/722.json','["寄掩白雲司，蜀都高臥時。鄰僧照寒竹，宿鳥動秋池。", "帝誦嘉蓮表，人吟寶劍詩。石渠流月斷，畫角截江吹。", "閑出黃金勒，前飛白鷺鶿。公心外國說，重望兩朝推。", "靜蘚斜圭影，孤窗響錫枝。興幽松雪見，心苦硯冰知。", "緣杖蟲聲切，過門馬足遲。漏殘終卷讀，日下大名垂。", "平磧容雕上，仙山許狖窺。數聯金口出，死免愧丘為。"]'),
('yuding-42','敘事寄薦福棲白','李洞','唐','御定全唐诗','yuding','','[]','險倚石屏風，秋濤夢越中。前朝吟會散，故國講流終。',96,'御定全唐詩/json/722.json','["險倚石屏風，秋濤夢越中。前朝吟會散，故國講流終。", "北地聞巴狖，南山見磧鴻。樓高驚雨闊，木落覺城空。", "兔滿期姚監，蟬稀別楚公。淨瓶光照客，拄杖朽生蟲。", "平地塔千尺，半空燈一籠。祝堯談幾句，旋瀉海濤東。"]'),
('yuding-43','送龍州田使君舊詩家','李洞','唐','御定全唐诗','yuding','','[]','禦劄軫西陲，龍州出牧時。度關雲作雪，掛棧水成澌。',72,'御定全唐詩/json/722.json','["禦劄軫西陲，龍州出牧時。度關雲作雪，掛棧水成澌。", "劍淬號猿岸，弓懸宿鶴枝。江燈混星斗，山木亂槍旗。", "鎖庫休秤藥，開樓又見詩。無心陪宴集，吟苦憶京師。"]'),
('yuding-44','和知己赴任華州','李洞','唐','御定全唐诗','yuding','','[]','東門罷相郡，此拜動京華。落日開宵印，初燈見早麻。',120,'御定全唐詩/json/722.json','["東門罷相郡，此拜動京華。落日開宵印，初燈見早麻。", "鶴身紅旆拂，仙掌白雲遮。塞色侵三縣，河聲聒兩衙。", "松根醒客酒，蓮座隱僧家。一道帆飛直，中筵嶽影斜。", "書名尋雪石，澄鼎露金沙。鎖合眠關吏，杯寒啄廟鴉。", "分台話嵩洛，賽雨戀煙霞。樹穀期招隱，吟詩煮柏茶。"]'),
('yuding-45','題咸陽樓','李洞','唐','御定全唐诗','yuding','','[]','晚亞古城門，憑高黯客魂。塞侵秦舊國，河浸漢荒村。',144,'御定全唐詩/json/722.json','["晚亞古城門，憑高黯客魂。塞侵秦舊國，河浸漢荒村。", "客路颺書燼，人家帶水痕。獵頻虛塚穴，耕苦露松根。", "牆外峰粘漢，冰中日晃原。斷碑移作砌，廣第灌成園。", "北馬疑眠磧，南人憶釣湓。橋閑野鹿過，街靜禁鴉翻。", "灘鼓城隍動，雲沖太白昏。標衣多呂裔，荷鍤或劉孫。", "吊問難知主，登攀強滴樽。不能扶壯勢，冠劍惜乾坤。"]'),
('yuding-46','贈興善徹公上人','李洞','唐','御定全唐诗','yuding','','[]','師資懷劍外，徒步管街東。九裏山橫燒，三條木落風。',60,'御定全唐詩/json/722.json','["師資懷劍外，徒步管街東。九裏山橫燒，三條木落風。", "古池曾看鶴，新塔未吟蟲。夜久龍髯冷，年多麈尾空。", "心宗本無礙，問學豈難同。"]'),
('yuding-47','龍池春草','李洞','唐','御定全唐诗','yuding','','[]','龍池清禁裏，芳草傍池春。旋長方遮岸，全生不染塵。',72,'御定全唐詩/json/722.json','["龍池清禁裏，芳草傍池春。旋長方遮岸，全生不染塵。", "和風輕動色，湛露靜流津。淺得承天步，深疑繞禦輪。", "魚尋倒影沒，花帶濕光新。肯學長河畔，綿綿思遠人。"]'),
('yuding-48','秋宿梓州牛頭寺','李洞','唐','御定全唐诗','yuding','','[]','月去簷三尺，川雲入寺樓。靈山頓離眾，列宿不多稠。',120,'御定全唐詩/json/722.json','["月去簷三尺，川雲入寺樓。靈山頓離眾，列宿不多稠。", "篆字焚初缺，翻經誦若流。窗閑二江冷，簾卷半空秋。", "詔散松梢別，棋終竹節收。靜增雙闕念，高並五翁遊。", "鶴夢生紅日，雲閑鎖梓州。望空工部眼，搔亂廣文頭。", "石室僧調馬，銀河客問牛。曉樓歸下界，大地一浮漚。"]'),
('yuding-49','送韋太尉自坤維除廣陵','李洞','唐','御定全唐诗','yuding','','[]','全蜀拜揚州，征東輟武侯。直來萬里月，旁到五峰秋。',72,'御定全唐詩/json/722.json','["全蜀拜揚州，征東輟武侯。直來萬里月，旁到五峰秋。", "幢冷遮高雪，旗閑卓亂流。謝朝明主喜，登省舊寮愁。", "隔海城通舶，連河市響樓。千官倚元老，虛夢法雲遊。"]'),
('yuding-0','贈曹郎中崇賢所居','李洞','唐','御定全唐诗','yuding','','[]','閑坊宅枕穿宮水，聽水分衾蓋蜀繒。藥杵聲中搗殘夢，',40,'御定全唐詩/json/723.json','["閑坊宅枕穿宮水，聽水分衾蓋蜀繒。藥杵聲中搗殘夢，", "詩句變風官漸緊，夜濤舂斷海邊藤。"]'),
('yuding-1','贈昭應沈少府','李洞','唐','御定全唐诗','yuding','','[]','行宮接縣判雲泉，袍色雖青骨且仙。鄠杜憶過梨栗墅，',40,'御定全唐詩/json/723.json','["行宮接縣判雲泉，袍色雖青骨且仙。鄠杜憶過梨栗墅，", "東送西迎終幾考，新詩覓得兩三聯。"]'),
('yuding-2','上司空員外','李洞','唐','御定全唐诗','yuding','','[]','禪心高臥似疏慵，詩客經過不厭重。藤杖幾攜量磧雪，',40,'御定全唐詩/json/723.json','["禪心高臥似疏慵，詩客經過不厭重。藤杖幾攜量磧雪，", "禹鑿故山歸未得，河聲暗老兩三松。"]'),
('yuding-3','敘舊游寄棲白','李洞','唐','御定全唐诗','yuding','','[]','老著重袍坐石房，竺經休講白眉長。省沖鼉沒投江島，',40,'御定全唐詩/json/723.json','["老著重袍坐石房，竺經休講白眉長。省沖鼉沒投江島，", "吟詩五嶺尋無可，倏忽如今四十霜。"]'),
('yuding-4','哭棲白供奉','李洞','唐','御定全唐诗','yuding','','[]','聞說孤窗坐化時，白莎蘿雨滴空池。吟詩堂裏秋關影，',40,'御定全唐詩/json/723.json','["聞說孤窗坐化時，白莎蘿雨滴空池。吟詩堂裏秋關影，", "逢山對月還惆悵，爭得無言似祖師。"]'),
('yuding-5','贈入內供奉僧','李洞','唐','御定全唐诗','yuding','','[]','內殿談經愜帝懷，沃州歸隱計全乖。數條雀尾來南海，',40,'御定全唐詩/json/723.json','["內殿談經愜帝懷，沃州歸隱計全乖。數條雀尾來南海，", "因逢夏日西明講，不覺宮人拔鳳釵。"]'),
('yuding-6','感恩書事寄上集義司徒相公','李洞','唐','御定全唐诗','yuding','','[]','積雪峰西遇獎稱，半家寒骨起溝塍。鎮時賢相回人鏡，',40,'御定全唐詩/json/723.json','["積雪峰西遇獎稱，半家寒骨起溝塍。鎮時賢相回人鏡，", "功居第一圖煙閣，依舊終南滿杜陵。"]'),
('yuding-7','贈永崇李將軍充襄陽制置使','李洞','唐','御定全唐诗','yuding','','[]','拜官門外發輝光，宿衛陰符注幾行。行處近天龍尾滑，',40,'御定全唐詩/json/723.json','["拜官門外發輝光，宿衛陰符注幾行。行處近天龍尾滑，", "從此浩然聲價歇，武中還有李襄陽。"]'),
('yuding-8','寄淮海惠澤上人','李洞','唐','御定全唐诗','yuding','','[]','海濤痕滿舊征衣，長憶初程宿翠微。竹裏橋鳴知馬過，',40,'御定全唐詩/json/723.json','["海濤痕滿舊征衣，長憶初程宿翠微。竹裏橋鳴知馬過，", "他日願師容一榻，煎茶掃地學忘機。"]'),
('yuding-9','春日隱居官舍感懷','李洞','唐','御定全唐诗','yuding','','[]','風吹燒燼雜汀沙，還似青溪舊寄家。入戶竹生床下葉，',40,'御定全唐詩/json/723.json','["風吹燒燼雜汀沙，還似青溪舊寄家。入戶竹生床下葉，", "銷得人間無限事，江亭月白誦南華。"]'),
('yuding-10','春日即事寄一二知己','李洞','唐','御定全唐诗','yuding','','[]','浴馬池西一帶泉，開門景物似樊川。朱衣映水人歸縣，',40,'御定全唐詩/json/723.json','["浴馬池西一帶泉，開門景物似樊川。朱衣映水人歸縣，", "縉紳處士知章句，忍使孤窗枕淚眠。"]'),
('yuding-11','廢寺閒居寄懷一二罷舉知己','李洞','唐','御定全唐诗','yuding','','[]','病居廢廟冷吟煙，無力爭飛類病蟬。槐省老郎蒙主棄，',40,'御定全唐詩/json/723.json','["病居廢廟冷吟煙，無力爭飛類病蟬。槐省老郎蒙主棄，", "處世堪驚又堪愧，一坡山色不論錢。"]'),
('yuding-12','題尼大德院','李洞','唐','御定全唐诗','yuding','','[]','雲鬟早歲斷金刀，戒律曾持五百條。臺上燈紅蓮葉密，',40,'御定全唐詩/json/723.json','["雲鬟早歲斷金刀，戒律曾持五百條。臺上燈紅蓮葉密，", "清淨高樓松檜寺，世雄翻愧自低腰。"]'),
('yuding-13','懷張喬張霞','李洞','唐','御定全唐诗','yuding','','[]','西風吹雨葉還飄，憶我同袍隔海濤。江塔眺山青入佛，',40,'御定全唐詩/json/723.json','["西風吹雨葉還飄，憶我同袍隔海濤。江塔眺山青入佛，", "應念無成獨流轉，懶磨銅片鬢毛焦。"]'),
('yuding-14','贈徐山人','李洞','唐','御定全唐诗','yuding','','[]','徐生何代降坤維，曾伴園公采紫芝。瓦礫變黃憂世換，',40,'御定全唐詩/json/723.json','["徐生何代降坤維，曾伴園公采紫芝。瓦礫變黃憂世換，", "知歎有唐三百載，光陰未抵一先棋。"]'),
('yuding-15','寄南嶽僧','李洞','唐','御定全唐诗','yuding','','[]','新秋日後曬書天，白日當松影卻圓。五字句求方寸佛，',40,'御定全唐詩/json/723.json','["新秋日後曬書天，白日當松影卻圓。五字句求方寸佛，", "花落儔公房外石，調猿弄虎歎無緣。"]'),
('yuding-16','華山','李洞','唐','御定全唐诗','yuding','','[]','碧山長凍地長秋，日夕泉源聒華州。萬戶煙侵關令宅，',40,'御定全唐詩/json/723.json','["碧山長凍地長秋，日夕泉源聒華州。萬戶煙侵關令宅，", "峰頂高眠靈藥熟，自無霜雪上人頭。"]'),
('yuding-17','和曹監春晴見寄','李洞','唐','御定全唐诗','yuding','','[]','竺廟鄰鐘震曉鴉，春陰蓋石似仙家。蘭台架列排書目，',40,'御定全唐詩/json/723.json','["竺廟鄰鐘震曉鴉，春陰蓋石似仙家。蘭台架列排書目，", "功成名著扁舟去，愁睹前題罩碧紗。"]'),
('yuding-18','贈三惠大師','李洞','唐','御定全唐诗','yuding','','[]','楓猿嶠角別多時，二教兼修內學師。藥樹影中頻綴偈，',40,'御定全唐詩/json/723.json','["楓猿嶠角別多時，二教兼修內學師。藥樹影中頻綴偈，", "詔落五天開夏講，兩街人競禮長眉。"]'),
('yuding-19','送醉畫王處士','李洞','唐','御定全唐诗','yuding','','[]','幾年乘興住南吳，狂醉蘭舟夜落湖。別後鶴毛描轉細，',40,'御定全唐詩/json/723.json','["幾年乘興住南吳，狂醉蘭舟夜落湖。別後鶴毛描轉細，", "關下相逢怪予老，篇章役思繞寰區。"]'),
('yuding-20','聞杜鵑','李洞','唐','御定全唐诗','yuding','','[]','萬古瀟湘波上雲，化為流血杜鵑身。長疑啄破青山色，',40,'御定全唐詩/json/723.json','["萬古瀟湘波上雲，化為流血杜鵑身。長疑啄破青山色，", "聲聲猶得到君耳，不見千秋一甑塵。"]'),
('yuding-21','賦得送軒轅先生歸羅浮山','李洞','唐','御定全唐诗','yuding','','[]','舊山歸隱浪搖青，綠鬢山童一帙經。詩帖布帆猿鳥看，',40,'御定全唐詩/json/723.json','["舊山歸隱浪搖青，綠鬢山童一帙經。詩帖布帆猿鳥看，", "此處先生應不住，吾君南望漫勞形。"]'),
('yuding-22','送包處士','李洞','唐','御定全唐诗','yuding','','[]','秋思枕月臥瀟湘，寄宿慈恩竹裏房。性急卻於棋上慢，',40,'御定全唐詩/json/723.json','["秋思枕月臥瀟湘，寄宿慈恩竹裏房。性急卻於棋上慢，", "聞說石門君舊隱，寒峰濺瀑壞書堂。"]'),
('yuding-23','贈龐煉師','李洞','唐','御定全唐诗','yuding','','[]','家住涪江漢語嬌，一聲歌戛玉樓簫。睡融春日柔金縷，',40,'御定全唐詩/json/723.json','["家住涪江漢語嬌，一聲歌戛玉樓簫。睡融春日柔金縷，", "若能攜手隨仙令，皎皎銀河渡鵲橋。"]'),
('yuding-24','送友罷舉赴邊職','李洞','唐','御定全唐诗','yuding','','[]','出剡篇章入洛文，無人細讀歎俱焚。莫辭秉笏隨紅旆，',40,'御定全唐詩/json/723.json','["出剡篇章入洛文，無人細讀歎俱焚。莫辭秉笏隨紅旆，", "高談闊略陳從事，盟誓邊庭壯我軍。"]'),
('yuding-25','病猿','李洞','唐','御定全唐诗','yuding','','[]','瘦纏金鎖惹朱樓，一別巫山樹幾秋。寒想蜀門清露滴，',40,'御定全唐詩/json/723.json','["瘦纏金鎖惹朱樓，一別巫山樹幾秋。寒想蜀門清露滴，", "啼過三聲應有淚，畫堂深不徹王侯。"]'),
('yuding-26','斃驢','李洞','唐','御定全唐诗','yuding','','[]','蹇驢秋斃瘞荒田，忍把敲吟舊竹鞭。三尺焦桐背殘月，',40,'御定全唐詩/json/723.json','["蹇驢秋斃瘞荒田，忍把敲吟舊竹鞭。三尺焦桐背殘月，", "如畫海門支肘望，阿誰家賣釣魚船。"]'),
('yuding-27','宿葉公棋閣','李洞','唐','御定全唐诗','yuding','','[]','帶風棋閣竹相敲，局瑩無塵拂樹梢。日到長天征未斷，',40,'御定全唐詩/json/723.json','["帶風棋閣竹相敲，局瑩無塵拂樹梢。日到長天征未斷，", "因悟修身試貪教，不須焚火向三茅。"]'),
('yuding-28','送郤先輩歸覲華陰','李洞','唐','御定全唐诗','yuding','','[]','桂枝博得鳳棲枝，歡覲家僮舞翠微。僧向瀑泉聲裏賀，',40,'御定全唐詩/json/723.json','["桂枝博得鳳棲枝，歡覲家僮舞翠微。僧向瀑泉聲裏賀，", "騷雅近來頹喪甚，送君傍覺有光輝。"]'),
('yuding-29','贈可上人','李洞','唐','御定全唐诗','yuding','','[]','寺門和鶴倚香杉，月吐秋光到思嚵。將法傳來穿泱漭，',40,'御定全唐詩/json/723.json','["寺門和鶴倚香杉，月吐秋光到思嚵。將法傳來穿泱漭，", "不斷清風牙底嚼，無因內殿得名銜。"]'),
('yuding-30','東川高僕射','李洞','唐','御定全唐诗','yuding','','[]','油幢影裏拜清風，十裏貔貅一片雄。三印鎖開霜滿地，',40,'御定全唐詩/json/723.json','["油幢影裏拜清風，十裏貔貅一片雄。三印鎖開霜滿地，", "新起畫樓攜客上，弦歌筵內海榴紅。"]'),
('yuding-31','宿成都松溪院','李洞','唐','御定全唐诗','yuding','','[]','松持節操溪澄性，一炷煙嵐壓寺隅。翡翠鳥飛人不見，',40,'御定全唐詩/json/723.json','["松持節操溪澄性，一炷煙嵐壓寺隅。翡翠鳥飛人不見，", "塵擁蜀城抽鎖後，此中猶夢在江湖。"]'),
('yuding-32','吊曹監','李洞','唐','御定全唐诗','yuding','','[]','宅上愁雲吹不散，桂林詩骨葬雲根。滿樓山色供鄰里，',40,'御定全唐詩/json/723.json','["宅上愁雲吹不散，桂林詩骨葬雲根。滿樓山色供鄰里，", "吟魂醉魄歸何處，禦水嗚嗚夜繞門。"]'),
('yuding-33','贈長安畢郎中','李洞','唐','御定全唐诗','yuding','','[]','高門寒沼水連雲，鷺識朱衣傍主人。地肺半邊晴帶雪，',40,'御定全唐詩/json/723.json','["高門寒沼水連雲，鷺識朱衣傍主人。地肺半邊晴帶雪，", "從此幾遷為計相，蓬萊三刻奏東巡。"]'),
('yuding-34','寄東蜀幕中友','李洞','唐','御定全唐诗','yuding','','[]','官亭池碧海榴殷，遙想清才倚畫欄。柳絮漲天籠地暖，',40,'御定全唐詩/json/723.json','["官亭池碧海榴殷，遙想清才倚畫欄。柳絮漲天籠地暖，", "為話門人吟太苦，風摧蘭秀一枝殘。"]'),
('yuding-35','曲江漁父','李洞','唐','御定全唐诗','yuding','','[]','兒孫閑弄雪霜髯，浪颭南山影入簷。臥穩篷舟龜作枕，',40,'御定全唐詩/json/723.json','["兒孫閑弄雪霜髯，浪颭南山影入簷。臥穩篷舟龜作枕，", "數尺寒絲一竿竹，豈知浮世有猜嫌。"]'),
('yuding-36','和劉駕博士贈莊嚴律禪師','李洞','唐','御定全唐诗','yuding','','[]','人言紫綬有光輝，不二心觀似草衣。塵劫自營還自壞，',40,'御定全唐詩/json/723.json','["人言紫綬有光輝，不二心觀似草衣。塵劫自營還自壞，", "每話南遊偏起念，五峰波上入船扉。"]'),
('yuding-37','智新上人話舊','李洞','唐','御定全唐诗','yuding','','[]','蟋蟀燈前話舊游，師經幾夏我經秋。金陵市合月光裏，',40,'御定全唐詩/json/723.json','["蟋蟀燈前話舊游，師經幾夏我經秋。金陵市合月光裏，", "相看未得東歸去，滿壁寒濤瀉白鷗。"]'),
('yuding-38','和淮南太尉留題鳳州王氏別業','李洞','唐','御定全唐诗','yuding','','[]','清秋看長鷺雛成，說向湘僧亦動情。節屋折將松上影，',40,'御定全唐詩/json/723.json','["清秋看長鷺雛成，說向湘僧亦動情。節屋折將松上影，", "閑想此中遺勝事，宿齋吟繞鳳池行。"]'),
('yuding-39','乙酉歲自蜀隨計趁試不及','李洞','唐','御定全唐诗','yuding','','[]','客臥涪江蘸月廳，知音喚起進趨生。寒梅折後方離蜀，',40,'御定全唐詩/json/723.json','["客臥涪江蘸月廳，知音喚起進趨生。寒梅折後方離蜀，", "文昌一試應關分，豈校褒斜兩日程。"]'),
('yuding-40','龍州韋郎中先夢六赤，後因打葉子以詩上','李洞','唐','御定全唐诗','yuding','','[]','紅蠟香煙撲畫楹，梅花落盡庾樓清。光輝圓魄銜山冷，',40,'御定全唐詩/json/723.json','["紅蠟香煙撲畫楹，梅花落盡庾樓清。光輝圓魄銜山冷，", "微黃喜兆莊周夢，六赤重新擲印成。"]'),
('yuding-41','和壽中丞傷猿','李洞','唐','御定全唐诗','yuding','','[]','遺掛朱欄鎖半尋，清聲難買恨黃金。懸崖接果今何在，',48,'御定全唐詩/json/723.json','["遺掛朱欄鎖半尋，清聲難買恨黃金。懸崖接果今何在，", "小山罷繞隨湘客，高樹休升對嶽禽。天竺省憐傷倍切，"]'),
('yuding-42','上靈州令狐相公','李洞','唐','御定全唐诗','yuding','','[]','征蠻破虜漢功臣，提劍歸來萬里身。',32,'御定全唐詩/json/723.json','["征蠻破虜漢功臣，提劍歸來萬里身。", "笑倚淩煙金柱看，形容憔悴老於真。"]'),
('yuding-43','寓言','李洞','唐','御定全唐诗','yuding','','[]','三千宮女露蛾眉，笑煮黃金日月遲。',32,'御定全唐詩/json/723.json','["三千宮女露蛾眉，笑煮黃金日月遲。", "麟鳳隔雲攀不及，空山惆悵夕陽時。"]'),
('yuding-44','客亭對月','李洞','唐','御定全唐诗','yuding','','[]','遊子離魂隴上花，風飄浪捲繞天涯。',32,'御定全唐詩/json/723.json','["遊子離魂隴上花，風飄浪捲繞天涯。", "一年十二度圓月，十一回圓不在家。"]'),
('yuding-45','宿鄠郊贈羅處士','李洞','唐','御定全唐诗','yuding','','[]','川靜星高櫟已枯，南山落石水聲粗。',32,'御定全唐詩/json/723.json','["川靜星高櫟已枯，南山落石水聲粗。", "白雲釣客窗中宿，臥數嵩峰聽五湖。"]'),
('yuding-46','有寄','李洞','唐','御定全唐诗','yuding','','[]','愛酒耽棋田處士，彈琴詠史賈先生。',32,'御定全唐詩/json/723.json','["愛酒耽棋田處士，彈琴詠史賈先生。", "禦溝臨岸有雲石，不見鶴來何處行。"]'),
('yuding-47','送三藏歸西天國','李洞','唐','御定全唐诗','yuding','','[]','十萬里程多少磧，沙中彈舌授降龍。',32,'御定全唐詩/json/723.json','["十萬里程多少磧，沙中彈舌授降龍。", "五天到日應頭白，月落長安半夜鐘。"]'),
('yuding-48','金陵懷古','李洞','唐','御定全唐诗','yuding','','[]','古來無此戰爭功，日日戈船卷海風。',32,'御定全唐詩/json/723.json','["古來無此戰爭功，日日戈船卷海風。", "一遇靈鼇開睡眼，六朝灰盡九江空。"]'),
('yuding-49','長安縣廳','李洞','唐','御定全唐诗','yuding','','[]','主人寂寞客屯邅，愁絕終南滿案前。',32,'御定全唐詩/json/723.json','["主人寂寞客屯邅，愁絕終南滿案前。", "乞取中庭藤五尺，為君高劚扣青天。"]'),
('yuding-50','題晰上人賈島詩卷','李洞','唐','御定全唐诗','yuding','','[]','賈生詩卷惠休裝，百葉蓮花萬里香。',32,'御定全唐詩/json/723.json','["賈生詩卷惠休裝，百葉蓮花萬里香。", "供得半年吟不足，長須字字頂司倉。"]'),
('yuding-51','送僧清演歸山','李洞','唐','御定全唐诗','yuding','','[]','毛褐斜肩背負經，曉思吟入竇山青。',32,'御定全唐詩/json/723.json','["毛褐斜肩背負經，曉思吟入竇山青。", "峰前野水橫官道，踏著秋天三四星。"]'),
('yuding-52','贈僧','李洞','唐','御定全唐诗','yuding','','[]','不羨王公與貴人，唯將雲鶴自相親。',32,'御定全唐詩/json/723.json','["不羨王公與貴人，唯將雲鶴自相親。", "閑來石上觀流水，欲洗禪衣未有塵。"]'),
('yuding-53','題學公院池蓮','李洞','唐','御定全唐诗','yuding','','[]','竹引山泉玉甃池，栽蓮莫怪藕生絲。',32,'御定全唐詩/json/723.json','["竹引山泉玉甃池，栽蓮莫怪藕生絲。", "如何不似麻衣客，坐對秋風待一枝。"]'),
('yuding-54','山居喜友人見訪','李洞','唐','御定全唐诗','yuding','','[]','入雲晴劚茯苓還，日暮逢迎木石間。',32,'御定全唐詩/json/723.json','["入雲晴劚茯苓還，日暮逢迎木石間。", "看待詩人無別物，半潭秋水一房山。"]'),
('yuding-55','秋宿長安韋主簿廳','李洞','唐','御定全唐诗','yuding','','[]','水木清涼夜直廳，愁人樓上唱寒更。',32,'御定全唐詩/json/723.json','["水木清涼夜直廳，愁人樓上唱寒更。", "坐勞同步簾前月，鼠動床頭印鎖聲。"]'),
('yuding-56','冬憶友人','李洞','唐','御定全唐诗','yuding','','[]','吟上山前數竹枝，葉翻似雪落霏霏。',32,'御定全唐詩/json/723.json','["吟上山前數竹枝，葉翻似雪落霏霏。", "枕前明月誰動影，睡裏驚來不覺歸。"]'),
('yuding-57','懷圭峰影林泉','李洞','唐','御定全唐诗','yuding','','[]','吾家舊物賈生傳，入內遙分錫杖泉。',32,'御定全唐詩/json/723.json','["吾家舊物賈生傳，入內遙分錫杖泉。", "鶴去帝移宮女散，更堪嗚咽過樓前。"]'),
('yuding-58','贈青龍印禪師','李洞','唐','御定全唐诗','yuding','','[]','雨澀秋刀剃雪時，庵前曾禮草堂師。',32,'御定全唐詩/json/723.json','["雨澀秋刀剃雪時，庵前曾禮草堂師。", "居人昨日相過說，鶴已生孫竹滿池。"]'),
('yuding-59','戲贈侯常侍','李洞','唐','御定全唐诗','yuding','','[]','葛洪卷與江淹賦，名動天邊傲石居。',32,'御定全唐詩/json/723.json','["葛洪卷與江淹賦，名動天邊傲石居。", "兩蜀詞人多載後，同君諱卻馬相如。"]'),
('yuding-60','繡嶺宮詞','李洞','唐','御定全唐诗','yuding','','[]','春日遲遲春草綠，野棠開盡飄香玉。',32,'御定全唐詩/json/723.json','["春日遲遲春草綠，野棠開盡飄香玉。", "繡嶺宮前鶴發翁，猶唱開元太平曲。"]'),
('yuding-61','中秋月','李洞','唐','御定全唐诗','yuding','','[]','九十日秋色，今秋已半分。孤光吞列宿，四面絕微雲。',48,'御定全唐詩/json/723.json','["九十日秋色，今秋已半分。孤光吞列宿，四面絕微雲。", "眾木排疏影，寒流疊細紋。遙遙望丹桂，心緒更紛紛。"]'),
('yuding-62','宿書僧院','李洞','唐','御定全唐诗','yuding','','[]','夜水筆前澄，時推外學能。書成百個字，庭轉幾遭燈。',48,'御定全唐詩/json/723.json','["夜水筆前澄，時推外學能。書成百個字，庭轉幾遭燈。", "寄墨大壇吏，分箋蜀國僧。為題江寺塔，牌掛入雲層。"]'),
('yuding-63','雪','李洞','唐','御定全唐诗','yuding','','[]','迢迢來極塞，連闕謂風吹。禪客呵金錫，征人擘凍旗。',96,'御定全唐詩/json/723.json','["迢迢來極塞，連闕謂風吹。禪客呵金錫，征人擘凍旗。", "細填蟲穴滿，重壓鶴巢欹。有影晴飄野，無聲夜落池。", "正繁秦甸暖，漸厚楚宮饑。凍挹分泉澀，光凝二閣癡。", "踏遺蘭署跡，聽起石門思。用表豐年瑞，無令掃玉墀。"]'),
('yuding-64','述懷二十韻獻覃懷相公','李洞','唐','御定全唐诗','yuding','','[]','帝夢求良弼，生申屬聖明。青雲縣器業，白日貫忠貞。',240,'御定全唐詩/json/723.json','["帝夢求良弼，生申屬聖明。青雲縣器業，白日貫忠貞。", "靄靄隨春動，忻忻共物榮。靜宜浮競息，坐覺好風生。", "萬國聞應躍，千門望盡傾。瑞含楊柳色，氣變管弦聲。", "百辟尋知度，三階正有程。魯儒規蘊藉，周誥美和平。", "碧水遺幽抱，朱絲寄遠情。風流秦印綬，儀錶漢公卿。", "忠讜期登用，回邪自震驚。雲開長劍倚，路絕一峰橫。", "九野方無事，滄溟本不爭。國將身共計，心與眾為城。", "早晚中條下，紅塵一顧清。南潭容伴鶴，西笑忽遷鶯。", "折樹恩難報，懷仁命甚輕。二年猶困辱，百口望經營。", "未在英侯選，空勞短羽征。知音初相國，從此免長鳴。"]'),
('yuding-65','歲暮自廣江至新興往復中題峽山寺','李洞','唐','御定全唐诗','yuding','','[]','薄暮緣西峽，停橈一訪僧。鷺巢行臥柳，猿飲倒垂藤。',72,'御定全唐詩/json/723.json','["薄暮緣西峽，停橈一訪僧。鷺巢行臥柳，猿飲倒垂藤。", "水曲岩千疊，雲深樹百層。山風寒殿磬，溪雨夜船燈。", "灘漲危槎沒，泉沖怪石崩。中台一襟淚，歲杪別良朋。"]'),
('yuding-66','冬日送涼州刺史','李洞','唐','御定全唐诗','yuding','','[]','寵餞西門外，雙旌出漢陵。未辭金殿日，已夢雪山燈。',120,'御定全唐詩/json/723.json','["寵餞西門外，雙旌出漢陵。未辭金殿日，已夢雪山燈。", "地遠終峰盡，天寒朔氣凝。新年行已到，舊典聽難勝。", "吏掃盤雕影，人遮散馬乘。移軍駝馱角，下塞掾河冰。", "獵近昆侖獸，吟招磧石僧。重輸右藏實，方見左車能。", "兵聚邊風急，城寬夜月澄。連營煙火嶺，望詔幾回登。"]'),
('yuding-67','過賈浪仙舊地','李洞','唐','御定全唐诗','yuding','','[]','鶴外唐來有謫星，長江東注冷滄溟。境搜松雪仙人島，',40,'御定全唐詩/json/723.json','["鶴外唐來有謫星，長江東注冷滄溟。境搜松雪仙人島，", "年年誰不登高第，未勝騎驢入畫屏。"]'),
('yuding-68','句','李洞','唐','御定全唐诗','yuding','','[]','公道此時如不得，昭陵慟哭一生休。（《北夢瑣言》雲：',61,'御定全唐詩/json/723.json','["公道此時如不得，昭陵慟哭一生休。（《北夢瑣言》雲：", "洞三榜，裴贄第二榜。策夜，簾前獻詩云云。尋卒蜀中。", "贄無子，人謂屈洞所致）"]'),
('yuding-0','酬友生早秋','唐求','唐','御定全唐诗','yuding','','[]','彤雲將欲罷，蟬柳響如秋。霧散九霄近，日程三伏愁。',48,'御定全唐詩/json/724.json','["彤雲將欲罷，蟬柳響如秋。霧散九霄近，日程三伏愁。", "殘陽宿雨霽，高浪碎沙漚。袪足餘旬後，分襟任自由。"]'),
('yuding-1','曉發','唐求','唐','御定全唐诗','yuding','','[]','旅館候天曙，整車趨遠程。幾處曉鐘斷，半橋殘月明。',48,'御定全唐詩/json/724.json','["旅館候天曙，整車趨遠程。幾處曉鐘斷，半橋殘月明。", "沙上鳥猶在，渡頭人未行。去去古時道，馬嘶三兩聲。"]'),
('yuding-2','客行','唐求','唐','御定全唐诗','yuding','','[]','上山下山去，千里萬里愁。樹色野橋暝，雨聲孤館秋。',48,'御定全唐詩/json/724.json','["上山下山去，千里萬里愁。樹色野橋暝，雨聲孤館秋。", "南北眼前道，東西江畔舟。世人重金玉，無金徒遠遊。"]'),
('yuding-3','題鄭處士隱居','唐求','唐','御定全唐诗','yuding','','[]','不信最清曠，及來愁已空。數點石泉雨，一溪霜葉風。',48,'御定全唐詩/json/724.json','["不信最清曠，及來愁已空。數點石泉雨，一溪霜葉風。", "業在有山處，道成無事中。酌盡一尊酒，病夫顏亦紅。"]'),
('yuding-4','古寺','唐求','唐','御定全唐诗','yuding','','[]','路傍古時寺，寥落藏金容。破塔有寒草，壞樓無曉鐘。',48,'御定全唐詩/json/724.json','["路傍古時寺，寥落藏金容。破塔有寒草，壞樓無曉鐘。", "亂紙失經偈，斷碑分篆蹤。日暮月光吐，繞門千樹松。"]'),
('yuding-5','贈著上人','唐求','唐','御定全唐诗','yuding','','[]','掩門江上住，盡日更無為。古木坐禪處，殘星鳴磬時。',48,'御定全唐詩/json/724.json','["掩門江上住，盡日更無為。古木坐禪處，殘星鳴磬時。", "水澆冰滴滴，珠數落累累。自有閑行伴，青藤杖一枝。"]'),
('yuding-6','馬嵬感事','唐求','唐','御定全唐诗','yuding','','[]','冷氣生深殿，狼星渡遠關。九城鼙鼓內，千騎道途間。',48,'御定全唐詩/json/724.json','["冷氣生深殿，狼星渡遠關。九城鼙鼓內，千騎道途間。", "鳳髻隨秋草，鸞輿入暮山。恨多留不得，悲淚滿龍顏。"]'),
('yuding-7','贈行如上人','唐求','唐','御定全唐诗','yuding','','[]','不知名利苦，念佛老岷峨。衲補雲千片，香燒印一窠。',48,'御定全唐詩/json/724.json','["不知名利苦，念佛老岷峨。衲補雲千片，香燒印一窠。", "戀山人事少，憐客道心多。日日齋鐘後，高懸濾水羅。"]'),
('yuding-8','送友人歸邛州','唐求','唐','御定全唐诗','yuding','','[]','鶴鳴山下去，滿篋荷瑤琨。放馬荒田草，看碑古寺門。',48,'御定全唐詩/json/724.json','["鶴鳴山下去，滿篋荷瑤琨。放馬荒田草，看碑古寺門。", "漸寒沙上雨，欲暝水邊村。莫忘分襟處，梅花撲酒尊。"]'),
('yuding-9','和舒上人山居即事','唐求','唐','御定全唐诗','yuding','','[]','敗葉填溪路，殘陽過野亭。仍彈一滴水，更讀兩張經。',48,'御定全唐詩/json/724.json','["敗葉填溪路，殘陽過野亭。仍彈一滴水，更讀兩張經。", "暝鳥煙中見，寒鐘竹裏聽。不多山下去，人世盡膻腥。"]'),
('yuding-10','發邛州寄友人','唐求','唐','御定全唐诗','yuding','','[]','茫茫驅一馬，自歎又何之。出郭見山處，待船逢雨時。',48,'御定全唐詩/json/724.json','["茫茫驅一馬，自歎又何之。出郭見山處，待船逢雨時。", "曉雞鳴野店，寒葉墮秋枝。寂寞前程去，閑吟欲共誰。"]'),
('yuding-11','舟行夜泊夔州','唐求','唐','御定全唐诗','yuding','','[]','維舟鏡面中，迥對白鹽峰。夜靜沙堤月，天寒水寺鐘。',48,'御定全唐詩/json/724.json','["維舟鏡面中，迥對白鹽峰。夜靜沙堤月，天寒水寺鐘。", "故園何日到，舊友幾時逢。欲作還家夢，青山一萬重。"]'),
('yuding-12','山東蘭若遇靜公夜歸','唐求','唐','御定全唐诗','yuding','','[]','松門一徑微，苔滑往來稀。半夜聞鐘後，渾身帶雪歸。',48,'御定全唐詩/json/724.json','["松門一徑微，苔滑往來稀。半夜聞鐘後，渾身帶雪歸。", "問寒僧接杖，辨語犬銜衣。又是安禪去，呼童閉竹扉。"]'),
('yuding-13','邊將','唐求','唐','御定全唐诗','yuding','','[]','三千護塞兒，獨自滯邊陲。老向二毛見，秋從一葉知。',48,'御定全唐詩/json/724.json','["三千護塞兒，獨自滯邊陲。老向二毛見，秋從一葉知。", "地寒鄉思苦，天暮角聲悲。卻被交親笑，封侯未有期。"]'),
('yuding-14','秋寄□江舒公','唐求','唐','御定全唐诗','yuding','','[]','故人何處望，秋色滿江濆。入水溪蟲亂，過橋山路分。',48,'御定全唐詩/json/724.json','["故人何處望，秋色滿江濆。入水溪蟲亂，過橋山路分。", "鶴歸松上月，僧入竹間雲。莫惜中宵磬，從教夢裏聞。"]'),
('yuding-15','題楊山人隱居','唐求','唐','御定全唐诗','yuding','','[]','深山道者家，門戶帶煙霞。綠綴沿岩草，紅飄落水花。',48,'御定全唐詩/json/724.json','["深山道者家，門戶帶煙霞。綠綴沿岩草，紅飄落水花。", "半庭栽小樹，一徑掃平沙。往往溪邊坐，持竿到日斜。"]'),
('yuding-16','夜上隱居寺','唐求','唐','御定全唐诗','yuding','','[]','尋師擬學空，空住虎溪東。千里照山月，一枝驚鶴風。',48,'御定全唐詩/json/724.json','["尋師擬學空，空住虎溪東。千里照山月，一枝驚鶴風。", "年如流去水，山似轉來蓬。盡日都無事，安禪石窟中。"]'),
('yuding-17','友人見訪不值因寄','唐求','唐','御定全唐诗','yuding','','[]','門戶寒江近，籬牆野樹深。晚風搖竹影，斜日轉山陰。',48,'御定全唐詩/json/724.json','["門戶寒江近，籬牆野樹深。晚風搖竹影，斜日轉山陰。", "砌覺披秋草，床驚倒古琴。更聞鄰舍說，一隻鶴來尋。"]'),
('yuding-18','塗次偶作','唐求','唐','御定全唐诗','yuding','','[]','歲月客中銷，崎嶇力自招。問人尋野寺，牽馬渡危橋。',48,'御定全唐詩/json/724.json','["歲月客中銷，崎嶇力自招。問人尋野寺，牽馬渡危橋。", "為雨疑天晚，因山覺路遙。前程何處是，一望又迢迢。"]'),
('yuding-19','送友人江行之廬山肄業','唐求','唐','御定全唐诗','yuding','','[]','蜀國初開棹，廬峰擬拾螢。獸皮裁褥暖，蓮葉制衣馨。',48,'御定全唐詩/json/724.json','["蜀國初開棹，廬峰擬拾螢。獸皮裁褥暖，蓮葉制衣馨。", "楚水秋來碧，巫山雨後青。莫教銜鳳詔，三度到中庭。"]'),
('yuding-20','山居偶作','唐求','唐','御定全唐诗','yuding','','[]','趨名逐利身，終日走風塵。還到水邊宅，卻為山下人。',48,'御定全唐詩/json/724.json','["趨名逐利身，終日走風塵。還到水邊宅，卻為山下人。", "僧教開竹戶，客許戴紗巾。且喜琴書在，蘇生未厭貧。"]'),
('yuding-21','贈道者','唐求','唐','御定全唐诗','yuding','','[]','披霞戴鹿胎，歲月不能催。飯把琪花煮，衣將藕葉裁。',48,'御定全唐詩/json/724.json','["披霞戴鹿胎，歲月不能催。飯把琪花煮，衣將藕葉裁。", "鶴從歸日養，松是小時栽。往往樵人見，溪邊洗藥來。"]'),
('yuding-22','邛州水亭夜宴送顧非熊之官','唐求','唐','御定全唐诗','yuding','','[]','寂寞邛城夜，寒塘對庾樓。蜀關蟬已噪，秦樹葉應秋。',48,'御定全唐詩/json/724.json','["寂寞邛城夜，寒塘對庾樓。蜀關蟬已噪，秦樹葉應秋。", "道路連天遠，笙歌到曉愁。不堪分袂後，殘月正如鉤。"]'),
('yuding-23','題青城山範賢觀','唐求','唐','御定全唐诗','yuding','','[]','數裏緣山不厭難，為尋真訣問黃冠。苔鋪翠點仙橋滑，',40,'御定全唐詩/json/724.json','["數裏緣山不厭難，為尋真訣問黃冠。苔鋪翠點仙橋滑，", "鐘聲已斷泉聲在，風動茅花月滿壇。"]'),
('yuding-24','送僧講罷歸山','唐求','唐','御定全唐诗','yuding','','[]','休將如意辯真空，吹盡天花任曉風。共看玉蟾三皎潔，',40,'御定全唐詩/json/724.json','["休將如意辯真空，吹盡天花任曉風。共看玉蟾三皎潔，", "依舊曹溪念經處，野泉聲在草堂東。"]'),
('yuding-25','題友人寓居','唐求','唐','御定全唐诗','yuding','','[]','寓居無不在天涯，莫恨秦關道路賒。繚繞城邊山是蜀，',40,'御定全唐詩/json/724.json','["寓居無不在天涯，莫恨秦關道路賒。繚繞城邊山是蜀，", "何處一聲金磬發，古松南畔有僧家。"]'),
('yuding-26','傷張玖秀才','唐求','唐','御定全唐诗','yuding','','[]','銅梁劍閣幾區區，十上探珠不見珠。卞玉影沈沙草暗，',40,'御定全唐詩/json/724.json','["銅梁劍閣幾區區，十上探珠不見珠。卞玉影沈沙草暗，", "吳水楚山千萬里，旅魂歸到故鄉無。"]'),
('yuding-27','題李少府別業','唐求','唐','御定全唐诗','yuding','','[]','尋得仙家不姓梅，馬嘶人語出塵埃。竹和庭上春煙動，',40,'御定全唐詩/json/724.json','["尋得仙家不姓梅，馬嘶人語出塵埃。竹和庭上春煙動，", "何年亦作圍棋伴，一到松間醉一回。"]'),
('yuding-28','贈楚公','唐求','唐','御定全唐诗','yuding','','[]','曾聞半偈雪山中，貝葉翻時理盡通。般若恒添持戒力，',40,'御定全唐詩/json/724.json','["曾聞半偈雪山中，貝葉翻時理盡通。般若恒添持戒力，", "長說滿庭花色好，一枝紅是一枝空。"]'),
('yuding-29','贈王山人','唐求','唐','御定全唐诗','yuding','','[]','紅藤一柱腳常輕，日日緣溪入穀行。山下有家身未老，',40,'御定全唐詩/json/724.json','["紅藤一柱腳常輕，日日緣溪入穀行。山下有家身未老，", "知到蓬萊難再訪，問何方法得長生。"]'),
('yuding-30','庭竹','唐求','唐','御定全唐诗','yuding','','[]','月籠翠葉秋承露，風亞繁梢暝掃煙。',32,'御定全唐詩/json/724.json','["月籠翠葉秋承露，風亞繁梢暝掃煙。", "知道雪霜終不變，永留寒色在庭前。"]'),
('yuding-31','題常樂寺','唐求','唐','御定全唐诗','yuding','','[]','桂冷香聞十里間，殿台渾不似人寰。',32,'御定全唐詩/json/724.json','["桂冷香聞十里間，殿台渾不似人寰。", "日斜回首江頭望，一片晴雲落後山。"]'),
('yuding-32','題劉煉師歸山','唐求','唐','御定全唐诗','yuding','','[]','風急雲輕鶴背寒，洞天誰道卻歸難。',32,'御定全唐詩/json/724.json','["風急雲輕鶴背寒，洞天誰道卻歸難。", "千山萬水瀛洲路，何處煙飛是醮壇。"]'),
('yuding-33','酬舒公見寄','唐求','唐','御定全唐诗','yuding','','[]','無客不言雲外見，為文長遣世間知。',32,'御定全唐詩/json/724.json','["無客不言雲外見，為文長遣世間知。", "一聲松徑寒吟後，正是前山雪下時。"]'),
('yuding-34','巫山下作','唐求','唐','御定全唐诗','yuding','','[]','細腰宮盡舊城摧，神女歸山更不來。',32,'御定全唐詩/json/724.json','["細腰宮盡舊城摧，神女歸山更不來。", "唯有楚江斜日裏，至今猶自繞陽臺。"]'),
('yuding-35','句','唐求','唐','御定全唐诗','yuding','','[]','恰似有龍深處臥，被人驚起黑雲生。（《臨池洗硯》，',24,'御定全唐詩/json/724.json','["恰似有龍深處臥，被人驚起黑雲生。（《臨池洗硯》，"]'),
('yuding-0','書懷','于鄴','唐','御定全唐诗','yuding','','[]','長安多路岐，西去欲何依。浮世只如此，舊山長憶歸。',48,'御定全唐詩/json/725.json','["長安多路岐，西去欲何依。浮世只如此，舊山長憶歸。", "自離京國久，應已故人稀。好與孤雲住，孤雲無是非。"]'),
('yuding-1','書情','於鄴','唐','御定全唐诗','yuding','','[]','負郭有田在，年年長廢耕。欲磨秋鏡淨，恐見白頭生。',48,'御定全唐詩/json/725.json','["負郭有田在，年年長廢耕。欲磨秋鏡淨，恐見白頭生。", "未作一旬別，已過千里程。不知書與劍，十載兩無成。"]'),
('yuding-2','塗中作','於鄴','唐','御定全唐诗','yuding','','[]','西南千里程，處處有車聲。若使地無利，始應人不營。',48,'御定全唐詩/json/725.json','["西南千里程，處處有車聲。若使地無利，始應人不營。", "天涯猶馬到，石跡尚塵生。如此未曾息，蜀山終冀平。"]'),
('yuding-3','春過函谷關','於鄴','唐','御定全唐诗','yuding','','[]','幾度作遊客，客行長苦辛。愁看函谷路，老盡布衣人。',48,'御定全唐詩/json/725.json','["幾度作遊客，客行長苦辛。愁看函谷路，老盡布衣人。", "歲遠關猶固，時移草亦春。何當名利息，遣此絕征輪。"]'),
('yuding-4','褒中即事','於鄴','唐','御定全唐诗','yuding','','[]','風吹殘雨歇，雲去有煙霞。南浦足遊女，綠蘋應發花。',48,'御定全唐詩/json/725.json','["風吹殘雨歇，雲去有煙霞。南浦足遊女，綠蘋應發花。", "遠鐘當半夜，明月入千家。不作故鄉夢，始知京洛賒。"]'),
('yuding-5','歲暮還家','於鄴','唐','御定全唐诗','yuding','','[]','東西流不駐，白日與車輪。殘雪半成水，微風應欲春。',48,'御定全唐詩/json/725.json','["東西流不駐，白日與車輪。殘雪半成水，微風應欲春。", "幾經他國歲，已減故鄉人。回首長安道，十年空苦辛。"]'),
('yuding-6','還家','於鄴','唐','御定全唐诗','yuding','','[]','為客憶歸舍，歸來還寂寥。壯時看欲過，白首固非遙。',48,'御定全唐詩/json/725.json','["為客憶歸舍，歸來還寂寥。壯時看欲過，白首固非遙。", "獨酌幾回醉，此愁終不銷。猶殘雞與犬，驅去住山椒。"]'),
('yuding-7','題華山麻處士所居','於鄴','唐','御定全唐诗','yuding','','[]','貴賤各擾擾，皆逢朝市間。到此馬無跡，始知君獨閑。',48,'御定全唐詩/json/725.json','["貴賤各擾擾，皆逢朝市間。到此馬無跡，始知君獨閑。", "冰破聽敷水，雪晴看華山。西風寂寥地，唯我坐忘還。"]'),
('yuding-8','天南懷故人','于鄴','唐','御定全唐诗','yuding','','[]','獨行千里塵，軋軋轉征輪。一別已多日，總看成老人。',48,'御定全唐詩/json/725.json','["獨行千里塵，軋軋轉征輪。一別已多日，總看成老人。", "洞庭雪不下，故國草應春。三月煙波暖，南風生綠蘋。"]'),
('yuding-9','路傍草','於鄴','唐','御定全唐诗','yuding','','[]','春至始青青，香車碾已平。不知山下處，來向路傍生。',48,'御定全唐詩/json/725.json','["春至始青青，香車碾已平。不知山下處，來向路傍生。", "每歲有人在，何時無馬行。應隨塵與土，吹滿洛陽城。"]'),
('yuding-10','秋夕聞雁','於鄴','唐','御定全唐诗','yuding','','[]','星漢欲沈盡，誰家砧未休。忽聞涼雁至，如報杜陵秋。',48,'御定全唐詩/json/725.json','["星漢欲沈盡，誰家砧未休。忽聞涼雁至，如報杜陵秋。", "千樹又黃葉，幾人新白頭。洞庭今夜客，一半卻登舟。"]'),
('yuding-11','洛中有懷','於鄴','唐','御定全唐诗','yuding','','[]','潺潺伊洛河，寂寞少恩波。鑾駕久不幸，洛陽春草多。',24,'御定全唐詩/json/725.json','["潺潺伊洛河，寂寞少恩波。鑾駕久不幸，洛陽春草多。"]'),
('yuding-12','送魏山韋處士','于鄴','唐','御定全唐诗','yuding','','[]','陰陰亭際間，相顧慘離顏。一片雲飛去，嵯峨空魏山。',24,'御定全唐詩/json/725.json','["陰陰亭際間，相顧慘離顏。一片雲飛去，嵯峨空魏山。"]'),
('yuding-13','白櫻桃','于鄴','唐','御定全唐诗','yuding','','[]','王母階前種幾株，水晶簾內看如無。',32,'御定全唐詩/json/725.json','["王母階前種幾株，水晶簾內看如無。", "只應漢武金盤上，瀉得珊珊白露珠。"]'),
('yuding-14','白櫻樹','於鄴','唐','御定全唐诗','yuding','','[]','記得花開雪滿枝，和蜂和蝶帶花移。',32,'御定全唐詩/json/725.json','["記得花開雪滿枝，和蜂和蝶帶花移。", "如今花落遊蜂去，空作主人惆悵詩。"]'),
('yuding-15','下第不勝其忿題路左佛廟','於鄴','唐','御定全唐诗','yuding','','[]','雀兒未逐颺風高，下視鷹鸇意氣豪。',32,'御定全唐詩/json/725.json','["雀兒未逐颺風高，下視鷹鸇意氣豪。", "自謂能生千里足，黃昏依舊委蓬蒿。"]'),
('yuding-16','感懷','于鄴','唐','御定全唐诗','yuding','','[]','東風吹草色，空使客蹉跎。不設太平險，更應遊子多。',48,'御定全唐詩/json/725.json','["東風吹草色，空使客蹉跎。不設太平險，更應遊子多。", "幾傷行處淚，一曲醉中歌。盡向青門外，東隨渭水波。"]'),
('yuding-17','遊中梁山','於鄴','唐','御定全唐诗','yuding','','[]','僻地好泉石，何人曾陸沈。不知青嶂外，更有白雲深。',48,'御定全唐詩/json/725.json','["僻地好泉石，何人曾陸沈。不知青嶂外，更有白雲深。", "因此見喬木，幾回思舊林。殷勤猿與鳥，唯我獨何心。"]'),
('yuding-18','尋山','於鄴','唐','御定全唐诗','yuding','','[]','到此絕車輪，萋萋草樹春。青山如有利，白石亦成塵。',48,'御定全唐詩/json/725.json','["到此絕車輪，萋萋草樹春。青山如有利，白石亦成塵。", "水闊應無路，松深不見人。如知巢與許，千載跡猶新。"]'),
('yuding-19','宿江口','于鄴','唐','御定全唐诗','yuding','','[]','南渡人來絕，喧喧雁滿沙。自生江上月，長有客思家。',48,'御定全唐詩/json/725.json','["南渡人來絕，喧喧雁滿沙。自生江上月，長有客思家。", "半夜下霜岸，北風吹荻花。自驚歸夢斷，不得到天涯。"]'),
('yuding-20','秋夜達蕭關','於鄴','唐','御定全唐诗','yuding','','[]','擾擾浮梁路，人忙月自閑。去年為塞客，今夜宿蕭關。',48,'御定全唐詩/json/725.json','["擾擾浮梁路，人忙月自閑。去年為塞客，今夜宿蕭關。", "辭國幾經歲，望鄉空見山。不知江葉下，又作布衣還。"]'),
('yuding-21','斜谷道','於鄴','唐','御定全唐诗','yuding','','[]','亂峰連疊嶂，千里綠峨峨。蜀國路如此，遊人車亦過。',48,'御定全唐詩/json/725.json','["亂峰連疊嶂，千里綠峨峨。蜀國路如此，遊人車亦過。", "遠煙當驛斂，驟雨逐風多。獨憶紫芝叟，臨風歌舊歌。"]'),
('yuding-22','過百牢關貽舟中者','於鄴','唐','御定全唐诗','yuding','','[]','蜀國少平地，方思京洛間。遠為千里客，來度百牢關。',48,'御定全唐詩/json/725.json','["蜀國少平地，方思京洛間。遠為千里客，來度百牢關。", "帆影清江水，鈴聲碧草山。不因名與利，爾我各應閑。"]'),
('yuding-23','客中覽鏡','于鄴','唐','御定全唐诗','yuding','','[]','何當開此鏡，即見發如絲。白日急於水，少年能幾時。',48,'御定全唐詩/json/725.json','["何當開此鏡，即見發如絲。白日急於水，少年能幾時。", "每逢芳草處，長返故園遲。所以多為客，蹉跎欲怨誰。"]'),
('yuding-24','長安逢隱者','於鄴','唐','御定全唐诗','yuding','','[]','征車千里至，碾遍六街塵。向此有營地，忽逢無事人。',48,'御定全唐詩/json/725.json','["征車千里至，碾遍六街塵。向此有營地，忽逢無事人。", "昔時顏未改，浮世路多新。且脫衣沽酒，終南山欲春。"]'),
('yuding-25','與僧話舊','於鄴','唐','御定全唐诗','yuding','','[]','草堂前有山，一見一相寬。處世貴僧靜，青松因歲寒。',48,'御定全唐詩/json/725.json','["草堂前有山，一見一相寬。處世貴僧靜，青松因歲寒。", "他山逢舊侶，盡日話長安。所以閑行跡，千回繞藥欄。"]'),
('yuding-26','贈王道士','于鄴','唐','御定全唐诗','yuding','','[]','日日市朝路，何時無苦辛。不隨丹灶客，終作白頭人。',48,'御定全唐詩/json/725.json','["日日市朝路，何時無苦辛。不隨丹灶客，終作白頭人。", "浮世度千載，桃源方一春。歸來華表上，應笑北邙塵。"]'),
('yuding-27','匣中琴','于鄴','唐','御定全唐诗','yuding','','[]','世人無正心，蟲網匣中琴。何以經時廢，非為娛耳音。',48,'御定全唐詩/json/725.json','["世人無正心，蟲網匣中琴。何以經時廢，非為娛耳音。", "獨令高韻在，誰感隙塵深。應是南風曲，聲聲不合今。"]'),
('yuding-28','友人亭松','於鄴','唐','御定全唐诗','yuding','','[]','俯仰不能去，如逢舊友同。曾因春雪散，見在華山中。',48,'御定全唐詩/json/725.json','["俯仰不能去，如逢舊友同。曾因春雪散，見在華山中。", "何處有明月，訪君聽遠風。相將歸未得，各占石岩東。"]'),
('yuding-29','過洛陽城','於鄴','唐','御定全唐诗','yuding','','[]','古來利與名，俱在洛陽城。九陌鼓初起，萬車輪已行。',48,'御定全唐詩/json/725.json','["古來利與名，俱在洛陽城。九陌鼓初起，萬車輪已行。", "周秦時幾變，伊洛水猶清。二月中橋路，鳥啼春草生。"]'),
('yuding-30','客中月','於鄴','唐','御定全唐诗','yuding','','[]','離家凡幾宵，一望一寥寥。新魄又將滿，故鄉應漸遙。',48,'御定全唐詩/json/725.json','["離家凡幾宵，一望一寥寥。新魄又將滿，故鄉應漸遙。", "獨臨彭蠡水，遠憶洛陽橋。更有乘舟客，淒然亦駐橈。"]'),
('yuding-31','王將軍宅夜聽歌','于鄴','唐','御定全唐诗','yuding','','[]','朱檻滿明月，美人歌落梅。忽驚塵起處，疑有鳳飛來。',48,'御定全唐詩/json/725.json','["朱檻滿明月，美人歌落梅。忽驚塵起處，疑有鳳飛來。", "一曲聽初徹，幾年愁暫開。東南正雲雨，不得見陽臺。"]'),
('yuding-32','長信宮','于鄴','唐','御定全唐诗','yuding','','[]','莫問古宮名，古宮空有城。惟應東去水，不改舊時聲。',24,'御定全唐詩/json/725.json','["莫問古宮名，古宮空有城。惟應東去水，不改舊時聲。"]'),
('yuding-33','高樓','於鄴','唐','御定全唐诗','yuding','','[]','遠天明月出，照此誰家樓。上有羅衣裳，涼風吹不休。',24,'御定全唐詩/json/725.json','["遠天明月出，照此誰家樓。上有羅衣裳，涼風吹不休。"]'),
('yuding-0','和三鄉詩','陸貞洞','唐','御定全唐诗','yuding','','[]','惆悵殘花怨暮春，孤鸞舞鏡倍傷神。',32,'御定全唐詩/json/726.json','["惆悵殘花怨暮春，孤鸞舞鏡倍傷神。", "清詞好個幹人事，疑是文姬第二身。"]'),
('yuding-1','和三鄉詩','劉谷','唐','御定全唐诗','yuding','','[]','蘭蕙芬香見玉姿，路傍花笑景遲遲。',32,'御定全唐詩/json/726.json','["蘭蕙芬香見玉姿，路傍花笑景遲遲。", "苧蘿山下無窮意，並在三鄉惜別時。"]'),
('yuding-2','和三鄉詩','王祝','唐','御定全唐诗','yuding','','[]','女幾山前嵐氣低，佳人留恨此中題。',32,'御定全唐詩/json/726.json','["女幾山前嵐氣低，佳人留恨此中題。", "不知雲雨歸何處，空使王孫見即迷。"]'),
('yuding-3','和三鄉詩','王滌','唐','御定全唐诗','yuding','','[]','浣紗遊女出關東，舊跡新詞一夢中。',32,'御定全唐詩/json/726.json','["浣紗遊女出關東，舊跡新詞一夢中。", "槐陌柳亭何限事，年年回首向春風。"]'),
('yuding-4','和三鄉詩','韋冰','唐','御定全唐诗','yuding','','[]','來時歡笑去時哀，家國迢迢向越台。',32,'御定全唐詩/json/726.json','["來時歡笑去時哀，家國迢迢向越台。", "待寫百年幽思盡，故宮流水莫相催。"]'),
('yuding-5','和三鄉詩','李昌鄴','唐','御定全唐诗','yuding','','[]','紅粉蕭娘手自題，分明幽怨發雲閨。',32,'御定全唐詩/json/726.json','["紅粉蕭娘手自題，分明幽怨發雲閨。", "不應更學文君去，泣向殘花歸剡溪。"]'),
('yuding-6','和三鄉詩','王碩','唐','御定全唐诗','yuding','','[]','無姓無名越水濱，芳詞空怨路傍人。',32,'御定全唐詩/json/726.json','["無姓無名越水濱，芳詞空怨路傍人。", "莫教才子偏惆悵，宋玉東家是舊鄰。"]'),
('yuding-7','和三鄉詩','李縞','唐','御定全唐诗','yuding','','[]','會稽王謝兩風流，王子沉淪謝女愁。',32,'御定全唐詩/json/726.json','["會稽王謝兩風流，王子沉淪謝女愁。", "歸思若隨文字在，路傍空為感千秋。"]'),
('yuding-8','和三鄉詩','張綺','唐','御定全唐诗','yuding','','[]','洛川依舊好風光，蓮帳無因見女郎。',32,'御定全唐詩/json/726.json','["洛川依舊好風光，蓮帳無因見女郎。", "雲雨散來音信斷，此生遺恨寄三鄉。"]'),
('yuding-9','和三鄉詩','高衢','唐','御定全唐诗','yuding','','[]','南北千山與萬山，軒車誰不思鄉關。',32,'御定全唐詩/json/726.json','["南北千山與萬山，軒車誰不思鄉關。", "獨留芳翰悲前跡，陌上恐傷桃李顏。"]'),
('yuding-10','複睹三鄉題處留贈','賈馳','唐','御定全唐诗','yuding','','[]','壁古字未滅，聲長響不絕。蕙質本如雲，松心應耐雪。',48,'御定全唐詩/json/726.json','["壁古字未滅，聲長響不絕。蕙質本如雲，松心應耐雪。", "耿耿離幽谷，悠悠望甌越。杞婦哭夫時，城崩無此說。"]'),
('yuding-11','秋入關','賈馳','唐','御定全唐诗','yuding','','[]','河上微風來，關頭樹初濕。今朝關城吏，又見孤客入。',36,'御定全唐詩/json/726.json','["河上微風來，關頭樹初濕。今朝關城吏，又見孤客入。", "上國誰與期，西來徒自急。"]'),
('yuding-12','詠手二首','趙光遠','唐','御定全唐诗','yuding','','[]','妝成皓腕洗凝脂，背接紅巾掬水時。薄霧袖中拈玉斝，',80,'御定全唐詩/json/726.json','["妝成皓腕洗凝脂，背接紅巾掬水時。薄霧袖中拈玉斝，", "好是琵琶弦畔見，細圓無節玉參差。", "撚玉搓瓊軟複圓，綠窗誰見上琴弦。慢籠彩筆閒書字，", "象床珍簟宮棋處，拈定文楸占角邊。"]'),
('yuding-13','題妓萊兒壁','趙光遠','唐','御定全唐诗','yuding','','[]','魚鑰獸環斜掩門，萋萋芳草憶王孫。醉憑青瑣窺韓壽，',40,'御定全唐詩/json/726.json','["魚鑰獸環斜掩門，萋萋芳草憶王孫。醉憑青瑣窺韓壽，", "欲知腸斷相思處，役盡江淹別後魂。"]'),
('yuding-14','題興化高田院橋亭','鄭良士','唐','御定全唐诗','yuding','','[]','到此溪亭上，浮生始覺非。野僧還惜別，遊客亦忘歸。',48,'御定全唐詩/json/726.json','["到此溪亭上，浮生始覺非。野僧還惜別，遊客亦忘歸。", "月滿千岩靜，風清一磬微。何時脫塵役，杖履願相依。"]'),
('yuding-15','遊九鯉湖','鄭良士','唐','御定全唐诗','yuding','','[]','仄徑傾崖不可通，湖嵐林靄共溟蒙。九溪瀑影飛花外，',40,'御定全唐詩/json/726.json','["仄徑傾崖不可通，湖嵐林靄共溟蒙。九溪瀑影飛花外，", "我來不乞邯鄲夢，取醉聊乘鄭國風。"]'),
('yuding-16','寄富洋院禪者','鄭良士','唐','御定全唐诗','yuding','','[]','畫破青山路一條，走鞭飛蓋去何遙。礙天岩樹春先冷，',40,'御定全唐詩/json/726.json','["畫破青山路一條，走鞭飛蓋去何遙。礙天岩樹春先冷，", "誰能學得空門士，冷卻心灰守寂寥。"]'),
('yuding-17','贈翁承贊漆林書堂詩','蕭項','唐','御定全唐诗','yuding','','[]','軺車故國世應稀，昔日書堂二紀歸。手植松筠同茂盛，',40,'御定全唐詩/json/726.json','["軺車故國世應稀，昔日書堂二紀歸。手植松筠同茂盛，", "卻對芸窗勤苦處，舉頭全是錦為衣。"]'),
('yuding-0','喜韓少府見訪','胡令能','唐','御定全唐诗','yuding','','[]','忽聞梅福來相訪，笑著荷衣出草堂。',32,'御定全唐詩/json/727.json','["忽聞梅福來相訪，笑著荷衣出草堂。", "兒童不慣見車馬，走入蘆花深處藏。"]'),
('yuding-1','觀鄭州崔郎中諸妓繡樣','胡令能','唐','御定全唐诗','yuding','','[]','日暮堂前花蕊嬌，爭拈小筆上床描。',32,'御定全唐詩/json/727.json','["日暮堂前花蕊嬌，爭拈小筆上床描。", "繡成安向春園裏，引得黃鶯下柳條。"]'),
('yuding-2','小兒垂釣','胡令能','唐','御定全唐诗','yuding','','[]','蓬頭稚子學垂綸，側坐莓苔草映身。',32,'御定全唐詩/json/727.json','["蓬頭稚子學垂綸，側坐莓苔草映身。", "路人借問遙招手，怕得魚驚不應人。"]'),
('yuding-3','王昭君','胡令能','唐','御定全唐诗','yuding','','[]','胡風似劍鎪人骨，漢月如鉤釣胃腸。',32,'御定全唐詩/json/727.json','["胡風似劍鎪人骨，漢月如鉤釣胃腸。", "魂夢不知身在路，夜來猶自到昭陽。"]'),
('yuding-4','望夫石','嚴郾','唐','御定全唐诗','yuding','','[]','何代提戈去不還，獨留形影白雲間。肌膚銷盡雪霜色，',40,'御定全唐詩/json/727.json','["何代提戈去不還，獨留形影白雲間。肌膚銷盡雪霜色，", "近來豈少征人婦，笑采蘼蕪上北山。"]'),
('yuding-5','賦百舌鳥','嚴郾','唐','御定全唐诗','yuding','','[]','此禽輕巧少同倫，我聽長疑舌滿身。星未沒河先報曉，',40,'御定全唐詩/json/727.json','["此禽輕巧少同倫，我聽長疑舌滿身。星未沒河先報曉，", "莫倚春風便多事，玉樓還有晏眠人。"]'),
('yuding-6','永州陪鄭太守登舟夜宴，席上各賦詩','蔣肱','唐','御定全唐诗','yuding','','[]','江頭朱紱間青衿，豈是仙舟不可尋。誰敢強登徐稚榻，',40,'御定全唐詩/json/727.json','["江頭朱紱間青衿，豈是仙舟不可尋。誰敢強登徐稚榻，", "剪盡蠟紅人未覺，歸時城郭曉煙深。"]'),
('yuding-7','寄遠','張迥1','唐','御定全唐诗','yuding','','[]','錦字憑誰達，閒庭草又枯。夜長燈影滅，天遠雁聲孤。',48,'御定全唐詩/json/727.json','["錦字憑誰達，閒庭草又枯。夜長燈影滅，天遠雁聲孤。", "蟬鬢凋將盡，虯髯白也無。幾回愁不語，因看朔方圖。"]'),
('yuding-8','春草凝露','張友正','唐','御定全唐诗','yuding','','[]','蒼蒼芳草色，含露對青春。已賴陽和長，仍慚潤澤頻。',72,'御定全唐詩/json/727.json','["蒼蒼芳草色，含露對青春。已賴陽和長，仍慚潤澤頻。", "日臨殘未滴，風度欲成津。蕙葉垂偏重，蘭叢洗轉新。", "將行愁裛徑，欲采畏濡身。獨愛池塘畔，清華遠襲人。"]'),
('yuding-9','錦帶佩吳鉤','張友正','唐','御定全唐诗','yuding','','[]','帶劍誰家子，春朝紫陌遊。結邊霞聚錦，懸處月隨鉤。',72,'御定全唐詩/json/727.json','["帶劍誰家子，春朝紫陌遊。結邊霞聚錦，懸處月隨鉤。", "彩縷回文出，雄芒練影浮。葉依花裏豔，霜向鍔中秋。", "的皪宜驄馬，斕斒映綺裘。應須待報國，一刎月支頭。"]'),
('yuding-10','山中臥病寄盧郎中','伍唐珪','唐','御定全唐诗','yuding','','[]','十年耕釣水雲間，住僻家貧少往還。一徑綠苔凝曉露，',40,'御定全唐詩/json/727.json','["十年耕釣水雲間，住僻家貧少往還。一徑綠苔凝曉露，", "空戀舊時恩獎地，無因匍匐出柴關。"]'),
('yuding-11','寒食日獻郡守','伍唐珪','唐','御定全唐诗','yuding','','[]','入門堪笑複堪憐，三徑苔荒一釣船。',32,'御定全唐詩/json/727.json','["入門堪笑複堪憐，三徑苔荒一釣船。", "慚愧四鄰教斷火，不知廚裏久無煙。"]'),
('yuding-12','上蘇使君','伍唐珪','唐','御定全唐诗','yuding','','[]','江西昔日推韓注，袁水今朝數趙祥。',32,'御定全唐詩/json/727.json','["江西昔日推韓注，袁水今朝數趙祥。", "縱使文翁能待客，終栽桃李不成行。"]'),
('yuding-13','贈妓人王福娘','孫棨','唐','御定全唐诗','yuding','','[]','彩翠仙衣紅玉膚，輕盈年在破瓜初。霞杯醉勸劉郎賭，',40,'御定全唐詩/json/727.json','["彩翠仙衣紅玉膚，輕盈年在破瓜初。霞杯醉勸劉郎賭，", "謾圖西子晨妝樣，西子元來未得如。"]'),
('yuding-14','題妓王福娘牆','孫棨','唐','御定全唐诗','yuding','','[]','移壁回窗費幾朝，指鐶偷解博紅椒。',96,'御定全唐詩/json/727.json','["移壁回窗費幾朝，指鐶偷解博紅椒。", "無端鬥草輸鄰女，更被拈將玉步搖。", "寒繡衣裳餉阿嬌，新團香獸不禁燒。", "東鄰起樣裙腰闊，剩蹙黃金線幾條。", "試共卿卿語笑初，畫堂連遣侍兒呼。", "寒肌不耐金如意，白獺為膏郎有無。"]'),
('yuding-15','戲李文遠','孫棨','唐','御定全唐诗','yuding','','[]','引君來訪洞中仙，新月如眉拂戶前。',32,'御定全唐詩/json/727.json','["引君來訪洞中仙，新月如眉拂戶前。", "領取嫦娥攀取桂，便從陵谷一時遷。"]'),
('yuding-16','題劉泰娘舍','孫棨','唐','御定全唐诗','yuding','','[]','尋常凡木最輕樗，今日尋樗桂不如。',32,'御定全唐詩/json/727.json','["尋常凡木最輕樗，今日尋樗桂不如。", "漢高新破咸陽後，英俊奔波遂吃虛。"]'),
('yuding-17','戲張道人不飲酒','顏蕘','唐','御定全唐诗','yuding','','[]','言自雲山訪我來，每聞奇秘覺叨陪。',32,'御定全唐詩/json/727.json','["言自雲山訪我來，每聞奇秘覺叨陪。", "吾師不飲人間酒，應待流霞即舉杯。"]'),
('yuding-18','句','顏蕘','唐','御定全唐诗','yuding','','[]','爽籟盡成鳴鳳曲，遊人多是弄珠仙。',16,'御定全唐詩/json/727.json','["爽籟盡成鳴鳳曲，遊人多是弄珠仙。"]'),
('yuding-19','秋醉歌','張為','唐','御定全唐诗','yuding','','[]','金風颯已起，還是招漁翁。攜酒天姥岑，自彈嶧陽桐。',192,'御定全唐詩/json/727.json','["金風颯已起，還是招漁翁。攜酒天姥岑，自彈嶧陽桐。", "脫卻登山履，赤腳翹青筇。泉聲掃殘暑，猿臂攀長松。", "翠微泛樽綠，苔蘚分煙紅。造化處術內，相對數壺空。", "醉眠嶺上草，不覺夜露濃。一夢到天曉，始覺一醉中。", "皎然夢中路，直到瀛洲東。初平把我臂，相與騎白龍。", "三留對上帝，玉樓十二重。上帝賜我酒，送我敲金鐘。", "寶閣香斂苒，琪樹寒玲瓏。動葉如笙篁，音律相怡融。", "珍重此一醉，百骸出天地。長如此夢魂，永謝名與利。"]'),
('yuding-20','謝別毛仙翁','張為','唐','御定全唐诗','yuding','','[]','羸形感神藥，削骨生豐肌。蘭炷飄靈煙，妖怪立誅夷。',60,'御定全唐詩/json/727.json','["羸形感神藥，削骨生豐肌。蘭炷飄靈煙，妖怪立誅夷。", "重睹日月光，何報父母慈。黃河濁袞袞，別淚流澌澌。", "黃河清有時，別淚無收期。"]'),
('yuding-21','漁陽將軍','張為','唐','御定全唐诗','yuding','','[]','霜髭擁頷對窮秋，著白貂裘獨上樓。',32,'御定全唐詩/json/727.json','["霜髭擁頷對窮秋，著白貂裘獨上樓。", "向北望星提劍立，一生長為國家憂。"]'),
('yuding-22','句','張為','唐','御定全唐诗','yuding','','[]','到處即閉戶，逢君方展眉。',12,'御定全唐詩/json/727.json','["到處即閉戶，逢君方展眉。"]'),
('yuding-23','岑公岩','馬冉','唐','御定全唐诗','yuding','','[]','南溪有仙澗，咫尺非人間。泠泠松風下，日暮空蒼山。',24,'御定全唐詩/json/727.json','["南溪有仙澗，咫尺非人間。泠泠松風下，日暮空蒼山。"]'),
('yuding-24','諸暨五泄山','周鏞','唐','御定全唐诗','yuding','','[]','路入蒼煙九過溪，九穿岩曲到招提。天分五溜寒傾北，',40,'御定全唐詩/json/727.json','["路入蒼煙九過溪，九穿岩曲到招提。天分五溜寒傾北，", "當年老默無消息，猶有詞堂一杖藜。"]'),
('yuding-25','贈羅隱','劉贊','唐','御定全唐诗','yuding','','[]','人皆言子屈，獨我謂君非。明主既難謁，青山何不歸。',48,'御定全唐詩/json/727.json','["人皆言子屈，獨我謂君非。明主既難謁，青山何不歸。", "年虛侵雪鬢，塵枉汙麻衣。自古逃名者，至今名豈微。"]'),
('yuding-26','句','劉贊','唐','御定全唐诗','yuding','','[]','絮花飛起雪漫漫，長得宮娥帶笑看。（《柳枝詞》，',23,'御定全唐詩/json/727.json','["絮花飛起雪漫漫，長得宮娥帶笑看。（《柳枝詞》，"]'),
('yuding-27','洛陽道','任翻','唐','御定全唐诗','yuding','','[]','憧憧洛陽道，塵下生春草。行者豈無家，無人在家老。',72,'御定全唐詩/json/727.json','["憧憧洛陽道，塵下生春草。行者豈無家，無人在家老。", "雞鳴前結束，爭去恐不早。百年路傍盡，白日車中曉。", "求富江海狹，取貴山嶽小。二端立在途，奔走無由了。"]'),
('yuding-28','春晴','任翻','唐','御定全唐诗','yuding','','[]','楚國多春雨，柴門喜晚晴。幽人臨水坐，好鳥隔花鳴。',48,'御定全唐詩/json/727.json','["楚國多春雨，柴門喜晚晴。幽人臨水坐，好鳥隔花鳴。", "野色臨空闊，江流接海平。門前到溪路，今夜月分明。"]'),
('yuding-29','秋晚郊居','任翻','唐','御定全唐诗','yuding','','[]','遠聲霜後樹，秋色水邊村。野徑無來客，寒風自動門。',48,'御定全唐詩/json/727.json','["遠聲霜後樹，秋色水邊村。野徑無來客，寒風自動門。", "海山藏日影，江月落潮痕。惆悵高飛晚，年年別故園。"]'),
('yuding-30','秋晚途次','任翻','唐','御定全唐诗','yuding','','[]','秋色滿行路，此時心不閑。孤貧游上國，少壯有衰顏。',48,'御定全唐詩/json/727.json','["秋色滿行路，此時心不閑。孤貧游上國，少壯有衰顏。", "眾鳥已歸樹，旅人猶過山。蕭條遠林外，風急水潺潺。"]'),
('yuding-31','葛仙井','任翻','唐','御定全唐诗','yuding','','[]','古井碧沉沉，分明見百尋。味甘傳邑內，脈冷應山心。',48,'御定全唐詩/json/727.json','["古井碧沉沉，分明見百尋。味甘傳邑內，脈冷應山心。", "圓入月輪淨，直涵峰影深。自從仙去後，汲引到如今。"]'),
('yuding-32','桐柏觀','任翻','唐','御定全唐诗','yuding','','[]','飄飄雲外者，暫宿聚仙堂。半夜人無語，中宵月送涼。',48,'御定全唐詩/json/727.json','["飄飄雲外者，暫宿聚仙堂。半夜人無語，中宵月送涼。", "鶴歸高樹靜，螢過小池光。不得多時住，門開是事忙。"]'),
('yuding-33','冬暮野寺','任翻','唐','御定全唐诗','yuding','','[]','江東寒近臘，野寺水天昏。無酒可銷夜，隨僧早閉門。',48,'御定全唐詩/json/727.json','["江東寒近臘，野寺水天昏。無酒可銷夜，隨僧早閉門。", "照牆燈影短，著瓦雪聲繁。飄泊仍千里，清吟欲斷魂。"]'),
('yuding-34','贈濟禪師','任翻','唐','御定全唐诗','yuding','','[]','碧峰秋寺內，禪客已無情。半頂發根白，一生心地清。',48,'御定全唐詩/json/727.json','["碧峰秋寺內，禪客已無情。半頂發根白，一生心地清。", "竹房侵月靜，石徑到門平。山下塵囂路，終年誓不行。"]'),
('yuding-35','經墮淚碑','任翻','唐','御定全唐诗','yuding','','[]','羊公傳化地，千古事空存。碑已無文字，人猶敬子孫。',48,'御定全唐詩/json/727.json','["羊公傳化地，千古事空存。碑已無文字，人猶敬子孫。", "峴山長閉恨，漢水自流恩。數處煙嵐色，分明是淚痕。"]'),
('yuding-36','長安冬夜書事','任翻','唐','御定全唐诗','yuding','','[]','憂來長不寐，往事重思量。清渭幾年客，故衣今夜霜。',48,'御定全唐詩/json/727.json','["憂來長不寐，往事重思量。清渭幾年客，故衣今夜霜。", "春風誰識面，水國但牽腸。十二門車馬，昏明各自忙。"]'),
('yuding-37','越江漁父','任翻','唐','御定全唐诗','yuding','','[]','借問釣魚者，持竿多少年。眼明汀島畔，頭白子孫前。',48,'御定全唐詩/json/727.json','["借問釣魚者，持竿多少年。眼明汀島畔，頭白子孫前。", "棹入花時浪，燈留雨夜船。越江深見底，誰識此心堅。"]'),
('yuding-38','哭友人','任翻','唐','御定全唐诗','yuding','','[]','逢著南州史，江邊哭問君。送終時有雪，歸葬處無雲。',48,'御定全唐詩/json/727.json','["逢著南州史，江邊哭問君。送終時有雪，歸葬處無雲。", "官庫惟留劍，鄰僧共結墳。兒孫未成立，誰與集遺文。"]'),
('yuding-39','送李衡','任翻','唐','御定全唐诗','yuding','','[]','羈棲親故少，遠別惜清才。天畔出相送，路長知未回。',48,'御定全唐詩/json/727.json','["羈棲親故少，遠別惜清才。天畔出相送，路長知未回。", "欲銷今日恨，強把異鄉杯。君去南堂後，應無客到來。"]'),
('yuding-40','宮怨','任翻','唐','御定全唐诗','yuding','','[]','淚幹紅落臉，心盡白垂頭。自此方知怨，從來豈信愁。',24,'御定全唐詩/json/727.json','["淚幹紅落臉，心盡白垂頭。自此方知怨，從來豈信愁。"]'),
('yuding-41','惜花','任翻','唐','御定全唐诗','yuding','','[]','無語與花別，細看枝上紅。明年又相見，還恐是愁中。',24,'御定全唐詩/json/727.json','["無語與花別，細看枝上紅。明年又相見，還恐是愁中。"]'),
('yuding-42','宿巾子山禪寺','任翻','唐','御定全唐诗','yuding','','[]','絕頂新秋生夜涼，鶴翻松露滴衣裳。',32,'御定全唐詩/json/727.json','["絕頂新秋生夜涼，鶴翻松露滴衣裳。", "前峰月映半江水，僧在翠微開竹房。"]'),
('yuding-43','再遊巾子山寺','任翻','唐','御定全唐诗','yuding','','[]','靈江江上幘峰寺，三十年來兩度登。',32,'御定全唐詩/json/727.json','["靈江江上幘峰寺，三十年來兩度登。", "野鶴尚巢松樹遍，竹房不見舊時僧。"]'),
('yuding-44','三遊巾子山寺感述','任翻','唐','御定全唐诗','yuding','','[]','清秋絕頂竹房開，松鶴何年去不回。',32,'御定全唐詩/json/727.json','["清秋絕頂竹房開，松鶴何年去不回。", "惟有前峰明月在，夜深猶過半江來。"]'),
('yuding-45','畫山水圖答大愚','荊浩','唐','御定全唐诗','yuding','','[]','恣意縱橫掃，峰巒次第成。筆尖寒樹瘦，墨淡野雲輕。',48,'御定全唐詩/json/727.json','["恣意縱橫掃，峰巒次第成。筆尖寒樹瘦，墨淡野雲輕。", "岩石噴泉窄，山根到水準。禪房時一展，兼稱苦空情。"]'),
('yuding-46','宿顧城二首','張直','唐','御定全唐诗','yuding','','[]','綠草展青裀，樾影連春樹。茅屋八九家，農器六七具。',132,'御定全唐詩/json/727.json','["綠草展青裀，樾影連春樹。茅屋八九家，農器六七具。", "主人有好懷，搴衣留我住。春酒新潑醅，香美連糟濾。", "一醉臥花陰，明朝送君去。", "醉臥夜將半，土底聞雞啼。驚駭問主人，為我剖荒迷。", "武湯東伐韋，固君含悲淒。神奪悔悟魄，幻化為石雞。", "形骸僅盈寸，咿喔若啁蜺。吾村耕耘叟，多獲於鋤犁。"]'),
('yuding-47','題桃源僧','陳光','唐','御定全唐诗','yuding','','[]','桃源有僧舍，跬步異人天。花亂似無主，鶴鳴疑有仙。',48,'御定全唐詩/json/727.json','["桃源有僧舍，跬步異人天。花亂似無主，鶴鳴疑有仙。", "軒廊明野色，松檜濕春煙。定擬辭塵境，依師過晚年。"]'),
('yuding-0','吟敘','周曇','唐','御定全唐诗','yuding','','[]','歷代興亡億萬心，聖人觀古貴知今。',32,'御定全唐詩/json/728.json','["歷代興亡億萬心，聖人觀古貴知今。", "古今成敗無多事，月殿花台幸一吟。"]'),
('yuding-1','閑吟','周曇','唐','御定全唐诗','yuding','','[]','考摭妍媸用破心，剪裁千古獻當今。',32,'御定全唐詩/json/728.json','["考摭妍媸用破心，剪裁千古獻當今。", "閑吟不是閑吟事，事有閑思閑要吟。"]'),
('yuding-2','唐虞門：唐堯','周曇','唐','御定全唐诗','yuding','','[]','祅氛不起瑞煙輕，端拱垂衣日月明。',32,'御定全唐詩/json/728.json','["祅氛不起瑞煙輕，端拱垂衣日月明。", "傳事四方無外役，茅茨深處土階平。"]'),
('yuding-3','唐虞門：虞舜','周曇','唐','御定全唐诗','yuding','','[]','進善懲奸立帝功，功成揖讓益溫恭。',32,'御定全唐詩/json/728.json','["進善懲奸立帝功，功成揖讓益溫恭。", "滿朝卿士多元凱，為黜兜苗與四凶。"]'),
('yuding-4','唐虞門：舜妃','周曇','唐','御定全唐诗','yuding','','[]','蒼梧一望隔重雲，帝子悲尋不記春。',32,'御定全唐詩/json/728.json','["蒼梧一望隔重雲，帝子悲尋不記春。", "何事淚痕偏在竹，貞姿應念節高人。"]'),
('yuding-5','唐虞門：再吟','周曇','唐','御定全唐诗','yuding','','[]','瀟湘何代泣幽魂，骨化重泉志尚存。',32,'御定全唐詩/json/728.json','["瀟湘何代泣幽魂，骨化重泉志尚存。", "若地道中休下淚，不應新竹有啼痕。"]'),
('yuding-6','三代門：夏禹','周曇','唐','御定全唐诗','yuding','','[]','堯違天孽賴詢謨，頓免洪波浸碧虛。',32,'御定全唐詩/json/728.json','["堯違天孽賴詢謨，頓免洪波浸碧虛。", "海內生靈微伯禹，盡應隨浪化為魚。"]'),
('yuding-7','三代門：再吟','周曇','唐','御定全唐诗','yuding','','[]','萬古龍門一旦開，無成甘死作黃能。',32,'御定全唐詩/json/728.json','["萬古龍門一旦開，無成甘死作黃能。", "司空定有匡堯術，九載之前何處來。"]'),
('yuding-8','三代門：太康','周曇','唐','御定全唐诗','yuding','','[]','師保何人為琢磨，安知父祖苦辛多。',32,'御定全唐詩/json/728.json','["師保何人為琢磨，安知父祖苦辛多。", "酒酣禽色方為樂，詎肯閑聽五子歌。"]'),
('yuding-9','三代門：後稷','周曇','唐','御定全唐诗','yuding','','[]','人惟邦本本由農，曠古誰高後稷功。',32,'御定全唐詩/json/728.json','["人惟邦本本由農，曠古誰高後稷功。", "百穀且繁三曜在，牲牢郊祀信無窮。"]'),
('yuding-10','三代門：文王','周曇','唐','御定全唐诗','yuding','','[]','昭然明德報天休，礿祭惟馨勝殺牛。',32,'御定全唐詩/json/728.json','["昭然明德報天休，礿祭惟馨勝殺牛。", "二老五侯何所詐，不歸商受盡歸周。"]'),
('yuding-11','三代門：武王','周曇','唐','御定全唐诗','yuding','','[]','文王寢膳武王隨，內豎言安色始怡。',32,'御定全唐詩/json/728.json','["文王寢膳武王隨，內豎言安色始怡。", "七載豈堪囚羑裏，一夫為報亦何疑。"]'),
('yuding-12','三代門：太公','周曇','唐','御定全唐诗','yuding','','[]','昌獵關西紂獵東，紂憐崇虎棄非熊。',32,'御定全唐詩/json/728.json','["昌獵關西紂獵東，紂憐崇虎棄非熊。", "危邦自謂多麟鳳，肯把王綱取釣翁。"]'),
('yuding-13','三代門：再吟','周曇','唐','御定全唐诗','yuding','','[]','東鄰不事事西鄰，禦物卑和物自親。',32,'御定全唐詩/json/728.json','["東鄰不事事西鄰，禦物卑和物自親。", "天下言知天下者，兆人無主屬賢人。"]'),
('yuding-14','三代門：又吟','周曇','唐','御定全唐诗','yuding','','[]','千妖萬態逞妍姿，破國亡家更是誰。',32,'御定全唐詩/json/728.json','["千妖萬態逞妍姿，破國亡家更是誰。", "匡政必能除苟媚，去邪當斷勿狐疑。"]'),
('yuding-15','三代門：子牙妻','周曇','唐','御定全唐诗','yuding','','[]','陵柏無心竹變秋，不能同戚擬同休。',32,'御定全唐詩/json/728.json','["陵柏無心竹變秋，不能同戚擬同休。", "歲寒焉在空垂涕，覆水如何欲再收。"]'),
('yuding-16','三代門：周公','周曇','唐','御定全唐诗','yuding','','[]','文武傳芳百代基，幾多賢哲守成規。',32,'御定全唐詩/json/728.json','["文武傳芳百代基，幾多賢哲守成規。", "仍聞吐握延儒素，猶恐民疵未盡知。"]'),
('yuding-17','三代門：夷齊','周曇','唐','御定全唐诗','yuding','','[]','讓國由衷義亦乖，不知天命匹夫才。',32,'御定全唐詩/json/728.json','["讓國由衷義亦乖，不知天命匹夫才。", "將除暴虐誠能阻，何異崎嶇助紂來。"]'),
('yuding-18','三代門：管蔡','周曇','唐','御定全唐诗','yuding','','[]','伊商胡越尚同圖，管蔡如何有異謨。',32,'御定全唐詩/json/728.json','["伊商胡越尚同圖，管蔡如何有異謨。", "不念祖宗危社稷，強於仁聖遣行誅。"]'),
('yuding-19','三代門：成王','周曇','唐','御定全唐诗','yuding','','[]','成王有過伯禽笞，聖惠能新日自奇。',32,'御定全唐詩/json/728.json','["成王有過伯禽笞，聖惠能新日自奇。", "王道既成何所感，越裳呈瑞鳳來儀。"]'),
('yuding-20','三代門：幽王','周曇','唐','御定全唐诗','yuding','','[]','狼煙篝火為邊塵，烽候那宜悅婦人。',32,'御定全唐詩/json/728.json','["狼煙篝火為邊塵，烽候那宜悅婦人。", "厚德未聞聞厚色，不亡家國幸亡身。"]'),
('yuding-21','三代門：平王','周曇','唐','御定全唐诗','yuding','','[]','犬戎西集殺幽王，邦土何由不便亡。',32,'御定全唐詩/json/728.json','["犬戎西集殺幽王，邦土何由不便亡。", "宜臼東來年更遠，川流難絕信源長。"]'),
('yuding-22','春秋戰國門：祭足','周曇','唐','御定全唐诗','yuding','','[]','吳魯燕韓豈別宗，曾無外禦但相攻。',32,'御定全唐詩/json/728.json','["吳魯燕韓豈別宗，曾無外禦但相攻。", "當時周鄭誰為相，交質將何服遠戎。"]'),
('yuding-23','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','周室衰微不共匡，干戈終日互爭強。',32,'御定全唐詩/json/728.json','["周室衰微不共匡，干戈終日互爭強。", "諸侯若解尊天子，列國何因次第亡。"]'),
('yuding-24','春秋戰國門：隱公','周曇','唐','御定全唐诗','yuding','','[]','今古難堤是小人，苟希榮寵任相親。',32,'御定全唐詩/json/728.json','["今古難堤是小人，苟希榮寵任相親。", "陳謀不信懷憂懼，反間須防卻害身。"]'),
('yuding-25','春秋戰國門：莊公','周曇','唐','御定全唐诗','yuding','','[]','齊甲強臨力有餘，魯莊為戰念區區。',32,'御定全唐詩/json/728.json','["齊甲強臨力有餘，魯莊為戰念區區。", "魚麗三鼓微曹劌，肉食安能暇遠謨。"]'),
('yuding-26','春秋戰國門：哀公','周曇','唐','御定全唐诗','yuding','','[]','賢為鄰用國憂危，廟算無非委豔奇。',32,'御定全唐詩/json/728.json','["賢為鄰用國憂危，廟算無非委豔奇。", "兩葉翠娥春乍展，一毛須去不難吹。"]'),
('yuding-27','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','好龍天為降真龍，及見真龍瘁厥躬。',32,'御定全唐詩/json/728.json','["好龍天為降真龍，及見真龍瘁厥躬。", "接下不勤徒好士，葉公何異魯哀公。"]'),
('yuding-28','春秋戰國門：平公','周曇','唐','御定全唐诗','yuding','','[]','鴻鵠輕騰萬里高，何殊朝野得賢豪。',32,'御定全唐詩/json/728.json','["鴻鵠輕騰萬里高，何殊朝野得賢豪。", "能知翼戴穹蒼力，不是蒙茸腹背毛。"]'),
('yuding-29','春秋戰國門：文公','周曇','唐','御定全唐诗','yuding','','[]','滅虢吞虞未息兵，柔秦敗楚霸威成。',32,'御定全唐詩/json/728.json','["滅虢吞虞未息兵，柔秦敗楚霸威成。", "文公徒欲三強服，分晉元來是六卿。"]'),
('yuding-30','春秋戰國門：景公','周曇','唐','御定全唐诗','yuding','','[]','覺病當宜早問師，病深難療恨難追。',32,'御定全唐詩/json/728.json','["覺病當宜早問師，病深難療恨難追。", "晉侯徒有秦醫緩，疾在膏肓救已遲。"]'),
('yuding-31','春秋戰國門：衛靈公','周曇','唐','御定全唐诗','yuding','','[]','子魚無隱欲源清，死不忘忠感衛靈。',32,'御定全唐詩/json/728.json','["子魚無隱欲源清，死不忘忠感衛靈。", "伯玉既親知德潤，殘桃休吃悟蘭馨。"]'),
('yuding-32','春秋戰國門：陳靈公','周曇','唐','御定全唐诗','yuding','','[]','誰與陳君嫁禍來，孔甯行父夏姬媒。',32,'御定全唐詩/json/728.json','["誰與陳君嫁禍來，孔甯行父夏姬媒。", "靈公徒認征舒面，至死何曾識禍胎。"]'),
('yuding-33','春秋戰國門：陳蔡君','周曇','唐','御定全唐诗','yuding','','[]','楚聘宣尼欲道光，是時陳蔡畏鄰強。',32,'御定全唐詩/json/728.json','["楚聘宣尼欲道光，是時陳蔡畏鄰強。", "庸謀但解遮賢路，不解迎賢謀自昌。"]'),
('yuding-34','春秋戰國門：楚惠王','周曇','唐','御定全唐诗','yuding','','[]','芹中遇蛭強為吞，不欲緣微有害人。',32,'御定全唐詩/json/728.json','["芹中遇蛭強為吞，不欲緣微有害人。", "何事免成心腹疾，皇天惟德是相親。"]'),
('yuding-35','春秋戰國門：楚懷王','周曇','唐','御定全唐诗','yuding','','[]','不聽陳軫信張儀，六裏商於果見欺。',32,'御定全唐詩/json/728.json','["不聽陳軫信張儀，六裏商於果見欺。", "既舍黔中西換得，又令生去益堪悲。"]'),
('yuding-36','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','不得商于又失齊，楚懷方寸一何迷。',32,'御定全唐詩/json/728.json','["不得商于又失齊，楚懷方寸一何迷。", "明知秦是虎狼國，更忍車輪獨向西。"]'),
('yuding-37','春秋戰國門：韓惠王','周曇','唐','御定全唐诗','yuding','','[]','韓惠開渠止暴秦，營田萬頃飽秦人。',32,'御定全唐詩/json/728.json','["韓惠開渠止暴秦，營田萬頃飽秦人。", "何殊般肉供羸獸，獸壯安知不害身。"]'),
('yuding-38','春秋戰國門：頃襄王','周曇','唐','御定全唐诗','yuding','','[]','秦陷荊王死不還，只緣偏聽子蘭言。',32,'御定全唐詩/json/728.json','["秦陷荊王死不還，只緣偏聽子蘭言。", "頃襄還信子蘭語，忍使江魚葬屈原。"]'),
('yuding-39','春秋戰國門：武公','周曇','唐','御定全唐诗','yuding','','[]','猛獸來兵只為文，豈宜涼德擬圖尊。',32,'御定全唐詩/json/728.json','["猛獸來兵只為文，豈宜涼德擬圖尊。", "君看豹彩蒙麋質，人取無難必不存。"]'),
('yuding-40','春秋戰國門：華元','周曇','唐','御定全唐诗','yuding','','[]','未知軍法忌偏頗，徒解於思腹漫皤。',32,'御定全唐詩/json/728.json','["未知軍法忌偏頗，徒解於思腹漫皤。", "昔日羊斟曾不預，今朝為政事如何。"]'),
('yuding-41','春秋戰國門：臧孫','周曇','唐','御定全唐诗','yuding','','[]','諸孟憎吾似犬獰，賢臧哭孟倍傷情。',32,'御定全唐詩/json/728.json','["諸孟憎吾似犬獰，賢臧哭孟倍傷情。", "季孫愛我如甘疾，疾足亡身藥故寧。"]'),
('yuding-42','春秋戰國門：公叔','周曇','唐','御定全唐诗','yuding','','[]','吳起南奔魏國荒，必聽公叔失賢良。',32,'御定全唐詩/json/728.json','["吳起南奔魏國荒，必聽公叔失賢良。", "無謀縱欲離安邑，可免河溝徙大樑。"]'),
('yuding-43','春秋戰國門：莊辛','周曇','唐','御定全唐诗','yuding','','[]','莊辛正諫謂妖詞，兵及鄢陵始悔思。',32,'御定全唐詩/json/728.json','["莊辛正諫謂妖詞，兵及鄢陵始悔思。", "見兔必能知顧犬，亡羊補棧未為遲。"]'),
('yuding-44','春秋戰國門：孫臏','周曇','唐','御定全唐诗','yuding','','[]','曾嫌勝己害賢人，鑽火明知速自焚。',32,'御定全唐詩/json/728.json','["曾嫌勝己害賢人，鑽火明知速自焚。", "斷足爾能行不足，逢君誰肯不酬君。"]'),
('yuding-45','春秋戰國門：靈輒','周曇','唐','御定全唐诗','yuding','','[]','失水枯鱗得再生，翳桑無地謝深情。',32,'御定全唐詩/json/728.json','["失水枯鱗得再生，翳桑無地謝深情。", "朱輪未染酬恩血，公子何由見赤誠。"]'),
('yuding-46','春秋戰國門：郭開','周曇','唐','御定全唐诗','yuding','','[]','秦襲邯鄲歲月深，何人沾贈郭開金。',32,'御定全唐詩/json/728.json','["秦襲邯鄲歲月深，何人沾贈郭開金。", "廉頗還國李牧在，安得趙王為爾擒。"]'),
('yuding-47','春秋戰國門：樂羊','周曇','唐','御定全唐诗','yuding','','[]','杯羹忍啜得非忠，巧佞胡為惑主聰。',32,'御定全唐詩/json/728.json','["杯羹忍啜得非忠，巧佞胡為惑主聰。", "盈篋謗書能寢默，中山不是樂羊功。"]'),
('yuding-48','春秋戰國門：虞卿','周曇','唐','御定全唐诗','yuding','','[]','割地求和國必危，安知堅守絕來思。',32,'御定全唐詩/json/728.json','["割地求和國必危，安知堅守絕來思。", "年年來伐年年割，割盡邯鄲何所之。"]'),
('yuding-49','春秋戰國門：豫讓','周曇','唐','御定全唐诗','yuding','','[]','門客家臣義莫儔，漆身吞炭不能休。',32,'御定全唐詩/json/728.json','["門客家臣義莫儔，漆身吞炭不能休。", "中行智伯思何異，國士終期國士酬。"]'),
('yuding-50','春秋戰國門：毛遂','周曇','唐','御定全唐诗','yuding','','[]','不識囊中穎脫錐，功成方信有英奇。',32,'御定全唐詩/json/728.json','["不識囊中穎脫錐，功成方信有英奇。", "平原門下三千客，得力何曾是素知。"]'),
('yuding-51','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','定獲英奇不在多，然須設網遍山河。',32,'御定全唐詩/json/728.json','["定獲英奇不在多，然須設網遍山河。", "禽雖一目羅中得，豈可空張一目羅。"]'),
('yuding-52','春秋戰國門：田文','周曇','唐','御定全唐诗','yuding','','[]','下客常才不足珍，誰為狗盜脫強秦。',32,'御定全唐詩/json/728.json','["下客常才不足珍，誰為狗盜脫強秦。", "秦關若待雞鳴出，笑殺臨淄土偶人。"]'),
('yuding-53','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','門下三千各自矜，頻彈劍客獨無能。',32,'御定全唐詩/json/728.json','["門下三千各自矜，頻彈劍客獨無能。", "田文不厭無能客，三窟全身果有憑。"]'),
('yuding-54','春秋戰國門：馮讙','周曇','唐','御定全唐诗','yuding','','[]','兔窟穿成主再興，輩流狐伏敢驕矜。',32,'御定全唐詩/json/728.json','["兔窟穿成主再興，輩流狐伏敢驕矜。", "馮讙不是無能者，要試君心欲展能。"]'),
('yuding-55','春秋戰國門：章子','周曇','唐','御定全唐诗','yuding','','[]','在家能子必能臣，齊將功成以孝聞。',32,'御定全唐詩/json/728.json','["在家能子必能臣，齊將功成以孝聞。", "改葬義無欺死父，臨戎安肯背生君。"]'),
('yuding-56','春秋戰國門：卞和','周曇','唐','御定全唐诗','yuding','','[]','磷磷誰為惑溫溫，至寶凡姿甚易分。',32,'御定全唐詩/json/728.json','["磷磷誰為惑溫溫，至寶凡姿甚易分。", "自是時人多貴耳，目無明鑒使俱焚。"]'),
('yuding-57','春秋戰國門：季劄','周曇','唐','御定全唐诗','yuding','','[]','吹毛霜刃過千金，生許徐君死掛林。',32,'御定全唐詩/json/728.json','["吹毛霜刃過千金，生許徐君死掛林。", "寶劍徒稱無價寶，行心更貴不欺心。"]'),
('yuding-58','春秋戰國門：孫武','周曇','唐','御定全唐诗','yuding','','[]','理國無難似理兵，兵家法令貴遵行。',32,'御定全唐詩/json/728.json','["理國無難似理兵，兵家法令貴遵行。", "行刑不避君王寵，一笑隨刀八陣成。"]'),
('yuding-59','春秋戰國門：夫差','周曇','唐','御定全唐诗','yuding','','[]','信聽讒言疾不除，忠臣須殺竟何如。',32,'御定全唐詩/json/728.json','["信聽讒言疾不除，忠臣須殺竟何如。", "會稽既雪夫差死，泉下胡顏見子胥。"]'),
('yuding-60','春秋戰國門：少孺','周曇','唐','御定全唐诗','yuding','','[]','寶貴親仁與善鄰，鄰兵何要互相臻。',32,'御定全唐詩/json/728.json','["寶貴親仁與善鄰，鄰兵何要互相臻。", "螳螂定是遭黃雀，黃雀須防挾彈人。"]'),
('yuding-61','春秋戰國門：蘇厲','周曇','唐','御定全唐诗','yuding','','[]','百步穿楊箭不移，養由堪教聽弘規。',32,'御定全唐詩/json/728.json','["百步穿楊箭不移，養由堪教聽弘規。", "身隆業著未知退，勿遣功名一旦隳。"]'),
('yuding-62','春秋戰國門：鬻拳','周曇','唐','御定全唐诗','yuding','','[]','鬻拳強諫懼威刑，退省懷慚不顧生。',32,'御定全唐詩/json/728.json','["鬻拳強諫懼威刑，退省懷慚不顧生。", "雙刖忍行留痛恨，惟君適足見忠誠。"]'),
('yuding-63','春秋戰國門：荊軻','周曇','唐','御定全唐诗','yuding','','[]','反刃相酬是匹夫，安知突騎駕群胡。',32,'御定全唐詩/json/728.json','["反刃相酬是匹夫，安知突騎駕群胡。", "有心為報懷權略，可在於期與地圖。"]'),
('yuding-64','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','幾尺如霜利不群，恩仇未報反亡身。',32,'御定全唐詩/json/728.json','["幾尺如霜利不群，恩仇未報反亡身。", "誠哉利器全由用，可惜吹毛不得人。"]'),
('yuding-65','春秋戰國門：陳軫','周曇','唐','御定全唐诗','yuding','','[]','丹青徒有逞喧嘩，有足由來不是蛇。',32,'御定全唐詩/json/728.json','["丹青徒有逞喧嘩，有足由來不是蛇。", "殺將破軍為柱國，君今官極更何加。"]'),
('yuding-66','春秋戰國門：田饒','周曇','唐','御定全唐诗','yuding','','[]','廚拋敗肉士懷饑，倉爛餘糧客未炊。',32,'御定全唐詩/json/728.json','["廚拋敗肉士懷饑，倉爛餘糧客未炊。", "臨難欲行求死士，將何恩信致扶危。"]'),
('yuding-67','春秋戰國門：鮑叔','周曇','唐','御定全唐诗','yuding','','[]','忠臣祝壽吐嘉詞，鮑叔臨軒酒一卮。',32,'御定全唐詩/json/728.json','["忠臣祝壽吐嘉詞，鮑叔臨軒酒一卮。", "安不忘危臣所願，願思危困必無危。"]'),
('yuding-68','春秋戰國門：晏嬰','周曇','唐','御定全唐诗','yuding','','[]','正人徒以刃相危，貪利忘忠死不為。',32,'御定全唐詩/json/728.json','["正人徒以刃相危，貪利忘忠死不為。", "麋鹿命懸當有處，驅車何必用賓士。"]'),
('yuding-69','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','下澤逢蛇蓋是常，還如山上見豺狼。',32,'御定全唐詩/json/728.json','["下澤逢蛇蓋是常，還如山上見豺狼。", "國中有怪非蛇獸，不用賢能是不祥。"]'),
('yuding-70','春秋戰國門：又吟','周曇','唐','御定全唐诗','yuding','','[]','馬斃廄人欲就刑，百年臨盡一言生。',32,'御定全唐詩/json/728.json','["馬斃廄人欲就刑，百年臨盡一言生。", "賴逢賢相能匡救，仍免吾君播惡聲。"]'),
('yuding-71','春秋戰國門：叔向','周曇','唐','御定全唐诗','yuding','','[]','重祿存家不敢言，小臣憂禍亦如然。',32,'御定全唐詩/json/728.json','["重祿存家不敢言，小臣憂禍亦如然。", "明開諫諍能無罪，只此宜為理國先。"]'),
('yuding-72','春秋戰國門：師曠','周曇','唐','御定全唐诗','yuding','','[]','老能勸學照餘生，似夜隨燈到處明。',32,'御定全唐詩/json/728.json','["老能勸學照餘生，似夜隨燈到處明。", "往行前言如不見，暗中無燭若為行。"]'),
('yuding-73','春秋戰國門：智伯','周曇','唐','御定全唐诗','yuding','','[]','三國連兵敵就擒，晉陽城下碧波深。',32,'御定全唐詩/json/728.json','["三國連兵敵就擒，晉陽城下碧波深。", "風濤撼處看沈趙，舟楫不從翻自沈。"]'),
('yuding-74','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','攻城來下惜先分，一旦家邦屬四鄰。',32,'御定全唐詩/json/728.json','["攻城來下惜先分，一旦家邦屬四鄰。", "徒逞威強稱智伯，不知權變是愚人。"]'),
('yuding-75','春秋戰國門：襄子','周曇','唐','御定全唐诗','yuding','','[]','君子常聞不迫危，城崩何用急重圍。',32,'御定全唐詩/json/728.json','["君子常聞不迫危，城崩何用急重圍。", "叛亡能退修文德，果見中牟以義歸。"]'),
('yuding-76','春秋戰國門：楊回','周曇','唐','御定全唐诗','yuding','','[]','三逐鄉閭五去君，莫知何地可容身。',32,'御定全唐詩/json/728.json','["三逐鄉閭五去君，莫知何地可容身。", "楊回不是逢英鑒，白首無成一旅人。"]'),
('yuding-77','春秋戰國門：顏回','周曇','唐','御定全唐诗','yuding','','[]','陋巷簞瓢困有年，是時端木飫腥膻。',32,'御定全唐詩/json/728.json','["陋巷簞瓢困有年，是時端木飫腥膻。", "宣尼行教何形跡，不肯分甘救子淵。"]'),
('yuding-78','春秋戰國門：子貢','周曇','唐','御定全唐诗','yuding','','[]','救魯亡吳事可傷，誰令利口說田常。',32,'御定全唐詩/json/728.json','["救魯亡吳事可傷，誰令利口說田常。", "吳亡必定由端木，魯亦宜其運不長。"]'),
('yuding-79','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','一言能使定安危，安己危人是所宜。',32,'御定全唐詩/json/728.json','["一言能使定安危，安己危人是所宜。", "仁義不思垂教化，背恩亡德豈儒為。"]'),
('yuding-80','春秋戰國門：鄭相','周曇','唐','御定全唐诗','yuding','','[]','鄭相清賢慎有餘，好魚魚至竟何如。',32,'御定全唐詩/json/728.json','["鄭相清賢慎有餘，好魚魚至竟何如。", "退魚留得終身祿，祿在何憂不得魚。"]'),
('yuding-81','春秋戰國門：子產','周曇','唐','御定全唐诗','yuding','','[]','為政何門是化源，寬仁高下保安全。',32,'御定全唐詩/json/728.json','["為政何門是化源，寬仁高下保安全。", "如嫌水德人多狎，拯溺宜將猛濟寬。"]'),
('yuding-82','春秋戰國門：管仲','周曇','唐','御定全唐诗','yuding','','[]','美酒濃馨客要沽，門深誰敢強提壺。',32,'御定全唐詩/json/728.json','["美酒濃馨客要沽，門深誰敢強提壺。", "苟非賢主詢賢士，肯信沽人畏子獹。"]'),
('yuding-83','春秋戰國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','社鼠穿牆巧庇身，何由攻灌若為熏。',32,'御定全唐詩/json/728.json','["社鼠穿牆巧庇身，何由攻灌若為熏。", "能知窟穴依形勢，不聽讒邪是聖君。"]'),
