('yuding-18','前漢門：又吟','周曇','唐','御定全唐诗','yuding','','[]','銅馬朱眉滿四方，總緣居攝亂天常。',32,'御定全唐詩/json/729.json','["銅馬朱眉滿四方，總緣居攝亂天常。", "因君多少布衣士，不是公卿即帝王。"]'),
('yuding-19','前漢門：毛延壽','周曇','唐','御定全唐诗','yuding','','[]','不拔金釵賂漢臣，徒嗟玉豔委胡塵。',32,'御定全唐詩/json/729.json','["不拔金釵賂漢臣，徒嗟玉豔委胡塵。", "能知貨賄移妍醜，豈獨丹青畫美人。"]'),
('yuding-20','前漢門：劉聖公','周曇','唐','御定全唐诗','yuding','','[]','不納良謀劉演言，胡為銜璧向崇宣。',32,'御定全唐詩/json/729.json','["不納良謀劉演言，胡為銜璧向崇宣。", "傷哉亂帝途窮處，何必當時譖福先。"]'),
('yuding-21','前漢門：樊崇徐宣','周曇','唐','御定全唐诗','yuding','','[]','庸中佼佼鐵錚錚，百萬長驅入帝京。',32,'御定全唐詩/json/729.json','["庸中佼佼鐵錚錚，百萬長驅入帝京。", "首事縱隳三善在，歸仁何慮不全生。"]'),
('yuding-22','前漢門：僭號公孫述','周曇','唐','御定全唐诗','yuding','','[]','劍蜀金湯孰敢爭，子陽才業匪雄英。',32,'御定全唐詩/json/729.json','["劍蜀金湯孰敢爭，子陽才業匪雄英。", "方知在德不在險，危棧何曾阻漢兵。"]'),
('yuding-23','後漢門：光武','周曇','唐','御定全唐诗','yuding','','[]','成敗非儒孰可量，儒生何指指蕭王。',32,'御定全唐詩/json/729.json','["成敗非儒孰可量，儒生何指指蕭王。", "蕭王得眾能寬裕，吳漢歸來帝業昌。"]'),
('yuding-24','後漢門：明帝','周曇','唐','御定全唐诗','yuding','','[]','朝臣咸佞孰知非，張佚公忠語獨奇。',32,'御定全唐詩/json/729.json','["朝臣咸佞孰知非，張佚公忠語獨奇。", "博士一言除太傅，諡為明帝信其宜。"]'),
('yuding-25','後漢門：桓帝','周曇','唐','御定全唐诗','yuding','','[]','能嫌跋扈斬梁王，甯便榮枯信段張。',32,'御定全唐詩/json/729.json','["能嫌跋扈斬梁王，甯便榮枯信段張。", "襄楷忠言誰佞惑，忍教奸禍起蕭牆。"]'),
('yuding-26','後漢門：靈帝','周曇','唐','御定全唐诗','yuding','','[]','榜懸金價鬻官榮，千萬為公五百卿。',32,'御定全唐詩/json/729.json','["榜懸金價鬻官榮，千萬為公五百卿。", "公瑾孔明窮退者，安知高臥遇雄英。"]'),
('yuding-27','後漢門：廢帝','周曇','唐','御定全唐诗','yuding','','[]','亂兵如蝟走王師，社稷顛危孰為持。',32,'御定全唐詩/json/729.json','["亂兵如蝟走王師，社稷顛危孰為持。", "夜逐螢光尋道路，漢家天子步歸時。"]'),
('yuding-28','後漢門：獻帝','周曇','唐','御定全唐诗','yuding','','[]','只為曹侯數貴人，普天黔首盡黃巾。',32,'御定全唐詩/json/729.json','["只為曹侯數貴人，普天黔首盡黃巾。", "漢靈早聽侍中諫，安得獻生稱不辰。"]'),
('yuding-29','後漢門：再吟','周曇','唐','御定全唐诗','yuding','','[]','咸怨刑科有黨偏，耕夫無不事戎旃。',32,'御定全唐詩/json/729.json','["咸怨刑科有黨偏，耕夫無不事戎旃。", "是時老幼饑號處，一斛黃禾五百千。"]'),
('yuding-30','後漢門：子密','周曇','唐','御定全唐诗','yuding','','[]','子密封侯豈所宜，能高德義必無為。',32,'御定全唐詩/json/729.json','["子密封侯豈所宜，能高德義必無為。", "當時若縛還彭氏，率土何憂不自歸。"]'),
('yuding-31','後漢門：羊續','周曇','唐','御定全唐诗','yuding','','[]','魚懸潔白振清風，祿散親賓歲自窮。',32,'御定全唐詩/json/729.json','["魚懸潔白振清風，祿散親賓歲自窮。", "單席寒廳慚使者，葛衣何以至三公。"]'),
('yuding-32','後漢門：楊震','周曇','唐','御定全唐诗','yuding','','[]','為國推賢匪惠私，十金為報遽相危。',32,'御定全唐詩/json/729.json','["為國推賢匪惠私，十金為報遽相危。", "無言暗室何人見，咫尺斯須已四知。"]'),
('yuding-33','後漢門：趙孝','周曇','唐','御定全唐诗','yuding','','[]','綠林清旦正朝饑，豈計行人瘦與肥。',32,'御定全唐詩/json/729.json','["綠林清旦正朝饑，豈計行人瘦與肥。", "為感在原哀叫切，鶺鴒休報聽雙飛。"]'),
('yuding-34','後漢門：馬後','周曇','唐','御定全唐诗','yuding','','[]','粗衣閑寂閱群書，薦達嬪妃廣帝居。',32,'御定全唐詩/json/729.json','["粗衣閑寂閱群書，薦達嬪妃廣帝居。", "再實傷根嫌貴寵，惠慈勞悴育皇儲。"]'),
('yuding-35','後漢門：魏博妻','周曇','唐','御定全唐诗','yuding','','[]','蘿掛青松是所依，松凋蘿更改何枝。',32,'御定全唐詩/json/729.json','["蘿掛青松是所依，松凋蘿更改何枝。", "操刀必割腕可斷，磐石徒堅心不移。"]'),
('yuding-36','後漢門：曹娥','周曇','唐','御定全唐诗','yuding','','[]','心摧目斷哭江濆，窺浪無蹤日又昏。',32,'御定全唐詩/json/729.json','["心摧目斷哭江濆，窺浪無蹤日又昏。", "不入重泉尋水底，此生安得見沈魂。"]'),
('yuding-37','後漢門：周都妻','周曇','唐','御定全唐诗','yuding','','[]','綠水雙鴛一已沈，皇天更欲配何禽。',32,'御定全唐詩/json/729.json','["綠水雙鴛一已沈，皇天更欲配何禽。", "不將血涕隨霜刃，誰見朱殷未死心。"]'),
('yuding-38','後漢門：鮑宣妻','周曇','唐','御定全唐诗','yuding','','[]','君惡奢華意不歡，一言從儉亦何難。',32,'御定全唐詩/json/729.json','["君惡奢華意不歡，一言從儉亦何難。", "但能和樂同琴瑟，未必恩情在綺紈。"]'),
('yuding-39','後漢門：呂母','周曇','唐','御定全唐诗','yuding','','[]','獄無良吏雪無由，處處戈鋋自執仇。',32,'御定全唐詩/json/729.json','["獄無良吏雪無由，處處戈鋋自執仇。", "呂母銜冤窮老婦，亦能為帥複私讎。"]'),
('yuding-40','三國門：蜀先主','周曇','唐','御定全唐诗','yuding','','[]','豫州軍敗信途窮，徐庶推能薦臥龍。',32,'御定全唐詩/json/729.json','["豫州軍敗信途窮，徐庶推能薦臥龍。", "不是卑詞三訪謁，誰令玄德主巴邛。"]'),
('yuding-41','三國門：再吟','周曇','唐','御定全唐诗','yuding','','[]','一家區宇忽三分，齷齪車書曷足論。',32,'御定全唐詩/json/729.json','["一家區宇忽三分，齷齪車書曷足論。", "定有伊薑為佐輔，忍教鴻雁各乾坤。"]'),
('yuding-42','三國門：後主','周曇','唐','御定全唐诗','yuding','','[]','萬峰如劍載前來，危閣橫空信險哉。',32,'御定全唐詩/json/729.json','["萬峰如劍載前來，危閣橫空信險哉。", "對此玄休長歎息，方知劉禪是庸才。"]'),
('yuding-43','三國門：吳後主','周曇','唐','御定全唐诗','yuding','','[]','吳宮季主恣驕奢，移盡江南百媚花。',32,'御定全唐詩/json/729.json','["吳宮季主恣驕奢，移盡江南百媚花。", "一旦狂風江上起，花隨風散落誰家。"]'),
('yuding-44','三國門：王表','周曇','唐','御定全唐诗','yuding','','[]','王表聞聲莫見身，吳中敬事甚君親。',32,'御定全唐詩/json/729.json','["王表聞聲莫見身，吳中敬事甚君親。", "是知邦國將亡滅，不聽人臣聽鬼神。"]'),
('yuding-45','三國門：魯肅','周曇','唐','御定全唐诗','yuding','','[]','輕財重義見英奇，聖主賢臣是所依。',32,'御定全唐詩/json/729.json','["輕財重義見英奇，聖主賢臣是所依。", "公瑾窘饑求子敬，一言才起數船歸。"]'),
('yuding-46','晉門：晉武帝','周曇','唐','御定全唐诗','yuding','','[]','漢貪金帛鬻公卿，財贍羸軍冀國寧。',32,'御定全唐詩/json/729.json','["漢貪金帛鬻公卿，財贍羸軍冀國寧。", "晉武鬻官私室富，是知猶不及桓靈。"]'),
('yuding-47','晉門：再吟','周曇','唐','御定全唐诗','yuding','','[]','君人為理在安民，論道求賢德自新。',32,'御定全唐詩/json/729.json','["君人為理在安民，論道求賢德自新。", "經國遠圖無所問，何曾言指一何神。"]'),
('yuding-48','晉門：惠帝','周曇','唐','御定全唐诗','yuding','','[]','蛙鳴堪笑問官私，更勸饑人食肉糜。',32,'御定全唐詩/json/729.json','["蛙鳴堪笑問官私，更勸饑人食肉糜。", "蒙昧萬機猶婦女，寇戎安得不紛披。"]'),
('yuding-49','晉門：賈後','周曇','唐','御定全唐诗','yuding','','[]','賈後甘為廢戮人，齊王還殺趙王倫。',32,'御定全唐詩/json/729.json','["賈後甘為廢戮人，齊王還殺趙王倫。", "一從天下無真主，瓜割中原四百春。"]'),
('yuding-50','晉門：懷帝','周曇','唐','御定全唐诗','yuding','','[]','蕃漢戈矛遍九垓，兩京簪紱走黃埃。',32,'御定全唐詩/json/729.json','["蕃漢戈矛遍九垓，兩京簪紱走黃埃。", "劉聰大會平陽日，遣帝行觴事可哀。"]'),
('yuding-51','晉門：湣帝','周曇','唐','御定全唐诗','yuding','','[]','耕牛吃盡大田荒，二兩黃金糴鬥糧。',32,'御定全唐詩/json/729.json','["耕牛吃盡大田荒，二兩黃金糴鬥糧。", "禦粥又聞無曲屑，不降胡虜奈饑腸。"]'),
('yuding-52','晉門：郭欽','周曇','唐','御定全唐诗','yuding','','[]','誰疑忠諫郭欽言，不逐戎夷出塞垣。',32,'御定全唐詩/json/729.json','["誰疑忠諫郭欽言，不逐戎夷出塞垣。", "晉室既無明聖主，果為胡虜亂中原。"]'),
('yuding-53','晉門：王夷甫','周曇','唐','御定全唐诗','yuding','','[]','六合誰為輔弼臣，八風昏處盡胡塵。',32,'御定全唐詩/json/729.json','["六合誰為輔弼臣，八風昏處盡胡塵。", "是知濟弱扶傾術，不屬高談虛論人。"]');
